-- Poems batch 364
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6cfcf658-ec33-4e80-a6c8-2cf5f65d3b6e','皇后閣端午帖子  其四','夏竦','宋','宋诗','song-poetry','','[]','千門襲吉縈朱索，九禁開晨闢紫闈。',32,'全唐诗/poet.song.8000.json','["千門襲吉縈朱索，九禁開晨闢紫闈。", "宫漏正長天睠重，永宣芳訓率三妃。"]'),
('c70d7808-698b-425f-9f9a-282e111f2c1f','皇后閣端午帖子  其五','夏竦','宋','宋诗','song-poetry','','[]','日記采蘭追楚俗，化孚流荇誦周詩。',32,'全唐诗/poet.song.8000.json','["日記采蘭追楚俗，化孚流荇誦周詩。", "肅恭懿德垂彤管，九御歸心百福宜。"]'),
('ef16a4d5-35b3-4945-ad94-a7d4f1fb9186','皇后閣端午帖子  其六','夏竦','宋','宋诗','song-poetry','','[]','中閨正肅鳴環節，吉日爰逢采术時。',32,'全唐诗/poet.song.8000.json','["中閨正肅鳴環節，吉日爰逢采术時。", "億載繁禧同聖壽，百男鴻慶茂仙枝。"]'),
('e65d742b-0ad6-440e-bed5-9d7a3bc8ea36','皇后閣端午帖子  其七','夏竦','宋','宋诗','song-poetry','','[]','點畫諸宫初獻巧，裁縫中禁又迎祥。',32,'全唐诗/poet.song.8000.json','["點畫諸宫初獻巧，裁縫中禁又迎祥。", "周南永播河洲化，仰佐鴻明燭萬方。"]'),
('6f389d40-f684-47e6-80ad-600a802171f8','郡王閣端午帖子  其一','夏竦','宋','宋诗','song-poetry','','[]','對日惠心時共仰，沐蘭嘉節慶長絲。',32,'全唐诗/poet.song.8000.json','["對日惠心時共仰，沐蘭嘉節慶長絲。", "仰承中緒隆天愛，永奉祥祺襲太熙。"]'),
('e034c112-84ae-4eea-b5aa-8573ec66fffc','郡王閣端午帖子  其二','夏竦','宋','宋诗','song-poetry','','[]','彤闈永奉千年慶，金策將封一字王。',32,'全唐诗/poet.song.8000.json','["彤闈永奉千年慶，金策將封一字王。", "佇向景風承異渥，預從佳節納多祥。"]'),
('2e396395-3ddd-470c-ac2d-5d697b139ba5','郡王閣端午帖子  其三','夏竦','宋','宋诗','song-poetry','','[]','五色彩絲頒禁殿，千齡嘉慶集藩房。',32,'全唐诗/poet.song.8000.json','["五色彩絲頒禁殿，千齡嘉慶集藩房。", "玉堂絃誦依真館，日日靈心降美祥。"]'),
('6dc93324-2b00-4e5c-bdc7-b6888b634590','郡王閣端午帖子  其四','夏竦','宋','宋诗','song-poetry','','[]','崑山瑞玉題真篆，閬苑蟠桃刻印文。',32,'全唐诗/poet.song.8000.json','["崑山瑞玉題真篆，閬苑蟠桃刻印文。", "並獻春閨延美慶，億年嘉氣永氤氲。"]'),
('a8273912-fe4f-4321-966c-568d556005e8','淑妃閣端午帖子  其一','夏竦','宋','宋诗','song-poetry','','[]','蕤賓布序逢良月，條達延祥記令辰。',32,'全唐诗/poet.song.8000.json','["蕤賓布序逢良月，條達延祥記令辰。", "仰奉椒塗宣內治，永昭芳譽冠虞嬪。"]'),
('8c4991c0-2011-41f8-ad64-0f1706c06254','淑妃閣端午帖子  其二','夏竦','宋','宋诗','song-poetry','','[]','芳園踏草迎嘉節，紫掖鳴環奉鞠衣。',32,'全唐诗/poet.song.8000.json','["芳園踏草迎嘉節，紫掖鳴環奉鞠衣。", "渥惠日新鴻慶遠，永隆徽序耀層闈。"]'),
('84191890-07d4-42e2-8e47-66160c3ccbca','淑妃閣端午帖子  其三','夏竦','宋','宋诗','song-poetry','','[]','萬宇清和當聖日，千門採拾遘良辰。',32,'全唐诗/poet.song.8000.json','["萬宇清和當聖日，千門採拾遘良辰。", "上真鴻緒宜蕃衍，從此高禖美應新。"]'),
('dc384207-5697-4eee-8566-55e8b920ff61','淑妃閣端午帖子  其四','夏竦','宋','宋诗','song-poetry','','[]','宴寢奉朝鳴采玉，良辰襲慶表長絲。',32,'全唐诗/poet.song.8000.json','["宴寢奉朝鳴采玉，良辰襲慶表長絲。", "仰承中壼垂芳裕，永播周南逮下詩。"]'),
('d7c107c0-b820-4344-96da-f301bc20635b','廷試','夏竦','宋','宋诗','song-poetry','','[]','殿上衮衣明日月，硯中旗影動龍蛇。',32,'全唐诗/poet.song.8000.json','["殿上衮衣明日月，硯中旗影動龍蛇。", "縱横禮樂三千字，獨對丹墀日未斜。"]'),
('7e1672cd-db84-4684-ba90-72daa743ab0a','和太師相公秋興十首  其一','夏竦','宋','宋诗','song-poetry','','[]','原上西風馬力生，折膠時候正凄清。',32,'全唐诗/poet.song.8000.json','["原上西風馬力生，折膠時候正凄清。", "功名未立頭空白，却憶金徽萬里行。"]'),
('00141e76-98b5-499d-8f2e-04d39b685371','和太師相公秋興十首  其二','夏竦','宋','宋诗','song-poetry','','[]','亭臯危葉乍經霜，過盡驚鴻落吹長。',32,'全唐诗/poet.song.8000.json','["亭臯危葉乍經霜，過盡驚鴻落吹長。", "閑上層樓待初月，方壺殘漏下三商。"]'),
('36e6e581-b4e3-4040-bb00-50060d81549b','和太師相公秋興十首  其三','夏竦','宋','宋诗','song-poetry','','[]','螢光照水星星度，鴈陣横空字字移。',32,'全唐诗/poet.song.8000.json','["螢光照水星星度，鴈陣横空字字移。", "何處佳人惜團扇，玉階烟葉動輕颸。"]'),
('bfaca0e2-54f9-44b1-95a2-98293a693591','和太師相公秋興十首  其四','夏竦','宋','宋诗','song-poetry','','[]','苑樹殘蟬送遠愁，懶將衰鬢照清流。',32,'全唐诗/poet.song.8000.json','["苑樹殘蟬送遠愁，懶將衰鬢照清流。", "歸來自掃東園葉，學灌寒蔬備晚秋。"]'),
('3a3a2d16-eebb-4dc1-9a9a-cf8c7020200b','和太師相公秋興十首  其五','夏竦','宋','宋诗','song-poetry','','[]','水榭凉生暑氣銷，疏螢點點漏迢迢。',32,'全唐诗/poet.song.8000.json','["水榭凉生暑氣銷，疏螢點點漏迢迢。", "明河案户蒼龍轉，只有匏瓜綴碧霄。"]'),
('19154b4a-81c5-44c2-afe6-cb6998cc910b','和太師相公秋興十首  其六','夏竦','宋','宋诗','song-poetry','','[]','沉沉池閣乍凉天，坐愛蓮薰夜不眠。',32,'全唐诗/poet.song.8000.json','["沉沉池閣乍凉天，坐愛蓮薰夜不眠。", "却憶北門曾候對，半簾斜月玉堂前。"]'),
('69c0fb2b-d414-44e8-82c0-6ef186192027','和太師相公秋興十首  其七','夏竦','宋','宋诗','song-poetry','','["\u897f\u6e56"]','相府新秋宴席開，西湖珠履踐蒼苔。',32,'全唐诗/poet.song.8000.json','["相府新秋宴席開，西湖珠履踐蒼苔。", "白頭舊吏方奔走，不得抽毫逐上才。"]'),
('fd8a5b7c-57cb-424a-8b0e-45d026179d4d','和太師相公秋興十首  其八','夏竦','宋','宋诗','song-poetry','','[]','遙思漢闕雨新晴，天際微雲夕吹生。',32,'全唐诗/poet.song.8000.json','["遙思漢闕雨新晴，天際微雲夕吹生。", "沆瀣氣凉僊掌迥，滿盤宵露結珠英。"]'),
('d0febad8-4f17-4610-bfc5-1f3f279114d0','和太師相公秋興十首  其九','夏竦','宋','宋诗','song-poetry','','[]','河漢西傾火漸流，露華微冷透輕裘。',32,'全唐诗/poet.song.8000.json','["河漢西傾火漸流，露華微冷透輕裘。", "何當弄鳳随驚吹，直上層城十二樓。"]'),
('473ba525-c529-4704-bba9-c2befe597489','和太師相公秋興十首  其一○','夏竦','宋','宋诗','song-poetry','','[]','彤管少文堪約史，霜戈無藝可防邊。',32,'全唐诗/poet.song.8000.json','["彤管少文堪約史，霜戈無藝可防邊。", "孟諸蒼莾平臺遠，坐對秋光又一年。"]'),
('e8dc6ca5-6591-4a9e-94e0-8cb5d1dfd7d7','青州','夏竦','宋','宋诗','song-poetry','','[]','日上西山舞鸞鶴，波翻碧海鬪蛟龍。',32,'全唐诗/poet.song.8000.json','["日上西山舞鸞鶴，波翻碧海鬪蛟龍。", "直鈎到了成何事，消得君王四履封。"]'),
('c5cd9a38-44eb-4377-b063-6193d6f3eb6b','江州琵琶亭','夏竦','宋','宋诗','song-poetry','','[]','年光過眼如車轂，職事羈人似馬銜。',32,'全唐诗/poet.song.8000.json','["年光過眼如車轂，職事羈人似馬銜。", "若遇琵琶應大笑，何須涕泣滿青衫。"]'),
('db765f3d-d0fa-4781-b3a9-f7a431a0b99f','狎鷗亭詩  其一','夏竦','宋','宋诗','song-poetry','','[]','元化平分荷大鈞，左符新刻玉爲麟。',32,'全唐诗/poet.song.8000.json','["元化平分荷大鈞，左符新刻玉爲麟。", "南湖特地栽桃李，擬伴沙鷗過十春。"]'),
('8eae9fe5-d9a6-4fa1-85f5-896362eac62e','狎鷗亭詩  其二','夏竦','宋','宋诗','song-poetry','','[]','海鴈橋邊綠水深，絕無塵土近花陰。',32,'全唐诗/poet.song.8000.json','["海鴈橋邊綠水深，絕無塵土近花陰。", "忘機不管人知否，自有溪鷗信此心。"]'),
('7bce09f5-baaa-47ac-a870-fa567e6a14d8','書懷','夏竦','宋','宋诗','song-poetry','','[]','黄閣有賢圖國計，皂嚢無黨害邊功。',32,'全唐诗/poet.song.8000.json','["黄閣有賢圖國計，皂嚢無黨害邊功。", "河湟飲馬無難事，一點沙塵在目中。"]'),
('0a536a6d-f578-4b8d-a95f-8e45079710eb','到任後作','夏竦','宋','宋诗','song-poetry','','[]','功兼文武帝師臣，久厭崇高樂退身。',32,'全唐诗/poet.song.8000.json','["功兼文武帝師臣，久厭崇高樂退身。", "任是東山無限好，謝公争忍負生民。"]'),
('bb0c3013-a8ba-4161-86d0-0a7e755a079b','西廳','夏竦','宋','宋诗','song-poetry','','[]','階除盡日微風度，簾幕先秋暑氣還。',32,'全唐诗/poet.song.8000.json','["階除盡日微風度，簾幕先秋暑氣還。", "莫訝使君臨案久，雨晴端正見南山。"]'),
('d31e84fe-c66f-42b4-81e9-2c15403e5140','宫詞  其一','夏竦','宋','宋诗','song-poetry','','[]','鬢攏春煙濕翠翹，石榴裙幔裊纖腰。',32,'全唐诗/poet.song.8000.json','["鬢攏春煙濕翠翹，石榴裙幔裊纖腰。", "絳脣不敢深深注，却怕香脂污玉簫。"]'),
('52a13a52-1dd8-449b-b11b-a2c271cb340c','宫詞  其二','夏竦','宋','宋诗','song-poetry','','[]','新染羅衣窣地紅，喜迎天仗宴春風。',32,'全唐诗/poet.song.8000.json','["新染羅衣窣地紅，喜迎天仗宴春風。", "歌詞若入君王聽，不惜新聲教六宫。"]'),
('c6e6d656-ed1f-40c1-b902-9344f45fd157','古意','夏竦','宋','宋诗','song-poetry','','[]','重上青樓拂蛛網，却匀愁黛對菱波。',32,'全唐诗/poet.song.8000.json','["重上青樓拂蛛網，却匀愁黛對菱波。", "也知新舊争多少，敢話機頭織素多。"]'),
('7606432f-03de-4c2f-9338-e05b4e0a91bf','漁者','夏竦','宋','宋诗','song-poetry','','[]','讀徧龍韜事可知，一竿閑把直鈎垂。',32,'全唐诗/poet.song.8000.json','["讀徧龍韜事可知，一竿閑把直鈎垂。", "秋來江上西風急，且繫扁舟卷釣絲。"]'),
('5a76418a-0aa3-480f-ae3e-930f77ce2325','觀藏珠','夏竦','宋','宋诗','song-poetry','','[]','敏手機心頗自安，遮藏有路巧千般。',32,'全唐诗/poet.song.8000.json','["敏手機心頗自安，遮藏有路巧千般。", "主公當面無因見，只怕旁人冷眼看。"]'),
('8e328524-dadd-4b7f-af63-8e0e324f8e40','安撫狀元內翰還朝復命再獲候迎先附短章以代片幅','夏竦','宋','宋诗','song-poetry','','[]','两朝西掖舊詞臣，蘖苦冰寒四十春。',32,'全唐诗/poet.song.8000.json','["两朝西掖舊詞臣，蘖苦冰寒四十春。", "霜雪滿頭塵滿袖，自慚重見玉堂人。"]'),
('82b2c29d-1a6e-4fd6-9bcc-31f7cce85ed7','送張逸人二首  其一','夏竦','宋','宋诗','song-poetry','','[]','上公詩筆千金重，逋客歸裝一棹輕。',32,'全唐诗/poet.song.8000.json','["上公詩筆千金重，逋客歸裝一棹輕。", "莫向青山更招隱，且留賢哲濟蒼生。"]'),
('8e808e24-1223-4e0e-b19a-aa67fc9b638a','送張逸人二首  其二','夏竦','宋','宋诗','song-poetry','','[]','徘徊獨鶴翻清景，容曵孤雲下絳霄。',32,'全唐诗/poet.song.8000.json','["徘徊獨鶴翻清景，容曵孤雲下絳霄。", "朝市山林本無異，前賢出處盡逍遙。"]'),
('72111142-c3a0-483b-9e61-0e982310b275','到任涇州寄長安府學諸先輩','夏竦','宋','宋诗','song-poetry','','[]','半載秦川令始行，論文猶未款羣英。',32,'全唐诗/poet.song.8000.json','["半載秦川令始行，論文猶未款羣英。", "横戈且趁從軍樂，不及期年待政成。"]'),
('c0645d92-674b-44b9-9ce4-b534bea4c8de','聞勸農二使渡江訪胡丞隱居','夏竦','宋','宋诗','song-poetry','','[]','宅臨殷羡投書渚，門擁維摩問疾人。',32,'全唐诗/poet.song.8000.json','["宅臨殷羡投書渚，門擁維摩問疾人。", "詔使艤舟應訪道，雨花交影隔西津。"]'),
('1692e806-6a04-4fae-8d70-3b50c5590083','咏鳳','夏竦','宋','宋诗','song-poetry','','[]','千仞翺翔覽德輝，成湯解網四靈歸。',32,'全唐诗/poet.song.8000.json','["千仞翺翔覽德輝，成湯解網四靈歸。", "梧桐欲下還驚去，悄悄饑鷹掠樹飛。"]'),
('1a51904d-8e66-4375-b43a-28f39c65e144','聞鶯','夏竦','宋','宋诗','song-poetry','','[]','春光容與曉風高，花映金塗見羽毛。',32,'全唐诗/poet.song.8000.json','["春光容與曉風高，花映金塗見羽毛。", "莫訝綠楊留不住，內園新雨熟含桃。"]'),
('a518130b-b0cf-4627-9e7c-966407732da6','咏鷹','夏竦','宋','宋诗','song-poetry','','[]','獲自野羅知性巧，飼之鮮食已恩豐。',32,'全唐诗/poet.song.8000.json','["獲自野羅知性巧，飼之鮮食已恩豐。", "下韝未便随人意，須是經春更一籠。"]'),
('a1922f79-f96c-4457-a18d-afe6813d05e4','再徙西都詠青雀寄張昇諫院','夏竦','宋','宋诗','song-poetry','','[]','弱羽傷弓尚未完，孤飛誰敢擬鴛鸞。',32,'全唐诗/poet.song.8000.json','["弱羽傷弓尚未完，孤飛誰敢擬鴛鸞。", "明珠自有千金價，莫爲遊人作彈丸。"]'),
('54fb373d-8009-4d13-a3e9-33e213f5ec45','廄馬','夏竦','宋','宋诗','song-poetry','','[]','萬里無塵塞草秋，玉輪金軛未巡遊。',32,'全唐诗/poet.song.8000.json','["萬里無塵塞草秋，玉輪金軛未巡遊。", "上林苜蓿天池水，飽食長鳴可自羞。"]'),
('ec7bc091-a449-4fc5-87e5-24cfb3b8a643','薔薇','夏竦','宋','宋诗','song-poetry','','[]','紅房深淺翠條低，滿架清香敵麝臍。',32,'全唐诗/poet.song.8000.json','["紅房深淺翠條低，滿架清香敵麝臍。", "攀折若無花底刺，豈教桃李獨成蹊。"]'),
