('5e01c1d3-cf58-4382-8084-d36a394a9983','句  其八','夏竦','宋','宋诗','song-poetry','','[]','氣凌雲夢吞八九，欲與溟渤爭雌雄。',16,'全唐诗/poet.song.8000.json','["氣凌雲夢吞八九，欲與溟渤爭雌雄。"]'),
('c0b94a74-64cf-4bf0-a942-cc843990ab83','桃源圖','馮信可','宋','宋诗','song-poetry','','[]','桃源東迴溪轉長，桃花開時春日光。',160,'全唐诗/poet.song.8000.json','["桃源東迴溪轉長，桃花開時春日光。", "幽禽出樹亂紅落，游魚吹花流水香。", "山人正住溪之滸，屋角花開自成塢。", "尋源未許武陵人，隱者但作桃花主。", "拄杖穿花來水頭，禽魚亦解識風流。", "往來況有樵雲叟，何惜銜杯同唱酬。", "一尊如出桃花色，花落尊中已無迹。", "醉鄉泠泠白日閑，黄塵滾滾青山隔。", "明年此日桃花開，何人凈掃溪陰苔。", "我亦天台約劉阮，春風一櫂酒船來。"]'),
('c05c32a6-37ad-4190-9e35-de284a4b8c72','如歸亭','章傪','宋','宋诗','song-poetry','','[]','吳上江上客亭幽，地占姑蘇最上游。',64,'全唐诗/poet.song.8000.json','["吳上江上客亭幽，地占姑蘇最上游。", "萬頃重湖朝夕浪，幾聲殘櫓往來舟。", "涼生領袖蘋風晚，冷射杯盤桂魄秋。", "東道正閑時倒屣，笙歌誰惜一遲留。"]'),
('7ac0a7a5-794e-45dc-bc9a-b4f6c779408c','如歸亭','何永錫','宋','宋诗','song-poetry','','[]','獨臨朱檻愛平波，安穩歸舟兩兩過。',64,'全唐诗/poet.song.8000.json','["獨臨朱檻愛平波，安穩歸舟兩兩過。", "數島雲霞栽橘社，一汀煙月採菱歌。", "湖心日定施青黛，砌下風恬展碧羅。", "好寫仙源槎閣主，便教從此上銀河。"]'),
('f2ea7585-1d41-4804-a503-5a9a34851f6e','如歸亭','陶伯宗','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','吾家本住洞庭西，煙雨生涯接釣磯。',32,'全唐诗/poet.song.8000.json','["吾家本住洞庭西，煙雨生涯接釣磯。", "今日吳江亭上望，水光山色卻如歸。"]'),
('48eafae1-4c01-4355-a37f-b2b116a8d49a','句','王瀆','宋','宋诗','song-poetry','','[]','東湖富泉石。',6,'全唐诗/poet.song.8000.json','["東湖富泉石。"]'),
('c3a5a29e-3fe2-4810-b193-f5db7af1d723','句','張觀','宋','宋诗','song-poetry','','[]','保心如止水，爲行見真書。',12,'全唐诗/poet.song.8000.json','["保心如止水，爲行見真書。"]'),
('331a2122-2f77-4b9c-84ed-c5a33709d1c2','登第後作','何拯','宋','宋诗','song-poetry','','[]','自古{宗/內}城繼踵希，吾門多幸盛昌時。',36,'全唐诗/poet.song.8000.json','["自古{宗/內}城繼踵希，吾門多幸盛昌時。", "姮娥不惜蟾宮桂，從此何家第二枝。"]'),
('e4672d52-c3f2-4a05-9bad-c7050d8a6ce1','退居','詹中正','宋','宋诗','song-poetry','','[]','宦情文思競闌珊，利戶名樞莫我關。',64,'全唐诗/poet.song.8000.json','["宦情文思競闌珊，利戶名樞莫我關。", "無可奈何新白髮，不如歸去舊青山。", "須知百歲都爲夢，未信千金買得閑。", "珍重樽中賢聖酒，非因風月亦開顔。"]'),
('c48fe2cf-c5cd-4149-ba2a-2bac9f55390b','香山','詹中正','宋','宋诗','song-poetry','','[]','浪兀孤舟一葉輕，香山登步覺神清。',64,'全唐诗/poet.song.8000.json','["浪兀孤舟一葉輕，香山登步覺神清。", "幾多怪石全勝畫，大半奇花不識名。", "猿狖盡當吟裏見，煙霞祇向眼前生。", "官身未約重來此，酒滿螺盃月正明。"]'),
('47111eea-e70e-470d-8cc0-ea3ccdc3159a','山居苦','詹中正','宋','宋诗','song-poetry','','[]','未達且窮棲，寂寥難可爲。',48,'全唐诗/poet.song.8000.json','["未達且窮棲，寂寥難可爲。", "雪窗燈焰短，茅屋雨聲低。", "幽砌苔金鎖，閑庭草半迷。", "江山無限意，時得入新題。"]'),
('942ac293-b4fd-4515-a12a-4f0a269949b9','句','詹中正','宋','宋诗','song-poetry','','[]','吟餘妓散杯中酒，歸去蝶隨頭上花。',16,'全唐诗/poet.song.8000.json','["吟餘妓散杯中酒，歸去蝶隨頭上花。"]'),
('2db01b21-48fd-44c0-a10b-1ecbf9925222','五更枕上','黄虛舟','宋','宋诗','song-poetry','','[]','睡覺愁無奈，難禁冬夜長。',48,'全唐诗/poet.song.8000.json','["睡覺愁無奈，難禁冬夜長。", "纔聽曉鐘動，又是世人忙。", "入市船撐月，朝天馬踏霜。", "布衾綿樣軟，切莫笑尋常。"]'),
('5d72666f-20d5-4389-9da1-d4b99b767972','蛾眉亭','黄虛舟','宋','宋诗','song-poetry','','[]','浩蕩長流浪拍天，貔貅十萬坐樓船。',64,'全唐诗/poet.song.8000.json','["浩蕩長流浪拍天，貔貅十萬坐樓船。", "年年春滿江南岸，夜夜風傳塞北煙。", "中界靈祇藏水府，六朝廢寢落山邊。", "秋來留得唐時月，捉月今誰是謫仙。"]'),
('0505fdd9-9fec-4ac4-90bd-eb1d3cef13e6','送李殿省赴任常熟','黄鑑','宋','宋诗','song-poetry','','[]','吳山紫翠倚晴空，潘令風流向此中。',64,'全唐诗/poet.song.8000.json','["吳山紫翠倚晴空，潘令風流向此中。", "雨飽公田方稼稔，春生香徑雜葩紅。", "綵艫銜尾凌波駛，頳鯉駢頭薦俎豐。", "玉季情深重暌索，南雲延脰接飛鴻。"]'),
('81753513-5717-4bfb-8bbc-f4a3107415f8','送梵才大師歸天台','黄鑑','宋','宋诗','song-poetry','','[]','城闕厭紛華，山泉樂清適。',120,'全唐诗/poet.song.8000.json','["城闕厭紛華，山泉樂清適。", "瞥然浮杯歸，遠思浩無極。", "珍篇藹晝評，凈義留泰譯。", "平生霧霞衣，倏變蘭蒲色。", "美號寵彌天，端居館香積。", "孤蹤共鳥還，情愔避高弋。", "煙波一葉舟，風雨兩鐶錫。", "佛壠有幽棲，鷹房多善識。", "把塵話空無，百慮從此息。", "回瞻輦寺居，不及莓苔石。"]'),
('05680c32-9089-42cb-b46c-1717bf1c7ad6','石門巖壁','黄鑑','宋','宋诗','song-poetry','','[]','峭壁矗雲三峽裏，急湍翻雪五湖邊。',32,'全唐诗/poet.song.8000.json','["峭壁矗雲三峽裏，急湍翻雪五湖邊。", "何年造物施神力，移到褒中小有天。"]'),
('815357ea-9885-4e35-a8c7-c90f396f61da','句  其一','黄鑑','宋','宋诗','song-poetry','','[]','遊魚波上遊。',6,'全唐诗/poet.song.8000.json','["遊魚波上遊。"]'),
('3f42c39c-ef43-4d40-bcfe-fe1a2bb97138','句  其二','黄鑑','宋','宋诗','song-poetry','','[]','遠水涵空迷極目，落花如霧擁歸軒。',16,'全唐诗/poet.song.8000.json','["遠水涵空迷極目，落花如霧擁歸軒。"]'),
('e620d494-ef47-460f-84e3-637ea6271594','即事','王致','宋','宋诗','song-poetry','','[]','谷暗隨呼應，禽春不速來。',24,'全唐诗/poet.song.8000.json','["谷暗隨呼應，禽春不速來。", "幽居逢令序，跬步且徘徊。"]'),
('130dfe37-cfd7-441b-ac96-94a6d82450c8','辭本州教官','王致','宋','宋诗','song-poetry','','[]','年近古稀有，不易升此堂。',24,'全唐诗/poet.song.8000.json','["年近古稀有，不易升此堂。", "他日留泉下，須留姓氏香。"]'),
('aef9d3c1-a711-444e-b256-ca28ba13a52b','題袁學士像','王致','宋','宋诗','song-poetry','','[]','平生有志惜分陰，經濟功夫着力深。',64,'全唐诗/poet.song.8000.json','["平生有志惜分陰，經濟功夫着力深。", "一日高飛成遠舉，幾回懷古作豪吟。", "春風頻夢丹墀月，夏日長思玉館琴。", "天下弦歌聲已舊，化成都只在公心。"]'),
('34fc8b02-f8ca-445d-9dfe-15a18e020f87','舟中作偈','釋楚圓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江行不盡，帝里到何時。',24,'全唐诗/poet.song.8000.json','["長江行不盡，帝里到何時。", "既得涼風便，休將艫棹施。"]'),
('1e141c06-1961-4254-8b0f-9c5aba58b2c6','訪隱居孫明復山齋二首  其一','孔道輔','宋','宋诗','song-poetry','','[]','日觀峰前訪隱淪，豈同沮溺異人羣。',32,'全唐诗/poet.song.8000.json','["日觀峰前訪隱淪，豈同沮溺異人羣。", "軻能養浩雄能默，今復淵源見此君。"]'),
('ee02e187-37bc-42db-9e04-5c02726a9861','訪隱居孫明復山齋二首  其二','孔道輔','宋','宋诗','song-poetry','','[]','脫屐名場藴壯圖，君方舉逸待嘉謨。',32,'全唐诗/poet.song.8000.json','["脫屐名場藴壯圖，君方舉逸待嘉謨。", "即期鶴版臨巖室，萬疊雲山戀得無。"]'),
('dbab66d4-17da-44a6-9081-3013ce213487','題祖廟二首  其一','孔道輔','宋','宋诗','song-poetry','','[]','秦火自焚寧害聖，金絲堂壁閟家書。',32,'全唐诗/poet.song.8000.json','["秦火自焚寧害聖，金絲堂壁閟家書。", "典墳啟發皆天意，非謂共王好治居。"]'),
('35676306-45ab-4441-b359-7ae14b67e098','題祖廟二首  其二','孔道輔','宋','宋诗','song-poetry','','[]','門有詩書不華彩，素王留得好生涯。',32,'全唐诗/poet.song.8000.json','["門有詩書不華彩，素王留得好生涯。", "行人莫訝頻回首，天下文章第一家。"]'),
('69363744-50ac-4233-a2f9-516a904b3779','山中作','釋惟政','宋','宋诗','song-poetry','','[]','橋上山萬重，橋下水千里。',24,'全唐诗/poet.song.8000.json','["橋上山萬重，橋下水千里。", "惟有白鷺鷥，見我常來此。"]'),
('4662886f-1028-4142-a922-2d1d834b7749','辭侍郎蔣公讌客見招','釋惟政','宋','宋诗','song-poetry','','[]','昨日曾將今日期，出門倚杖又思惟。',32,'全唐诗/poet.song.8000.json','["昨日曾將今日期，出門倚杖又思惟。", "爲僧只合居巖谷，國土筵中甚不宜。"]'),
('1503f4fa-810f-4377-8286-6f424875fc54','自題像','釋惟政','宋','宋诗','song-poetry','','[]','貌古形疏倚杖蔾，分明畫出須菩提。',32,'全唐诗/poet.song.8000.json','["貌古形疏倚杖蔾，分明畫出須菩提。", "解空不許離聲色，似聽孤猨月下啼。"]'),
('b03d075b-66eb-4b59-bc86-fe02d3d381ab','送僧偈','釋惟政','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u8a00\u5fd7", "\u9b4f\u664b\u5357\u5317\u671d\u8bd7", "\u8c22\u7edd"]','山中何所有，嶺上多白雲。',24,'全唐诗/poet.song.8000.json','["山中何所有，嶺上多白雲。", "祇可自怡悅，不堪持贈君。"]'),
('f3fdeaa3-ae10-4296-a86f-71de76c7d8d0','惠州野吏亭','黄仲通','宋','宋诗','song-poetry','','[]','危亭治舊基，登覽一何奇。',48,'全唐诗/poet.song.8000.json','["危亭治舊基，登覽一何奇。", "萬態羅浮景，三章宰輔詩。", "嵐光如畫處，霽色乍開時。", "味此休閑趣，惟予野吏知。"]'),
('d8d1d207-aa6d-4d7c-9de2-b70adbf4e439','登岳陽樓','麻溫其','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','湖邊景物屬秋天，樓上風光似去年。',64,'全唐诗/poet.song.8000.json','["湖邊景物屬秋天，樓上風光似去年。", "仙侶緱生留福地，湘娥帝子寄哀弦。", "雲門自統軒臺外，木葉偏飛楚客前。", "極目江山何處是，一帆萬里信歸船。"]'),
('642e66c8-ee87-486b-920c-2c4205014031','送龍池寥先生開講沙場詩','余湜','宋','宋诗','song-poetry','','[]','沙場諸子弟，少小盡晞顔。',48,'全唐诗/poet.song.8000.json','["沙場諸子弟，少小盡晞顔。", "迎我五經笥，歸來七島山。", "朝遊松子洞，暮宿惠人灣。", "講罷西風裏，扁舟早送還。"]'),
('e855f6dd-56fd-43fb-831c-3763f9dbe445','句','余湜','宋','宋诗','song-poetry','','[]','西母子回金殿冷，綠珠一墜玉樓空。',16,'全唐诗/poet.song.8000.json','["西母子回金殿冷，綠珠一墜玉樓空。"]'),
('79f6ec7a-c630-4ae8-8618-49e7d2bf69f0','詩一首','史溫','宋','宋诗','song-poetry','','[]','曹娥廟貌枕江湄，南北行人合孝思。',32,'全唐诗/poet.song.8000.json','["曹娥廟貌枕江湄，南北行人合孝思。", "有智不爭三十里，千年黄絹一廳碑。"]'),
('c3d28472-d6c7-43f6-8d7b-49a7f2bc5c83','寄天台王鍊師兼呈邑宰','張日損','宋','宋诗','song-poetry','','[]','百里凄清古縣城，阮郎陶令自相應。',64,'全唐诗/poet.song.8000.json','["百里凄清古縣城，阮郎陶令自相應。", "非無柳影含彭澤，別有花光勝武陵。", "閑醉想同莎外石，冷吟知共夜深燈。", "紅塵未得尋高興，心過青山第幾層。"]'),
('aece51a4-84cb-4abb-b83d-4fcbdd1db43d','題廣化寺阿育王塔','黄康弼','宋','宋诗','song-poetry','','[]','齊野非吳渚，支郎是子陵。',24,'全唐诗/poet.song.8000.json','["齊野非吳渚，支郎是子陵。", "釣臺千古月，寶塔萬年燈。"]'),
('f45334b2-118c-4b13-a8bb-f1c62f723f37','海棠','高覿','宋','宋诗','song-poetry','','[]','錦里花中色最奇，妖嬈天賦本來稀。',64,'全唐诗/poet.song.8000.json','["錦里花中色最奇，妖嬈天賦本來稀。", "綺霞忽照迷紅障，縠露輕籠設翠幃。", "繁朵有情妝媚景，纖枝無力带殘暉。", "好將繡向羅裙上，永作香閨楚楚衣。"]'),
('7f9c0a27-babb-4a9f-b852-e604cf13d132','虎丘','蘇耆','宋','宋诗','song-poetry','','[]','虎踞標靈跡，危樓杳靄間。',72,'全唐诗/poet.song.8000.json','["虎踞標靈跡，危樓杳靄間。", "劍池沉石壁，金池湧秋山。", "塔影松軒斷，雲迷蘚逕斑。", "磬隨靈籟盡，鶴伴老僧閑。", "有句慚先哲，無辭愈厚顔。", "我來聊寫望，頓覺離人寰。"]'),
('5b2c523f-a86b-4678-9854-3a1497acbec5','句','蘇耆','宋','宋诗','song-poetry','','[]','上到天門最高處，不能容物只容身。',16,'全唐诗/poet.song.8000.json','["上到天門最高處，不能容物只容身。"]'),
('a841ccb2-cebf-4e2e-b2a0-588ae399b7f2','送僧歸護國寺','祖士衡','宋','宋诗','song-poetry','','[]','雪中問法傳宗印，日暮裁詩變楚騷。',64,'全唐诗/poet.song.8000.json','["雪中問法傳宗印，日暮裁詩變楚騷。", "香積諸天修凈供，蒲葺三殿賜新袍。", "夜禪錫駐青鴛剎，曉渡杯陵白露濤。", "參罷虛堂惟宴坐，風松露桂海蟾高。"]'),
('99a8b59e-fcfd-4922-9b42-9887945bc5b7','寄李先生','黄晞','宋','宋诗','song-poetry','','[]','久不見泰伯，中心頻損和。',144,'全唐诗/poet.song.8000.json','["久不見泰伯，中心頻損和。", "近聞束書卷，更卜好山阿。", "學古成儒癖，敦風蕩俗訛。", "周公法已矣，原憲事如何。", "母老祿未及，身閑鬢不皤。", "新文海裔播，舊業釣竿拖。", "寧戚歌寧發，麻姑使屢過。", "時人一握小，吾道片雲多。", "友弟俱游宦，池樊自摭莎。", "聞猿詩興逸，敲戶酒徒羅。", "鄉里名光也，朝廷禮後麽。", "年來魚信至，怪我客蹉跎。"]'),
('91cb8f62-5c1a-4da9-bc60-3948a160ab22','詩一首','黄晞','宋','宋诗','song-poetry','','[]','福唐太守天下才，好事求奇竭中楮。',128,'全唐诗/poet.song.8000.json','["福唐太守天下才，好事求奇竭中楮。", "有時勸我靜祛懷，到處尋幽閑笑侶。", "一朝薏苡足人疑，萬里珠璣同夢睹。", "樹墓休提孤劍鐞，星垣忽見清絃古。", "好物終難寂寞留，高門即是從容所。", "幾年何地各分飛，此地當歌忽胥遇。", "還記當頭灑淚人，同是從前舊承顧。", "中郎一見厚難忘，柯亭有竹君知否。"]'),
('3a227808-a894-4af7-8f99-bfd620121076','留題涪州石魚','劉忠順','宋','宋诗','song-poetry','','[]','七十二鱗波底鐫，一銜蓂草一銜蓮。',64,'全唐诗/poet.song.8000.json','["七十二鱗波底鐫，一銜蓂草一銜蓮。", "出來非共貪芳餌，奏去因同報稔年。", "方客遠書徒自得，牧人嘉夢合相先。", "前知上瑞宜頻見，帝念民饑刺史賢。"]'),
('20e488ff-19f7-4859-92b6-4c152f20efb2','留題資聖寺宗己嘉遯居','劉忠順','宋','宋诗','song-poetry','','[]','院幽庵更小，嘉遯稱名尊。',48,'全唐诗/poet.song.8000.json','["院幽庵更小，嘉遯稱名尊。", "展榻殊無地，看山別有門。", "潮來供菜圃，雲過隔城村。", "了畢如來藏，任他風動搖。"]'),
('0534aab2-f5f3-42a1-9ae6-4b8d01cfb88c','龍泉秩滿題','蔡用之','宋','宋诗','song-poetry','','[]','昨日新官對舊官，吏民一半冷相看。',32,'全唐诗/poet.song.8000.json','["昨日新官對舊官，吏民一半冷相看。", "夜來惟有前灘水，依舊多情到枕寒。"]'),
('0284c8b5-61b9-4ffe-be58-2dd88cba2463','富順','解旦','宋','宋诗','song-poetry','','[]','封疆莫嘆極西陲，景物尤堪著詠思。',64,'全唐诗/poet.song.8000.json','["封疆莫嘆極西陲，景物尤堪著詠思。", "亭臺處處垂楊影，街巷家家小酒旗。", "舊同吳楚分梅艷，新比戎瀘有荔枝。", "鑿井鹹泉通海脈，靠山公署映江涯。"]'),
('b21057e7-1132-4148-964f-f27eba9722bb','句','解旦','宋','宋诗','song-poetry','','[]','便作武陵溪上看，春來何處不開花。',16,'全唐诗/poet.song.8000.json','["便作武陵溪上看，春來何處不開花。"]'),
('6a46121d-dcb4-465a-ab19-b393140c2be3','贈張俞秀才遊金華山','鄭炎','宋','宋诗','song-poetry','','[]','凌晨別我將何適，鶴態飄然振霜翮。',128,'全唐诗/poet.song.8000.json','["凌晨別我將何適，鶴態飄然振霜翮。", "指點金華欲去遊，騎驢直造煙霞宅。", "一片嵐光凝不飛，數里松陰翠如滴。", "背臘山寒雪未消，迎春地暖花爭拆。", "水潺潺兮風索索，簾卷虛堂正岑寂。", "高歌應有鬼神聽，狀物潛驅鴻化力。", "繄我浮生繫郡符，安得乘閑訪靈跡。", "吟成一首送君詩，倩僧勒上巖邊石。"]'),
('f9b63162-b6a4-4484-b3e8-2220991ecb6c','贈內臣孫可久','柳永','宋','宋诗','song-poetry','','[]','故侯幽隱直城東，草樹扶疏一畝宮。',64,'全唐诗/poet.song.8000.json','["故侯幽隱直城東，草樹扶疏一畝宮。", "曾珥貂璫爲近侍，卻紆絛褐作閑翁。", "高吟擁鼻詩懷壯，雅論持衡道氣充。", "厭盡繁華天上樂，始將蹤蹟學冥鴻。"]'),
('a38dd548-a474-4487-9025-e1a40aba9062','鬻海歌','柳永','宋','宋诗','song-poetry','','[]','鬻海之民何所營，婦無蠶織夫無耕。',256,'全唐诗/poet.song.8000.json','["鬻海之民何所營，婦無蠶織夫無耕。", "衣食之源太寥落，牢盆鬻就汝輸征。", "年年春夏潮盈浦，潮退刮泥成島嶼。", "風乾日曝鹹咺加，始灌潮波塯成滷。", "滷濃鹹淡未得閑，採樵深入無窮山。", "豹蹤虎迹不敢避，朝陽出去夕陽還。", "船載肩擎未遑歇，投入巨竈炎炎熱。", "晨燒暮爍堆積高，才得波濤變成雪。", "自從潴滷至飛霜，無非假貸充餱糧。", "秤入官中得微直，一緡往往十緡償。", "周而復始無休息，官租未了私租逼。", "驅妻逐子課工程，雖作人形俱菜色。", "鬻海之民何苦辛，安得母富子不貧。", "本朝一物不失所，願廣皇仁到海濱。", "甲兵凈洗征輸輟，君有餘財罷鹽鐵。", "太平相業爾惟鹽，化作夏商周時節。"]'),
('c2c9e719-092f-402d-9cdf-a12b6e0296b2','題中峰寺','柳永','宋','宋诗','song-poetry','','[]','攀蘿躡石落崔嵬，千萬峰中梵室開。',64,'全唐诗/poet.song.8000.json','["攀蘿躡石落崔嵬，千萬峰中梵室開。", "僧向半空爲世界，眼看平地起風雷。", "猿偷曉果升松去，竹逗清流入檻來。", "旬月經遊殊不厭，欲歸回首更遲迴。"]'),
('050bdb45-605f-4f58-8edf-65155f585319','句','柳永','宋','宋诗','song-poetry','','[]','分得天一角，織成山四圍。',12,'全唐诗/poet.song.8000.json','["分得天一角，織成山四圍。"]'),
('9880b609-8ec4-44c9-acb9-e3a29ee750c7','小孤山  其一','蔡齊','宋','宋诗','song-poetry','','[]','大孤之石衡且修，青青長在湖之頭。',144,'全唐诗/poet.song.8000.json','["大孤之石衡且修，青青長在湖之頭。", "小孤之石銳以高，削立江崖當洪濤。", "滔滔逝水東流去，兩石崔嵬屹天柱。", "蜀巴之源浩沄沄，壯哉此誠江海門。", "鴻龐稍見士宇廣，疏鑿方知夏禹勤。", "名山大川神所主，過者震驚誰敢侮。", "云何作廟向荒壖，摶土娉婷像龍女。", "篙師賈客爾何知，坎坎伐鼓持豚蹄。", "倚篷清坐漁歌起，日暮但見崖鷹飛。"]'),
('3bc51157-9793-409e-a377-16d9113d0ec5','小孤山  其二','蔡齊','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','危峰屹立長江上，勢折華胥限百蠻。',64,'全唐诗/poet.song.8000.json','["危峰屹立長江上，勢折華胥限百蠻。", "鰲背孤撐青玉柱，斗杓斜插翠雲鬟。", "月生西海初三夜，潮到東吳第一關。", "安得扁舟多載酒，放歌擊楫浪花間。"]'),
('bbbfdd88-a8b7-4c8b-8e53-ad232fe7fc1f','小孤索用黄士殷同賦','蔡齊','宋','宋诗','song-poetry','','[]','纜舟宿松縣，我友愛奇觀。',72,'全唐诗/poet.song.8000.json','["纜舟宿松縣，我友愛奇觀。", "愛登小孤山，千里瞰江岸。", "窄塞峽浪喧，微茫渚沙漫。", "臨深看泳魚，思歸聞啼雁。", "茫茫吊千古，俯仰亦嗟嘆。", "君侯金玉章，貽我舟中玩。"]'),
('ae5fd6b8-3dbb-4853-a755-27bfe0001bee','洋州','蔡交','宋','宋诗','song-poetry','','[]','武定新雄閫，豐寧舊奧墟。',240,'全唐诗/poet.song.8000.json','["武定新雄閫，豐寧舊奧墟。", "地兼秦蜀美，川會漢洋紆。", "翠壘環封嶺，清流躍野渠。", "安知下斜谷，別得上華胥。", "乾酒香村落，生金富里閭。", "晴軒迎螮蝀，夜管送蟾蜍。", "啼烏絃幽塢，芳花繡碧墟。", "路飛遊女蓋，巷曳隱人裾。", "陸會尋穿石，江遨揭聚魚。", "繳將藤解坼，耗用穀驅除。", "雙竹溪翁杖，柔芎壩戶蔬。", "鎮留僊婿恨，巖邃佛人居。", "照市成都錦，盈庠闕里書。", "採茶驚雉鷓，護橘趁狨狙。", "俗洽庭無訟，年豐廥有儲。", "大資州將懶，藐與世賢疏。", "統總村何有，甘酣分有餘。", "正宜心自怍，更有位誰如。", "未執歸田耒，猶乘集事車。", "好於閑靜處，積漸學樵漁。"]'),
('cc2fee2c-5c97-41dc-bc6e-3b6712a6edd6','句','釋居昱','宋','宋诗','song-poetry','','[]','松聲和雨聽，山色带雲看。',12,'全唐诗/poet.song.8000.json','["松聲和雨聽，山色带雲看。"]'),
('b03759ae-292b-4186-b325-458f606efd42','送僧歸護國寺','李遵勗','宋','宋诗','song-poetry','','[]','雷海譚音出世雄，臺巖香社冠禪叢。',64,'全唐诗/poet.song.8000.json','["雷海譚音出世雄，臺巖香社冠禪叢。", "紅爐點雪靈機密，翠徑斑苔道步通。", "珠水濾羅晨漱凈，豉蓴縈筯午齋豐。", "當帆已應王臣供，金地天龍繞舊宮。"]'),
('500d4fa5-45d7-457f-a189-b56c277206b2','遊黄山','聶宗卿','宋','宋诗','song-poetry','','[]','陟岡尋勝蹟，小徑遶危岑。',72,'全唐诗/poet.song.8000.json','["陟岡尋勝蹟，小徑遶危岑。", "高隱重雲幕，閑游亂石林。", "因潛滌患水，如臥辟寒金。", "松老青姿怪，巖空紫氣深。", "幾宵驚客夢，半夜有猿吟。", "我本神僊裔，徘徊稱道心。"]'),
('2b5fd57f-4f4b-4463-a75a-d9fe761173d6','經照湖方干舊居','吳遵路','宋','宋诗','song-poetry','','[]','磻谿垂釣者，終得展其才。',48,'全唐诗/poet.song.8000.json','["磻谿垂釣者，終得展其才。", "何事先生隱，不逢明主來。", "泉聲秋雨歇，月色夜雲開。", "對此空惆悵，吟魂早晚迴。"]'),
('4ccbe2a0-8fdd-4e0c-b5b8-5203efca6e47','送梵才大師歸天台','吳遵路','宋','宋诗','song-poetry','','[]','高躅動京國，靜緣懷故山。',48,'全唐诗/poet.song.8000.json','["高躅動京國，靜緣懷故山。", "扁舟乘興往，孤鳥倦飛還。", "社漏重湖外，霞城積靄閑。", "碧雲聊寓意，即境自幽關。"]'),
('2e843b99-1613-41f1-9f88-641dad2a797d','題三學山','王雍','宋','宋诗','song-poetry','','[]','五色琉璃白晝寒，當年佛脚萬旃檀。',64,'全唐诗/poet.song.8000.json','["五色琉璃白晝寒，當年佛脚萬旃檀。", "藕絲織出三衣妙，貝葉經傳一偈難。", "夜看聖燈紅菡萏，曉驚飛石碧瑯玕。", "更聞鸚鵡因緣塔，八十山僧試說看。"]'),
('6535462a-89c8-40db-aef2-28849f2e20ec','興慶池禊宴','張奎','宋','宋诗','song-poetry','','[]','公餘連騎賞芳妍，柳重花明祓禊天。',64,'全唐诗/poet.song.8000.json','["公餘連騎賞芳妍，柳重花明祓禊天。", "絲竹繞堤浮舴艋，綺羅照水戲鞦韆。", "回頭景物才三月，屈指光陰又一年。", "臺旆行春暫均逸，鳳凰池暖正思賢。"]'),
('1ed738e8-d8c3-4689-850e-facaa591e373','和答劉夔詠茱萸  其一','程琳','宋','宋诗','song-poetry','','[]','霜枝彫翠雁橫秋，莫倚危樓動旅愁。',32,'全唐诗/poet.song.8000.json','["霜枝彫翠雁橫秋，莫倚危樓動旅愁。", "菊有清香樽有酒，茱萸不插也風流。"]'),
('0094de43-5aa7-469e-9921-6b30d4b2c7b7','和答劉夔詠茱萸  其二','程琳','宋','宋诗','song-poetry','','[]','秋風臺上起高歌，把酒看花意已多。',32,'全唐诗/poet.song.8000.json','["秋風臺上起高歌，把酒看花意已多。", "屈軼不生神豸死，結茱爲佩欲如何。"]'),
('e47a8ab0-4135-4c8c-9baa-127157dac35b','詠西湖','程琳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖多勝景，飛蓋喜相陪。',24,'全唐诗/poet.song.8000.json','["西湖多勝景，飛蓋喜相陪。", "暑氣迎秋盡，江聲向夕來。"]'),
('f7351613-5ad0-403d-9314-4f7b20bc115c','海棠','程琳','宋','宋诗','song-poetry','','[]','海外移根灼灼奇，風情閑麗比應稀。',64,'全唐诗/poet.song.8000.json','["海外移根灼灼奇，風情閑麗比應稀。", "晶瑩寶萼排珠琲，旖旎芳叢簇繡帷。", "繁極只愁隨暮雨，飄多何計駐春暉。", "浣花溪上年年意，露濕煙霞拂客衣。"]'),
('6af5d297-2a5b-46de-b241-40e7c45174fb','冬近','程琳','宋','宋诗','song-poetry','','[]','世間剝復每相尋，此理幾幾喚得譍。',32,'全唐诗/poet.song.8000.json','["世間剝復每相尋，此理幾幾喚得譍。", "萬木凍僵梅有信，黄河冰合井如蒸。"]'),
('3f57f56a-9786-49d8-9fb2-74e1eaff86a0','竊聞集賢侍郎政成公暇時出遊覽因念青社境物之勝長句四韻奉寄','龐籍','宋','宋诗','song-poetry','','[]','政報公餘稱雅懷，兩城煙樹盡樓臺。',64,'全唐诗/poet.song.8000.json','["政報公餘稱雅懷，兩城煙樹盡樓臺。", "波通龍口春戲盛，雲入山門曉望開。", "園館有詩書命筆，海邦無寇破蠻才。", "當時不俟交符印，恨失嵐亭展宴罍。"]'),
('42c74665-cd5d-485b-8894-3213c0410ccf','到塞後有懷青社','龐籍','宋','宋诗','song-poetry','','[]','初到營陵春始回，泱泱風物接梧臺。',64,'全唐诗/poet.song.8000.json','["初到營陵春始回，泱泱風物接梧臺。", "魚鹽利重通闤盛，箏瑟聲和宴席開。", "天際膚雲連岱色，海中靈藥慕仙才。", "早知未許身閑去，悔捨堯田石澗來。"]'),
('eddf0739-6675-4f40-ba07-1b588b603bb7','送餘姚知縣陳最寺丞','龐籍','宋','宋诗','song-poetry','','[]','需頭章薦重，方底詔除榮。',48,'全唐诗/poet.song.8000.json','["需頭章薦重，方底詔除榮。", "人比鳴琴令，官參夢馬卿。", "菰煙吳地景，濤鷺浙江程。", "美政應天報，姚虞舊俗清。"]'),
('5f828c1d-086d-41e3-9590-d7e0f08025f1','記異','龐籍','宋','宋诗','song-poetry','','[]','冬至子時陽已生，道隨陽長物將萌。',32,'全唐诗/poet.song.8000.json','["冬至子時陽已生，道隨陽長物將萌。", "星辰賜告銘心骨，願以寬章輔至平。"]'),
('81773c28-30d7-4249-a6d4-6e81ebf906b4','經嚴子陵釣臺作四首  其一','龐籍','宋','宋诗','song-poetry','','[]','翠岫臨寒瀨，先生老此中。',48,'全唐诗/poet.song.8000.json','["翠岫臨寒瀨，先生老此中。", "釣耕輕萬乘，要領戒三公。", "入宿星躔動，歸來世網空。", "何人知此意，千古激澆風。"]'),
('3c1f4d34-d26d-4c46-a465-b1e73b1712ed','經嚴子陵釣臺作四首  其二','龐籍','宋','宋诗','song-poetry','','[]','道閉甯濡足，時平亦括囊。',48,'全唐诗/poet.song.8000.json','["道閉甯濡足，時平亦括囊。", "故人登世帝，清瀨自吾鄉。", "渭叟非真釣，商奴是詐狂。", "先生不可問，天外一鸞翔。"]'),
('91ec24d2-8df5-435a-b58b-6c9fefd3380f','經嚴子陵釣臺作四首  其三','龐籍','宋','宋诗','song-poetry','','[]','聞箇狂奴足，生平在草萊。',48,'全唐诗/poet.song.8000.json','["聞箇狂奴足，生平在草萊。", "不榮升帝腹，寧自蹋魚臺。", "步武中朝下，胼胝故國回。", "滄浪重一濯，京雒有塵埃。"]'),
('addaf374-fd6d-4787-b811-9e34bcebf3bb','經嚴子陵釣臺作四首  其四','龐籍','宋','宋诗','song-poetry','','[]','長天杳杳道冥冥，一士孤風達至精。',64,'全唐诗/poet.song.8000.json','["長天杳杳道冥冥，一士孤風達至精。", "雲若有心應有著，魚緣輕餌是輕生。", "何人楚澤三年放，此地家灘七里清。", "應宿將臣皆列士，未將煙水博功名。"]'),
('bd48fe69-16d3-4f63-b4e2-0047b975e4b3','句  其一','龐籍','宋','宋诗','song-poetry','','[]','毗耶長者入街初。',8,'全唐诗/poet.song.8000.json','["毗耶長者入街初。"]'),
('b31d2cf2-a1b4-4c17-82f6-4ab1cdb6e84e','句  其二','龐籍','宋','宋诗','song-poetry','','[]','田園貧宰相，圖史富書生。',12,'全唐诗/poet.song.8000.json','["田園貧宰相，圖史富書生。"]'),
('11a97fc8-e598-434b-835d-8dd710dc04f3','句  其三','龐籍','宋','宋诗','song-poetry','','[]','巢鳳閣邊勞遠夢，繫龍橋下認前題。',16,'全唐诗/poet.song.8000.json','["巢鳳閣邊勞遠夢，繫龍橋下認前題。"]'),
('4dda0ec7-1ff2-4a25-ad56-7d22654f41d4','句  其四','龐籍','宋','宋诗','song-poetry','','[]','蜀道盤紆去不迷，故園猶在武陽西。',16,'全唐诗/poet.song.8000.json','["蜀道盤紆去不迷，故園猶在武陽西。"]'),
('9d1eaf6d-84a1-4262-9eaa-78ee966cb8cc','題太平興國宮','李受','宋','宋诗','song-poetry','','[]','香爐峰下宅天官，三界方知可往還。',64,'全唐诗/poet.song.8000.json','["香爐峰下宅天官，三界方知可往還。", "白石眼前分世路，紫雲頭上接天班。", "滄溟豈隔毫芒內，憶劫皆歸瞬息間。", "但得心源到真境，凌虛鸞鶴會躋攀。"]'),
('72e3d344-c9cc-41c0-8b56-0e6eae590d85','題應天寺','齊廓','宋','宋诗','song-poetry','','[]','寶勢聳如飛，簷牙照錦翬。',48,'全唐诗/poet.song.8000.json','["寶勢聳如飛，簷牙照錦翬。", "路盤危磴出，僧觸斷雲歸。", "萬井分塵界，千巖在目圍。", "浮生枉多事，到此合忘機。"]'),
('86f19223-6c59-42fa-a34c-668572e530ce','如歸亭','齊廓','宋','宋诗','song-poetry','','[]','翬飛綺構成，賓至得佳名。',48,'全唐诗/poet.song.8000.json','["翬飛綺構成，賓至得佳名。", "岫列千螺出，江涵匹練平。", "吟看客帆度，坐見釣舟橫。", "獨倚雕闌外，令人心骨清。"]'),
('ca288054-6f76-490b-973a-4dc790a3fd55','句','齊廓','宋','宋诗','song-poetry','','[]','祖龍神兵驅不得，揮電成鞭有遺迹。',16,'全唐诗/poet.song.8000.json','["祖龍神兵驅不得，揮電成鞭有遺迹。"]'),
('4b171fbe-93e6-4b06-b152-59853386a1cf','石傘峰書堂','齊唐','宋','宋诗','song-poetry','','[]','傘峰一片崎危石，枕在青冥絕壁間。',64,'全唐诗/poet.song.8000.json','["傘峰一片崎危石，枕在青冥絕壁間。", "人作鹽梅資世濟，蹟留巖岫與雲閑。", "露盤高出長年殿，羽蓋斜臨宛委山。", "藐矣諸孫愧前躅，但開三徑掩柴關。"]'),
('b79da9d1-4b75-4a87-93ea-c98f7d1a3c1c','題禹廟','齊唐','宋','宋诗','song-poetry','','[]','削斷龍門劍力閑，遺祠終古鑑湖邊。',64,'全唐诗/poet.song.8000.json','["削斷龍門劍力閑，遺祠終古鑑湖邊。", "崑墟到海曾窮地，石穴藏書不記年。", "春色門牆花滴雨，曉光臺殿水浮煙。", "塗山萬國梯航集，告禪靈壇豈偶然。"]'),
('d913798d-d30a-4dee-af39-bf38b5ad999d','送張尊師監龍瑞宮','齊唐','宋','宋诗','song-poetry','','[]','陽明洞天三月春，桃花艷艷迎笑人。',128,'全唐诗/poet.song.8000.json','["陽明洞天三月春，桃花艷艷迎笑人。", "仙官瑤裾翠羽裾，直上非煙驂紫麟。", "手把赤書秘玉文，朝謁太素三元君。", "琳房窈窕出青雲，衆真嘯語林際聞。", "山精木魅知有主，斂戢鬼火摧飈輪。", "崇巖絕壑足清放，抗跡萬里無埃塵。", "物不疵癘年穀熟，綽約曾潛姑射神。", "祈師努力學此道，下濟澤國窮鰥民。"]'),
('fb70e08d-1027-4c13-8ecf-39bcbd7b053a','仙茅','齊唐','宋','宋诗','song-poetry','','[]','仙方上品誇靈種，忽怪靈芝拆紫苞。',32,'全唐诗/poet.song.8000.json','["仙方上品誇靈種，忽怪靈芝拆紫苞。", "玉澤返嬰看驗術，少微山是小三茅。"]'),
('cd4b13eb-8b99-41ab-93d0-b4bc15defa1c','玉洞','齊唐','宋','宋诗','song-poetry','','[]','白石洞間路，吾家在其中。',24,'全唐诗/poet.song.8000.json','["白石洞間路，吾家在其中。", "琴窗與書閣，一半是雲封。"]'),
('4b09974d-6f05-4b50-9a00-9c337699ee62','披雲樓','齊唐','宋','宋诗','song-poetry','','[]','元和文物盛羣賢，曾借蓬萊住列仙。',32,'全唐诗/poet.song.8000.json','["元和文物盛羣賢，曾借蓬萊住列仙。", "畫入簾櫳煙外寺，鑑搖臺榭水中天。"]'),
('093553a2-47a5-44b4-a8fb-a32875e16d53','越州通判廳事後新鑿方井','齊唐','宋','宋诗','song-poetry','','[]','臥龍山脚寒巖底，沮洳泥涂不記年。',64,'全唐诗/poet.song.8000.json','["臥龍山脚寒巖底，沮洳泥涂不記年。", "疏引一朝逢智匠，坐令咫尺變璇淵。", "待時藏用懷靈德，濟物施功假世賢。", "留作越人歌詠事，召棠陰下酌貪泉。"]'),
('c0e825ee-3115-439c-acc3-2723a36e255b','題上虞南塔院','齊唐','宋','宋诗','song-poetry','','[]','雁級指高冥，登瞻地域靈。',24,'全唐诗/poet.song.8000.json','["雁級指高冥，登瞻地域靈。", "路尋滄海斷，山带沃洲青。"]'),
('f33128e4-4592-4277-b643-443e0ea1a23c','長葺聖壽寺','齊唐','宋','宋诗','song-poetry','','[]','建中天子寄彌綸，築隱商巖舊葉存。',64,'全唐诗/poet.song.8000.json','["建中天子寄彌綸，築隱商巖舊葉存。", "麟笑有文藏冊府，駟車流慶屬衡門。", "金繩寶構新空界，劍樹真游接古原。", "藐矣諸孫愧前躅，脫身仍謝北山猿。"]'),
('f38c3528-9ee8-4d8c-bc93-953b9a67e420','十詠  其一','齊唐','宋','宋诗','song-poetry','','[]','遠適廬陵郡，經旬泛楚天。',24,'全唐诗/poet.song.8000.json','["遠適廬陵郡，經旬泛楚天。", "江山晴繞枕，星斗夜隨船。"]'),
('2e702fb4-971d-4337-8035-10957e31085a','十詠  其二','齊唐','宋','宋诗','song-poetry','','[]','遠適廬陵郡，重江去不窮。',24,'全唐诗/poet.song.8000.json','["遠適廬陵郡，重江去不窮。", "全家片帆底，三月怒濤中。"]'),
('92bebd7c-36e6-4180-9c5e-fe6baa891ded','登狼山閣','齊唐','宋','宋诗','song-poetry','','[]','海腹藏吳楚，天樞轉斗牛。',24,'全唐诗/poet.song.8000.json','["海腹藏吳楚，天樞轉斗牛。", "夜分驚日浴，潮落見鯨遊。"]'),
('5bfda26f-776f-4dd4-a82b-0dc5bcba4ec3','烏江廟','齊唐','宋','宋诗','song-poetry','','[]','天意降時雨，山川潛出雲。',24,'全唐诗/poet.song.8000.json','["天意降時雨，山川潛出雲。", "鋤秦將授漢，此力半因君。"]'),
('a5c737a6-b5dc-47e6-8c18-234f86d3cb41','南雄城樓','齊唐','宋','宋诗','song-poetry','','[]','漢初開郡出南夷，萬壑千巖足嶮巇。',48,'全唐诗/poet.song.8000.json','["漢初開郡出南夷，萬壑千巖足嶮巇。", "天上斗牛應共域，人間江嶺自分岐。", "尉佗椎髻遺風俗，馬援飛鳶墮水時。"]'),
('240a127d-a374-4e30-84c9-4782bac4e871','觀潮','齊唐','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','何意滔天苦作威，狂驅海若走馮夷。',64,'全唐诗/poet.song.8000.json','["何意滔天苦作威，狂驅海若走馮夷。", "因看平地波翻起，知是滄浪鼎沸時。", "初似長平萬瓦震，忽如圓嶠六鼇移。", "直應待得澄如練，會有安流往濟時。"]'),
('0e073f98-bbfb-4bb8-a60c-fafb982413b0','句  其一','齊唐','宋','宋诗','song-poetry','','[]','戴水寒流對軒檻，桃源深徑入漁樵。',16,'全唐诗/poet.song.8000.json','["戴水寒流對軒檻，桃源深徑入漁樵。"]'),
('f2656dcb-338a-4e42-861d-f736e8badd76','句  其二','齊唐','宋','宋诗','song-poetry','','[]','楩柟非給燎，鱮魴必施罛。',12,'全唐诗/poet.song.8000.json','["楩柟非給燎，鱮魴必施罛。"]'),
('affb6648-056c-46f6-9191-350c51f363bf','句  其三','齊唐','宋','宋诗','song-poetry','','[]','纖綸魚羅尾，鳴鏃雉摧班。',12,'全唐诗/poet.song.8000.json','["纖綸魚羅尾，鳴鏃雉摧班。"]'),
('0c346d9c-da44-4d91-a1ad-c7bf76447533','句  其四','齊唐','宋','宋诗','song-poetry','','[]','新築隄成號杜塘，結茅深穩佔湖光。',16,'全唐诗/poet.song.8000.json','["新築隄成號杜塘，結茅深穩佔湖光。"]'),
('3451edab-2b9f-4cb7-99c4-249d3dede9a0','句  其五','齊唐','宋','宋诗','song-poetry','','[]','掃拂漁蓬出涇來。',8,'全唐诗/poet.song.8000.json','["掃拂漁蓬出涇來。"]'),
('004b104d-375c-4459-83a6-2c8a0246382c','句  其六','齊唐','宋','宋诗','song-poetry','','[]','獨坐澗邊聽水落，卻來洞口看雲生。',16,'全唐诗/poet.song.8000.json','["獨坐澗邊聽水落，卻來洞口看雲生。"]'),
('90a7cdba-f23d-460d-b8c6-f6fea18d465c','句  其七','齊唐','宋','宋诗','song-poetry','','[]','飛棟新成蘸碧軒，會稽山脚照湖邊。',16,'全唐诗/poet.song.8000.json','["飛棟新成蘸碧軒，會稽山脚照湖邊。"]'),
('da252e1e-18f4-4bdd-b8ce-d84f2cf59799','句  其八','齊唐','宋','宋诗','song-poetry','','[]','偃藩唯覺訟鈴虛。',8,'全唐诗/poet.song.8000.json','["偃藩唯覺訟鈴虛。"]'),
('bff9c1fc-23a7-4a09-a86e-17467ddadc2b','句  其九','齊唐','宋','宋诗','song-poetry','','[]','唯有梅花報春早，雪中傳信過江干。',16,'全唐诗/poet.song.8000.json','["唯有梅花報春早，雪中傳信過江干。"]'),
('d2cf475a-f471-46cd-a77a-46c47bcbb4c4','句  其一○','齊唐','宋','宋诗','song-poetry','','[]','劍水清涼夢筆山，戟衣照日啟重關。',16,'全唐诗/poet.song.8000.json','["劍水清涼夢筆山，戟衣照日啟重關。"]'),
('463ef7ac-b4a0-4abc-98c4-f5b7bf380be6','句  其一一','齊唐','宋','宋诗','song-poetry','','[]','歲貴波然素，時珍蟹有箱。',12,'全唐诗/poet.song.8000.json','["歲貴波然素，時珍蟹有箱。"]'),
('35ea4749-e92c-4741-95ac-f0f2967842db','句  其一二','齊唐','宋','宋诗','song-poetry','','[]','身閑婚嫁畢，秋老蟹螯肥。',12,'全唐诗/poet.song.8000.json','["身閑婚嫁畢，秋老蟹螯肥。"]'),
('2effe294-987e-43b6-a32a-8ba570fd7c37','句  其一三','齊唐','宋','宋诗','song-poetry','','[]','春波池上搘琴薦，秋月桐陰把蟹螯。',16,'全唐诗/poet.song.8000.json','["春波池上搘琴薦，秋月桐陰把蟹螯。"]'),
('f55567c9-ba17-4557-bc7d-9ed58071bf56','歌一首','段穀','宋','宋诗','song-poetry','','[]','一間茅屋，尚自修治。',45,'全唐诗/poet.song.8000.json','["一間茅屋，尚自修治。", "信任風吹，連簷破碎。", "斗栱邪欹，看看倒也。", "牆壁作散土一堆，主人永不來歸。"]'),
('45f0e128-4b19-4b60-8642-68bc3c5208e9','九鯉湖','張式','宋','宋诗','song-poetry','','[]','半生漂落江湖外，此日登樓花正開。',64,'全唐诗/poet.song.8000.json','["半生漂落江湖外，此日登樓花正開。", "丹竈依然沈澗水，珠簾空自掛瑤臺。", "昔年道士何時去，前度遊人今又來。", "點檢洞門題詠處，幾多墨迹篆蒼苔。"]'),
('eaf1c513-a8cf-44e8-8c49-edf9db9db9ce','謝黄惣太博見示文集','范仲淹','宋','宋诗','song-poetry','','[]','松桂有嘉色，不與衆芳期。',180,'全唐诗/poet.song.8000.json','["松桂有嘉色，不與衆芳期。", "金石有正聲，詎將羣響隨。", "君子著雅言，以道不以時。", "仰止江夏公，大醇無小疵。", "孜孜經緯心，落落教化辭。", "上有帝皇道，下有人臣規。", "邈與聖賢會，豈以富貴移。", "誰言荆棘滋，獨此生蘭芝。", "誰言鼃黽繁，獨此蟠龍龜。", "豈徒一時異，將爲千古奇。", "願此周召風，達我堯舜知。", "致之諷諫路，陞之誥命司。", "二雅正得失，五典陳雍熙。", "頌聲格九廟，王澤及四夷。", "自然天下文，不復迷宗師。"]'),
('c2d6037c-e4fe-4d54-be33-444a630de693','四民詩 士','范仲淹','宋','宋诗','song-poetry','','[]','前王詔多士，咸以德爲先。',252,'全唐诗/poet.song.8000.json','["前王詔多士，咸以德爲先。", "道從仁義廣，名由忠孝全。", "美祿報爾功，好爵縻爾賢。", "黜陟金鑑下，昭昭媸與妍。", "此道日以疏，善惡何茫然。", "君子不斥怨，歸諸命與天。", "術者乘其隙，異端千萬惑。", "天道入指掌，神心出胸臆。", "聽幽不聽明，言命不言德。", "學者忽其本，仕者浮於職。", "節義爲空言，功名思苟得。", "天下無所勸，賞罰幾乎息。", "陰陽有變化，其神固不測。", "禍福有倚伏，循環亦無極。", "前聖不敢言，小人爾能臆。", "裨竈方激揚，孔子甘寂默。", "六經無光輝，反如日月蝕。", "大道豈復興，此弊何時抑。", "末路競馳騁，澆風揚羽翼。", "昔多松柏心，今皆桃李色。", "願言造物者，回此天地力。"]'),
('1dff4f3e-9e03-498e-a722-36ceea2704a6','四民詩 農','范仲淹','宋','宋诗','song-poetry','','[]','聖人作耒耜，蒼蒼民乃粒。',120,'全唐诗/poet.song.8000.json','["聖人作耒耜，蒼蒼民乃粒。", "國俗儉且淳，人足而家給。", "九載襄陵禍，比户猶安輯。", "何人變清風，驕奢日相襲。", "制度非唐虞，賦斂由呼吸。", "傷哉田桑人，常悲大絃急。", "一夫耕幾壟，游墮如雲集。", "一蠶吐幾絲，羅綺如山入。", "太平不自存，凶荒亦何及。", "神農與后稷，有靈應爲泣。"]'),
('ef6f8ea5-9df8-418d-9568-584bae2915a4','四民詩 工','范仲淹','宋','宋诗','song-poetry','','[]','先王教百工，作爲天下器。',144,'全唐诗/poet.song.8000.json','["先王教百工，作爲天下器。", "周旦意不朽，刊之考工記。", "嗟嗟遠聖人，制度日以紛。", "窈窕阿房宫，萬態横青雲。", "熒煌甲乙帳，一朝那肯焚。", "秦漢驕心起，陳隋益其侈。", "鼓舞天下風，滔滔弗能止。", "可甚佛老徒，不取慈儉書。", "竭我百家産，崇爾一室居。", "四海競如此，金碧照萬里。", "茅茨帝者榮，今爲庶人恥。", "宜哉老成言，欲攦般輸指。"]'),
('d6d2cf25-55b6-40c6-8299-c1cddaf661fa','商','范仲淹','宋','宋诗','song-poetry','','[]','嘗聞商者云，轉貨賴斯民。',228,'全唐诗/poet.song.8000.json','["嘗聞商者云，轉貨賴斯民。", "遠近日中合，有無天下均。", "上以利吾國，下以藩吾身。", "周官有常籍，豈云逐末人。", "天意亦何事，狼虎生貪秦。", "經界變阡陌，吾商苦悲辛。", "四民無常籍，茫茫僞與真。", "游者竊吾利，墮者亂吾倫。", "淳源一以蕩，頽波浩無津。", "可堪貴與富，侈態日日新。", "萬里奉綺羅，九陌資埃塵。", "窮山無遺寶，竭海無遺珍。", "鬼神爲之勞，天地爲之貧。", "此弊已千載，千載猶因循。", "桑柘不成林，荆棘有餘春。", "吾商則何罪，君子恥爲鄰。", "上有堯舜主，下有周召臣。", "琴瑟願更張，使我歌良辰。", "何日用此言，皇天豈不仁。"]'),
('31f08551-dc1e-4e7a-afe0-5df8d76edd95','寄題孫氏碧鮮亭','范仲淹','宋','宋诗','song-poetry','','[]','天地何風流，復生王子猷。',216,'全唐诗/poet.song.8000.json','["天地何風流，復生王子猷。", "黄金買碧鮮，綠玉排清秋。", "非木亦非草，東君歲寒寶。", "耿耿金石性，雪霜不能老。", "清風及故人，徘徊過此君。", "泠泠鈞天音，千載猶得聞。", "應是聖賢魄，鍾爲此標格。", "高節見直清，靈心隱虛白。", "粉筠多體貌，錦籜見兒童。", "上交松桂枝，下結蘭蕙叢。", "秀氣藹晴嵐，翠光凝綠水。", "明月白露中，静如隱君子。", "不願湘靈泣，不求伶倫吹。", "鳯皇得未晚，蛟龍起何時。", "蕭蕭雲水間，良與主人宜。", "紅塵滿浮世，何當拂長袂。", "坐嘯此亭中，行歌此亭際。", "逍遙復逍遙，不知千萬歲。"]'),
('1124d200-65e6-4e58-9ba3-0d218cd6ecad','贈張先生','范仲淹','宋','宋诗','song-poetry','','[]','應是少微星，又云嚴君平。',288,'全唐诗/poet.song.8000.json','["應是少微星，又云嚴君平。", "浩歌七十餘，未嘗識戈兵。", "康寧福已大，清静道自生。", "邈與神仙期，不犯寵辱驚。", "讀易夢周公，大得天地情。", "養志學浮丘，久鍊日月精。", "壽存金石性，嘯作鸞鳯聲。", "陰德不形言，一一在幽明。", "何當換金骨，五雲朝玉京。", "有客淳且狂，少小愛功名。", "非謂鐘鼎重，非謂簞瓢輕。", "素聞前哲道，欲向聖朝行。", "風塵三十六，未作萬人英。", "乃聞頭角者，五神長戰争。", "禍福有倚伏，富貴多虧盈。", "金門不乏雋，白雲宜退耕。", "人間有嵩華，棲之比蓬瀛。", "芝田春藹藹，玉澗晝錚錚。", "峰巒多秀色，杉桂一何清。", "月壑認瑤池，花巖列錦城。", "朱鉉冉冉奏，金醴遲遲傾。", "相勸綺季徒，頽玉信縱横。", "此樂不尋常，何苦事浮榮。", "願師先覺者，遠遠濯吾纓。"]'),
('f7217f10-f18f-45b0-8673-b2685d13f751','明月謠','范仲淹','宋','宋诗','song-poetry','','[]','明月在天西，初如玉鈎微。',120,'全唐诗/poet.song.8000.json','["明月在天西，初如玉鈎微。", "一夕增一分，堂堂有餘輝。", "不掩五星耀，不礙浮雲飛。", "徘徊河漢間，秀色若可餐。", "清風起叢桂，白露生階蘭。", "高樓望君時，爲君拂金徽。", "奏以堯舜音，此音天與稀。", "明月或可聞，顧我亦依依。", "月有萬古光，人有萬古心。", "此心良可歌，憑月爲知音。"]'),
('066505e4-48fb-4e4e-a0b1-b08c44af2793','上漢謠','范仲淹','宋','宋诗','song-poetry','','[]','真人累陰德，聞之三十天。',240,'全唐诗/poet.song.8000.json','["真人累陰德，聞之三十天。", "一朝鸞鶴來，高舉爲神仙。", "冉冉去紅塵，飄飄凌紫煙。", "下有脩真者，望拜何拳拳。", "願君銀臺上，侍帝玉案前。", "當有人間問，請爲天下宣。", "自從混沌死，淳風日衰靡。", "百王道不同，萬物情多詭。", "堯舜累代仁，絃歌始能治。", "桀紂一旦非，宗廟自然毁。", "是非既循環，興亡亦繼軌。", "福至在朱門，禍來先赤子。", "嘗聞自天意，天意豈如此。", "何爲治亂間，多言歷數爾。", "願天賜吾君，如天千萬春。", "明與日月久，恩將雨露均。", "帝力何可見，物情自欣欣。", "人復不言天，天亦不傷人。", "天人兩相忘，逍遙何有鄉。", "吾當飲且歌，不知羲與黄。"]'),
('82716ca0-020e-438e-b46a-f594592ac24c','清風謠','范仲淹','宋','宋诗','song-poetry','','[]','清風何處來，先此高高臺。',168,'全唐诗/poet.song.8000.json','["清風何處來，先此高高臺。", "蘭叢國香起，桂枝天籟迥。", "飄飄度清漢，浮雲安在哉。", "萬古鬱結心，一旦爲君開。", "有客慰所思，臨風久徘徊。", "神若遊華胥，身疑立天台。", "極渇飲沆瀣，大暑執瓊瓌。", "曠如攜松丘，騰上煙霞遊。", "熙如揖莊老，語人逍遙道。", "朱絃鼓其薫，可以解吾民。", "滄浪比其清，可以濯吾纓。", "願此陽春時，勿使飄暴生。", "千靈無結愠，萬卉不摧榮。", "庶幾宋玉賦，聊廣楚王情。"]'),
('13a2b667-a076-43a6-924a-feb7d6f6d575','書海陵滕從事文會堂','范仲淹','宋','宋诗','song-poetry','','[]','東南滄海郡，幕府清風堂。',120,'全唐诗/poet.song.8000.json','["東南滄海郡，幕府清風堂。", "詩書對周孔，琴瑟親羲黄。", "君子不獨樂，我朋來遠方。", "言蘭一相接，豈特十步香。", "德星一相聚，直有千載光。", "道味清可挹，文思高若翔。", "笙磬得同聲，精色皆激揚。", "栽培盡桃李，棲止皆鸞皇。", "琢玉作鎮圭，鑄金爲干將。", "猗哉滕子京，此意久而芳。"]'),
('b78b270e-8eb3-411c-a985-8c6de68f68dd','上都行送張伯玉','范仲淹','宋','宋诗','song-poetry','','[]','上都有聖人，日月一以新。',120,'全唐诗/poet.song.8000.json','["上都有聖人，日月一以新。", "曄曄天下才，西走堯舜賓。", "百谷望東浸，萬星依北辰。", "直者爲之轅，曲者爲之輪。", "一材不復遺，况此席上珍。", "南山張公子，氣象清且淳。", "懷有綺繡文，朝無瓜瓞親。", "寸心如鐵石，不羞賤與貧。", "買臣起白社，賈誼富青春。", "寶此金轆轤，去去延平津。"]'),
('b5f201dc-4fad-4325-9fdf-35f0138d2e4b','鳴琴','范仲淹','宋','宋诗','song-poetry','','[]','思古理鳴琴，聲聲動金玉。',24,'全唐诗/poet.song.8000.json','["思古理鳴琴，聲聲動金玉。", "何以報昔人，傳此堯舜曲。"]'),
('6be303fb-3aae-4057-b3ef-7161af82f8c5','馴鷗詠','范仲淹','宋','宋诗','song-poetry','','[]','萬物有常性，性無不貴生。',120,'全唐诗/poet.song.8000.json','["萬物有常性，性無不貴生。", "風翔與駿奔，一一遠害情。", "鴥彼沙上鷗，皎皎霜雪明。", "月宿滄洲静，日浴滄浪清。", "何以狎溪人，溪人淡無營。", "循循自飲啄，往往相逢迎。", "徘徊兩無猜，何慕亦何驚。", "客有懷依依，雲水言將歸。", "逐爾羣鷗樂，羣鷗爾勿飛。", "此心未忘者，天機非殺機。"]'),
('a35a5803-973f-41a2-b708-dc28085b1cb4','古鑑','范仲淹','宋','宋诗','song-poetry','','[]','磨此千年鑑，朱顔清可覽。',24,'全唐诗/poet.song.8000.json','["磨此千年鑑，朱顔清可覽。", "君看日月光，無求照人膽。"]'),
('5e93eca1-c7b0-4f52-85b5-9e5afbbf2e68','贈樊秀才','范仲淹','宋','宋诗','song-poetry','','[]','五代雲雷屯，九野皆龍戰。',204,'全唐诗/poet.song.8000.json','["五代雲雷屯，九野皆龍戰。", "聞國如棋枰，皇極何由建。", "太祖乘天飛，大發光華旦。", "樊公江表來，經綸速如電。", "微子入姬周，倉皇救塗炭。", "四海乃大同，萬里聞薫風。", "禮樂與征伐，出自明光宫。", "大勳未大賞，積慶宜無窮。", "李廣不封侯，繼世多英雄。", "公有承家子，所至神明理。", "復有起家孫，一見知千里。", "和氣十洲春，清流九江水。", "非有神筆夢，粲粲文何綺。", "天子青春朝，列鼎招英髦。", "明年桃李開，禹浪如霞高。", "之子可變化，咫尺登金鰲。", "始知祖德長，光輝傳佩刀。"]'),
('947117e3-ac4c-48eb-b00b-43c2d6960705','贈棋者','范仲淹','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','何處逢神仙，傳此棋上旨。',132,'全唐诗/poet.song.8000.json','["何處逢神仙，傳此棋上旨。", "静持生殺權，密照安危理。", "接勝如雲舒，禦敵如山止。", "突圍秦師震，諸侯皆披靡。", "入險漢將危，奇兵翻背水。", "勢應不可隳，關河常表裏。", "南軒春日長，國手相得喜。", "泰山不礙目，疾雷不經耳。", "一子貴千金，一路重千里。", "精思入於神，變化胡能擬。", "成敗繫之人，吾當著棋史。"]'),
('10f2ecec-8289-4e93-bb2a-59a868aff084','歲寒堂三題 歲寒堂','范仲淹','宋','宋诗','song-poetry','','[]','我先本唐相，奕世天衢行。',144,'全唐诗/poet.song.8000.json','["我先本唐相，奕世天衢行。", "子孫四方志，有家在江城。", "雙松儼可愛，高堂因以名。", "雅知堂上居，宛得山中情。", "目有千年色，耳有千年聲。", "六月無炎光，長如玉壺清。", "于以聚詩書，教子脩誠明。", "于以列鐘鼓，邀賓樂昇平。", "綠煙亦何知，終日在簷楹。", "太陽無偏照，自然虚白生。", "不向揺落地，何憂歲峥嶸。", "勗哉肯構人，處之千萬榮。"]'),
('c541a127-f132-4d98-b8a7-22103ec8fe7b','歲寒堂三題 君子樹','范仲淹','宋','宋诗','song-poetry','','[]','二松何年植，清風未嘗息。',108,'全唐诗/poet.song.8000.json','["二松何年植，清風未嘗息。", "夭矯向庭户，雙龍思霹靂。", "豈無桃李姿，賤彼非正色。", "豈無蘭菊芳，貴此有清德。", "萬木怨揺落，獨如春山碧。", "乃知天地威，亦向歲寒惜。", "有聲若江湖，有心若金璧。", "雅爲君子材，對之每前席。", "或當應自然，化爲補天石。"]'),
('809362ed-c733-45b0-8926-6c65e66f44b6','歲寒堂三題 松風閣','范仲淹','宋','宋诗','song-poetry','','[]','此閣宜登臨，上有松風吟。',96,'全唐诗/poet.song.8000.json','["此閣宜登臨，上有松風吟。", "非絃亦非匏，自起簫韶音。", "明月萬里時，何必開綠琴。", "鳯皇下雲霓，鏘鏘嗚中林。", "淳如葛天歌，太古傳于今。", "潔如庖羲易，洗人平生心。", "安得嘉賓來，當之共披襟。", "陶景若在僊，千載一相尋。"]'),
('28cf1dd6-eb27-4d50-9a40-356bc5e10ae9','贈都下隱者','范仲淹','宋','宋诗','song-poetry','','[]','梅福隱市門，嚴平居卜肆。',120,'全唐诗/poet.song.8000.json','["梅福隱市門，嚴平居卜肆。", "乃知神仙徒，非必煙霞地。", "異哉西山人，逍遙京洛塵。", "門多長者車，察脈如有神。", "軒皇萬餘載，此術了然在。", "精意洞五行，飛名落四海。", "結舍擬滄洲，東池接御溝。", "蘭芳披幽徑，琴樽在小舟。", "清夜泛月華，宛是江湖遊。", "他日上雲去，兹爲黄鶴樓。"]'),
('dc7936d8-bb17-47f0-9be7-70b9a849c4ac','和人遊嵩山十二題 公路澗','范仲淹','宋','宋诗','song-poetry','','[]','嵩高發靈源，北望洛陽注。',48,'全唐诗/poet.song.8000.json','["嵩高發靈源，北望洛陽注。", "清流引河漢，白氣横雲霧。", "英雄惜此地，百萬曾相拒。", "近代無戰争，常人自來去。"]'),
('d24a22a0-f429-4fa3-85ac-2ee5f8ac0641','和人遊嵩山十二題 拜馬澗','范仲淹','宋','宋诗','song-poetry','','[]','傳聞王子仙，澗邊遺一驥。',36,'全唐诗/poet.song.8000.json','["傳聞王子仙，澗邊遺一驥。", "當時青雲路，雞犬亦可致。", "未必真龍媒，悠悠在平地。"]'),
('db6d2e18-0911-424d-a845-da5943e2d62c','和人遊嵩山十二題 二室道','范仲淹','宋','宋诗','song-poetry','','[]','太室何森聳，少室欲飛動。',36,'全唐诗/poet.song.8000.json','["太室何森聳，少室欲飛動。", "相對起雲霞，恍如遊仙夢。", "何以寵此行，行歌降神頌。"]'),
('9498c128-92ab-440a-9d9a-c134aef65f0b','和人遊嵩山十二題 自峻極中院步登太室中峰','范仲淹','宋','宋诗','song-poetry','','[]','白雲隨人來，翩翩疾如馬。',36,'全唐诗/poet.song.8000.json','["白雲隨人來，翩翩疾如馬。", "洪崖與浮丘，襟袂安足把。", "不來峻極遊，何能小天下。"]'),
('31fa2db7-7e92-44a3-8565-c9d2e3ca127b','和人遊嵩山十二題 玉女窗','范仲淹','宋','宋诗','song-poetry','','[]','窈窕玉女窗，想像玉女粧。',36,'全唐诗/poet.song.8000.json','["窈窕玉女窗，想像玉女粧。", "皎皎月爲鑑，飄飄霓作裳。", "莫學陽臺夢，無端惑楚王。"]'),
('7c974feb-68e4-4789-98f2-dd4165306b80','和人遊嵩山十二題 玉女搗衣石','范仲淹','宋','宋诗','song-poetry','','[]','但見巖前砧，誰聞月下杵。',36,'全唐诗/poet.song.8000.json','["但見巖前砧，誰聞月下杵。", "金文與鐵色，璨璨知千古。", "試問搗衣仙，何如補天女。"]'),
('6c421393-2b15-41e2-8fac-5fb617c21089','和人遊嵩山十二題 天門','范仲淹','宋','宋诗','song-poetry','','[]','天門絕境遊，熙然揖灝氣。',36,'全唐诗/poet.song.8000.json','["天門絕境遊，熙然揖灝氣。", "下顧莽蒼間，雲雷走平地。", "天威不遠人，孰起欺天意。"]'),
('967a781f-b3d1-439b-8857-181a303f3e86','和人遊嵩山十二題 天門泉','范仲淹','宋','宋诗','song-poetry','','[]','天門有靈泉，埃塵未嘗至。',36,'全唐诗/poet.song.8000.json','["天門有靈泉，埃塵未嘗至。", "日月自高照，雲霞亦輝庇。", "惟抱夷齊心，飲之可無愧。"]'),
('f7dbc81d-8263-4cce-b900-ab230544e0b9','和人遊嵩山十二題 天池','范仲淹','宋','宋诗','song-poetry','','[]','岳頂見天池，神異安可度。',36,'全唐诗/poet.song.8000.json','["岳頂見天池，神異安可度。", "勿謂無波濤，雲雷有時惡。", "乘此澄清間，吾纓可以濯。"]'),
('bfd82bc5-f8f4-48e7-af9d-6919c13e964e','和人遊嵩山十二題 三醉石','范仲淹','宋','宋诗','song-poetry','','[]','巍巍八仙壇，上有三醉石。',36,'全唐诗/poet.song.8000.json','["巍巍八仙壇，上有三醉石。", "憐此高陽徒，如樂華胥域。", "憔悴澤邊人，獨醒良可惜。"]'),
('ada971b3-723c-452c-8570-4ee7ba2f1c0b','和人遊嵩山十二題 峻極上寺','范仲淹','宋','宋诗','song-poetry','','[]','徘徊峻極寺，清意滿烟霞。',36,'全唐诗/poet.song.8000.json','["徘徊峻極寺，清意滿烟霞。", "好風從天來，吹落桂樹花。", "高高人物外，猶屬梵王家。"]'),
('7f224403-73ea-4068-8106-c1b420105841','和人遊嵩山十二題 中峰','范仲淹','宋','宋诗','song-poetry','','[]','嵩高最高處，逸客偶登臨。',36,'全唐诗/poet.song.8000.json','["嵩高最高處，逸客偶登臨。", "迴看日月影，正得天地心。", "念此非常遊，千載一披襟。"]'),
('60aba26a-fbe0-4d6f-87a5-c5d18677344c','聽真上人琴歌','范仲淹','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','銀潢耿耿霜稜稜，西軒月色寒如冰。',216,'全唐诗/poet.song.8000.json','["銀潢耿耿霜稜稜，西軒月色寒如冰。", "上人一叩朱絲繩，萬籟不起秋光凝。", "伏羲歸天忽千古，我聞遺音淚如雨。", "嗟嗟不及鄭衛兒，北里南鄰競歌舞。", "競歌舞，何時休，師襄堂上心悠悠。", "擊浮金，戞鳴玉，老龍秋啼蒼海底，幼猿暮嘯寒山曲。", "隴頭琴瑟咽流泉，洞庭蕭蕭落寒木。", "此聲感物何太靈，十二銜珠下仙鵠。", "爲予再奏南風詩，神人和暢舜無爲。", "爲余試彈廣陵散，鬼物悲哀晉方亂。", "乃知聖人情慮深，將治四海先治琴。", "興亡哀樂不我遁，坐中可見天下心。", "感公遺我正始音，何以報之千黄金。"]'),
('8d25a0c1-0f8b-412e-87ec-4d9d6cb7de6f','和僧長吉湖居五題 湖山','范仲淹','宋','宋诗','song-poetry','','[]','湖山滿清氣，賞心甲吳越。',36,'全唐诗/poet.song.8000.json','["湖山滿清氣，賞心甲吳越。", "晴嵐起片雲，晚水連初月。", "漁父得意歸，歌詩等閑發。"]'),
('a00560eb-86fb-4db0-8f89-f375b06dcac8','和僧長吉湖居五題 水月','范仲淹','宋','宋诗','song-poetry','','[]','千尋月脚寒，湖影浄於天。',36,'全唐诗/poet.song.8000.json','["千尋月脚寒，湖影浄於天。", "忽如嫦娥宫，俯仰見嬋娟。", "更約中秋夕，長津無寸烟。"]'),
('1463fd9b-037d-4d9d-a994-65f47c811245','和僧長吉湖居五題 筠亭','范仲淹','宋','宋诗','song-poetry','','[]','爲愛碧鮮亭，入夏敂敂至。',36,'全唐诗/poet.song.8000.json','["爲愛碧鮮亭，入夏敂敂至。", "臺榭競生煙，獨有清凉意。", "高岡鳯不來，幽人此沉醉。"]'),
('af5087f2-a24c-4130-b6d0-85d1cb17e20f','和僧長吉湖居五題 風笛','范仲淹','宋','宋诗','song-poetry','','[]','風引湖邊笛，焉知非隱淪。',36,'全唐诗/poet.song.8000.json','["風引湖邊笛，焉知非隱淪。", "一聲裂雲去，明月生精神。", "無爲落梅調，留寄隴頭人。"]'),
('47b1e7d4-144e-4269-8f7d-db7fbe1239e8','和僧長吉湖居五題 渚蓮','范仲淹','宋','宋诗','song-poetry','','[]','武陵誰家子，波面雙雙渡。',36,'全唐诗/poet.song.8000.json','["武陵誰家子，波面雙雙渡。", "空積心中絲，未成機上素。", "似共織女期，秋宵苦霜露。"]'),
('ccf3c73c-b2d1-4823-99e5-0870ac7381b9','酬葉道卿學士見寄','范仲淹','宋','宋诗','song-poetry','','[]','世傳學中祿，小子迺逢辰。',168,'全唐诗/poet.song.8000.json','["世傳學中祿，小子迺逢辰。", "一入諫諍司，鴻毛忽其身。", "可負萬乘主，甘爲三黜人。", "豈量堯舜心，如日照孤臣。", "薄責落善地，雅尚過朝倫。", "僅同龜在泥，敢冀蠖求伸。", "朱樓逼清江，下睨百丈鱗。", "羡此南魚樂，不忍持鈎綸。", "爲郡良優優，乏材止循循。", "恬愉弗擾外，何以慰遠民。", "拙可存吾樸，静可逸吾神。", "漸得疏懶味，下車將四旬。", "嘉興風雅來，觀對如天賓。", "感兹韶夏音，佐我臺上春。"]'),
('fb4a8071-ef0b-4712-90b5-8b1755de256b','和章岷從事鬭茶歌','范仲淹','宋','宋诗','song-poetry','','[]','年年春自東南來，建溪先暖冰微開。',331,'全唐诗/poet.song.8000.json','["年年春自東南來，建溪先暖冰微開。", "溪邊奇茗冠天下，武夷仙人從古栽。", "新雷昨夜發何處，家家嬉笑穿雲去。", "露牙錯落一番榮，綴玉含珠散嘉樹。", "終朝採掇未盈襜，唯求精粹不敢貪。", "研膏焙乳有雅製，方中圭兮圓中蟾。", "北苑將期獻天子，林下雄豪先鬭美。", "鼎磨雲外首山銅，瓶攜江上中泠水。", "黄金碾畔綠塵飛，紫玉甌心雪濤起。", "鬭余味兮輕醍醐，鬭余香兮薄蘭芷。", "其間品第胡能欺，十目視而十手指。", "勝若登仙不可攀，輸同降將無窮恥。", "于嗟天産石上英，論功不愧階前蓂。", "衆人之濁我可清，千日之醉我可醒。", "屈原試與招魂魄，劉伶却得聞雷霆。", "盧仝敢不歌，陸羽須作經。", "森然萬象中，焉知無茶星。", "商山丈人休茹芝，首陽先生休采薇。", "長安酒價減千萬，成都藥市無光輝。", "不如仙山一啜好，泠然便欲乘風飛。", "君莫羡花間女郎只鬭草，贏得珠璣滿斗歸。"]'),
('eb723f7d-79d4-4bd7-af6c-7815e7e08a83','和葛閎寺丞接花歌','范仲淹','宋','宋诗','song-poetry','','[]','江城有卒老且貧，憔悴抱關良苦辛。',384,'全唐诗/poet.song.8000.json','["江城有卒老且貧，憔悴抱關良苦辛。", "衆中忽聞語聲好，知是北來京洛人。", "我試問云何至是，欲語汍瀾墮雙淚。", "斯須收淚始能言，生自東都富貴地。", "家有城南錦繡園，少年止以花爲事。", "黄金用盡無他能，却作瓊林苑中吏。", "年年中使先春來，曉宣口勅脩花臺。", "奇芬異卉百餘品，求新換舊争栽培。", "猶恐君王厭顔色，羣芳只似尋常開。", "幸有神仙接花術，更向都城求絕匹。", "梁王苑裏索妍姿，石氏園中搜淑質。", "金刀玉尺裁量妙，香膏膩壤彌縫密。", "迴得東皇造化工，五色敷華異平日。", "一朝寵愛歸牡丹，千花相笑妖嬈難。", "竊藥嫦娥新換骨，嬋娟不似人間看。", "太平天子春遊好，金明柳色籠黄道。", "道南樓殿五雲高，鈞天捧上蓬萊島。", "四邊桃李不勝春，何况花王對玉宸。", "國色精明動韶景，天香旖旎飄芳塵。", "特奏霓裳羽衣曲，千官獻壽羅星辰。", "兌悅臨軒逾數刻，花吏此時方得色。", "白銀紅錦滿牙牀，拜賜仗前生羽翼。", "惟觀風景不憂身，一心歲歲供春職。", "中途得罪情多故，刻木在前何敢訴。"]'),
('738aad3b-9568-437c-904b-096531507b75','天平山白雲泉','范仲淹','宋','宋诗','song-poetry','','[]','靈泉在天半，狂波不能侵。',156,'全唐诗/poet.song.8000.json','["靈泉在天半，狂波不能侵。", "神蛟穴其中，渇虎不敢臨。", "隱照涵秋碧，泓然一勺深。", "游潤騰龍飛，散作三日霖。", "天造豈無意，神化安可尋。", "挹之如醍醐，盡得清涼心。", "聞之異絲竹，不含哀樂音。", "月好羣籟息，涓涓度前林。", "子晉罷雲笙，伯牙收玉琴。", "徘徊不擬去，復發滄浪吟。", "乃云堯湯歲，盈盈常若今。", "萬里江海源，千秋松桂陰。", "兹焉如有價，北斗量黄金。"]'),
('9cd214e9-8fc2-4de0-8e3b-ca9d45eeb1ba','留題常熟頂山僧居','范仲淹','宋','宋诗','song-poetry','','[]','平湖數百里，隱然一山起。',72,'全唐诗/poet.song.8000.json','["平湖數百里，隱然一山起。", "中有白龍泉，可洗人間耳。", "吾師仁智心，愛兹山水音。", "結茅三十年，不道日月深。", "笑我名未已，來問無端理。", "却指嶺邊雲，斯焉贈君子。"]'),
('1592ea3e-3bae-47d3-b2c4-18bde65ba1d3','江上漁者','范仲淹','宋','宋诗','song-poetry','','[]','江上往來人，但愛鱸魚美。',24,'全唐诗/poet.song.8000.json','["江上往來人，但愛鱸魚美。", "君看一葉舟，出沒風波裏。"]'),
('5ad0d0da-e985-4930-98fa-83582bab41ef','送蔡挺代父之蜀','范仲淹','宋','宋诗','song-poetry','','[]','朔風豈不寒，蜀道豈不難。',48,'全唐诗/poet.song.8000.json','["朔風豈不寒，蜀道豈不難。", "之子代親行，萬里心自安。", "劍閣雪猶明，錦江春未闌。", "到日必詩戰，重登李杜壇。"]'),
('80e4db14-bd72-41cf-b8c4-931a6d7134d0','鄱陽酬泉州曹使君見寄','范仲淹','宋','宋诗','song-poetry','','[]','吾生豈不幸，所稟多剛腸。',288,'全唐诗/poet.song.8000.json','["吾生豈不幸，所稟多剛腸。", "身甘一枝巢，心苦千仞翔。", "志意苟天命，富貴非我望。", "立譚萬乘前，肝竭喉無漿。", "意君成大舜，千古聞羶香。", "寸懷如春風，思與天下芳。", "片玉棄且在，雙足何辭傷。", "王章死於漢，韓愈逐諸唐。", "獄中與嶺外，妻子不得將。", "義士撫卷起，眦血一霑裳。", "胡弗學掲厲，胡弗隨低昂。", "干時宴安人，滅然已不揚。", "匹夫虎敢鬬，女子熊能當。", "况彼二長者，烏肯巧如簧。", "我愛古人節，皎皎明如霜。", "今日貶江徼，多慚韓與王。", "罪大禍不稱，所損傷纖茫。", "盡室來官下，君恩大難忘。", "酒聖無隱量，詩豪有餘章。", "秋來魏公亭，金菊何煌煌。", "登高發秘思，聊以攄吾狂。", "卓有梅聖俞，作邑郡之旁。", "矯首賦靈烏，擬彼歌滄浪。", "因成答客戲，移以贈名郎。"]'),
('73e7115f-567f-48cd-97e9-b01e241989e0','和謝希深學士見寄','范仲淹','宋','宋诗','song-poetry','','[]','天地久開泰，過言防結括。',72,'全唐诗/poet.song.8000.json','["天地久開泰，過言防結括。", "誰憐多出處，自省有本末。", "心焉介如石，可裂不可奪。", "盡室得江行，君恩與全活。", "迴頭諫諍路，尚願無壅遏。", "豈獨世所非，千載成迂闊。"]'),
('90332767-8ba4-4bd1-88da-3bfc01510bc6','廬山瀑布','范仲淹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','靈源何太高，北斗想可挹。',84,'全唐诗/poet.song.8000.json','["靈源何太高，北斗想可挹。", "凌日五光直，逗雲千仞急。", "白虹下澗飲，寒劍倚天立。", "闊電不得瞬，長雷無敢蟄。", "萬丈巖崖坼，一道林巒濕。", "險逼飛鳥墜，冷束山鬼泣。", "須當截海去，獨流不相入。"]'),
('12ecff7b-6ad6-4ea1-8deb-3f1c126f299d','滕子京魏介之二同年相訪丹陽郡','范仲淹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江天下險，涉者利名驅。',120,'全唐诗/poet.song.8000.json','["長江天下險，涉者利名驅。", "二公訪貧交，過之如坦途。", "風波豈不惡，忠信天所扶。", "相見乃大笑，命歌倒金壺。", "同年三百人，大半功名呼。", "沒者草自綠，存者顔無朱。", "功名若在天，何必心區區。", "莫競貴高路，休防讒疾夫。", "孔子作旅人，孟軻號迂儒。", "吾輩不飲酒，笑殺高陽徒。"]'),
('3ba9c339-20f8-4a9f-9e3f-fdd80020faa1','送劉牧推官之兖州','范仲淹','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','相國鎮東魯，開閤多英豪。',96,'全唐诗/poet.song.8000.json','["相國鎮東魯，開閤多英豪。", "羡子賦從軍，壯思如波濤。", "當有非常遇，所得連六鼇。", "故人孫復之，卧雲生二毛。", "或作梁甫吟，秋風共呼號。", "翩翩草檄外，可與相遊遨。", "益以夫子心，萬物都一毫。", "此行名與節，須似泰山高。"]'),
('08a1c10b-e49e-4da0-b4a7-3c245f3ab203','和楊畋孤琴詠','范仲淹','宋','宋诗','song-poetry','','[]','愛此千里器，如見古人面。',48,'全唐诗/poet.song.8000.json','["愛此千里器，如見古人面。", "欲彈換朱絲，明月當秋漢。", "我願宫商絃，相應聲無間。", "自然召南風，莫起孤琴歎。"]'),
('f0db52b5-3a91-4740-b54b-d0e33c4b615c','絳州園池','范仲淹','宋','宋诗','song-poetry','','[]','絳臺史君府，亭閣參園圃。',96,'全唐诗/poet.song.8000.json','["絳臺史君府，亭閣參園圃。", "一泉西北來，羣峰高下覩。", "池魚或躍金，水簾長布雨。", "怪柏鎖蛟虬，醜石鬭貙虎。", "羣花相倚笑，垂楊自由舞。", "静境合通仙，清陰不知暑。", "每與風月期，可無詩酒助。", "登臨問民俗，依舊陶唐古。"]'),
('069d4ede-3860-4f49-a361-30ddb412a718','晉祠泉','范仲淹','宋','宋诗','song-poetry','','[]','神哉叔虞廟，地勝出嘉泉。',96,'全唐诗/poet.song.8000.json','["神哉叔虞廟，地勝出嘉泉。", "一源甚澄静，數步忽潺湲。", "此異孰可窮，觀者增恭虔。", "錦鱗無敢釣，長生同水仙。", "千家溉禾稻，滿目江鄉田。", "我來動所思，致主愧前賢。", "大道果能行，時雨宜不愆。", "皆如晉祠下，生民無旱年。"]'),
('071a4edc-fabf-41fc-be03-1e16175d30bd','訪陜郊魏疏處士','范仲淹','宋','宋诗','song-poetry','','[]','賢哉先處士，天書召不起。',132,'全唐诗/poet.song.8000.json','["賢哉先處士，天書召不起。", "雲夫嗣孤風，復爲隱君子。", "有石礪其齒，有泉洗其耳。", "下瞰紅塵路，榮利無窮已。", "孜孜朝市人，同在風波裏。", "大爲高士笑，誓不拾青紫。", "我亦寵辱流，所幸無愠喜。", "進者道之行，退者道之止。", "矧今領方面，豈稱長城倚。", "來訪卧雲人，而請益諸已。", "得無長者言，佩之玉非美。"]'),
('860f687a-26d3-494c-9c11-f3fc22457ca3','中元夜百花洲作','范仲淹','宋','宋诗','song-poetry','','[]','南陽太守清狂發，未到中秋先賞月。',112,'全唐诗/poet.song.8000.json','["南陽太守清狂發，未到中秋先賞月。", "百花洲裏夜忘歸，綠梧無聲露光滑。", "天學碧海吐明珠，寒輝射空星斗疏。", "西樓下看人間世，瑩然都在青玉壺。", "從來酷暑不可避，今夕涼生豈天意。", "一笛吹銷萬里雲，主人高歌客大醉。", "客醉起舞逐我歌，弗舞弗歌如老何。"]'),
('b046a535-2b93-45a2-83a3-4aac75607615','覽秀亭詩','范仲淹','宋','宋诗','song-poetry','','[]','南陽有絕勝，城下百花洲。',240,'全唐诗/poet.song.8000.json','["南陽有絕勝，城下百花洲。", "謝公創危亭，屹在高城頭。", "盡覽洲中秀，歷歷銷人憂。", "作詩刻金石，意垂千載休。", "我來亭蚤壞，何以待英遊。", "試觀荆棘繁，欲步瓦礫稠。", "嗟嗟命良工，美材肆爾求。", "曰基復日搆，落成會中秋。", "開樽揖明月，席上皆應劉。", "敏速迭唱和，醺酣爭獻酬。", "老子素不淺，預兹年少儔。", "九日重登臨，涼空氛氣收。", "風來鴈聲度，雲去山色留。", "西郊有潭菊，滿以金船浮。", "雅爲君子壽，外物真悠悠。", "過則與春期，春時良更優。", "焰焰衆卉明，衮衮新泉流。", "簫鼓動地喧，羅綺傾城遊。", "五馬不行樂，州人爲之羞。", "亭焉詎可廢，願此多賢侯。"]'),
('280ff495-26eb-4cdb-9f61-a47a1d58c26c','祠風師酬提刑趙學士見貽','范仲淹','宋','宋诗','song-poetry','','[]','先王制禮經，祠爲國大事。',168,'全唐诗/poet.song.8000.json','["先王制禮經，祠爲國大事。", "孟春祭風師，刺史敢有二。", "齋戒升于壇，拜手首至地。", "所祈動以時，生物得咸遂。", "勿鼓江海濤，害我舟檝利。", "昊天六七月，會有雷雨至。", "慎無吹散去，坐使百穀悴。", "高秋三五夕，明月生天際。", "乃可驅雲烟，以喜萬人意。", "願君入薫絃，上副吾皇志。", "阜財復解愠，即爲天下賜。", "八使重古禮，作詩歌祭義。", "誠欲通神明，非徒奬州吏。", "賢哉推此心，良以警有位。"]'),
('a057d872-042c-4882-93d8-4bbe52e0bb06','依韻和安陸孫司諫見寄','范仲淹','宋','宋诗','song-poetry','','[]','穰下故都今善藩，沃衍千里多豐年。',160,'全唐诗/poet.song.8000.json','["穰下故都今善藩，沃衍千里多豐年。", "孫公頃以清浄化，我來代之慚二天。", "人物高傳卧龍里，神仙近接弄珠川。", "漢光舊烈山河在，徘徊弔古良依然。", "二十八將固不朽，風雲一代皆忠賢。", "我亦明時得君者，出處十載功不前。", "尚得州麾養衰疾，優游豈減居林泉。", "因逢故人作宴喜，琴樽風月夕不眠。", "之翰詩來若金石，重於我輩何其偏。", "相其直道了無悔，寧争蠖屈與鵬騫。"]'),
('84e9bdf6-8ef5-4d3c-8649-a85e7243fe56','送鄖鄉尉黄通','范仲淹','宋','宋诗','song-poetry','','[]','少年好逸驥，老者重安車。',72,'全唐诗/poet.song.8000.json','["少年好逸驥，老者重安車。", "争先尚逐逐，致遠貴徐徐。", "勿言一尉卑，千户繫慘舒。", "外矜固不足，內樂則有餘。", "子游與季路，作邑寧欷歔。", "五斗對萬鍾，所問道何如。"]'),
('5df6a298-4595-4d24-9a1c-3d54c2fca2f7','依韻和襄陽王源叔龍圖見寄','范仲淹','宋','宋诗','song-poetry','','[]','高車赴南峴，敝郊主東道。',144,'全唐诗/poet.song.8000.json','["高車赴南峴，敝郊主東道。", "風采喜一見，布素情相好。", "屈指四十秋，于今歲寒保。", "我起爲君壽，善頌復善禱。", "願盡杯中物，薄言理可到。", "君子貴有終，功名非必早。", "朝端卿大夫，所尚賢而老。", "世慮久乃周，聖門深已造。", "與君誓許國，無忝於祖考。", "潔如鳯食竹，樂若魚在藻。", "安得長相親，時時一絕倒。", "不忘平生期，明月滿懷抱。"]'),
('69eb1fdf-6c08-4dab-8e13-ca1069eb45fa','依韻答賈黯監丞賀雪','范仲淹','宋','宋诗','song-poetry','','[]','今之刺史古諸侯，孰敢不分天子憂。',192,'全唐诗/poet.song.8000.json','["今之刺史古諸侯，孰敢不分天子憂。", "自秋徂冬渇雨雪，旬奏空文慚轉郵。", "得非郡國政未洽，刺史閉閤當自尤。", "上賴天子仁且聖，神龍奔走不俟求。", "同雲千里結雪意，一夕密下誠如羞。", "曉來賞心江海上，東望不見三神丘。", "渾祛厲氣發和氣，明年黍稷須盈疇。", "烟郊空闊獵者健，酒市暖熱沽人稠。", "光精璨璨奪劍戟，清寒拂拂生衣裘。", "鈴齋賀客有喜色，飲酣歌作擊前籌。", "常願帝力及南畝，盡使風俗如東鄒。", "誰言吾子青春者，意在生民先發謳。"]'),
('d6f32a33-ba18-4618-baa8-1c3e0b7a6179','依韻答提刑張太博嘗新醖','范仲淹','宋','宋诗','song-poetry','','[]','南陽本佳處，偶得作守臣。',288,'全唐诗/poet.song.8000.json','["南陽本佳處，偶得作守臣。", "地與汝墳近，古來風化純。", "當官一無術，易易復循循。", "長使下情達，窮民奚不伸。", "此外更何事，優游欵嘉賓。", "時得一笑會，恨無千日醇。", "客有多聞者，密法爲我陳。", "自言此靈物，盡心妙始臻。", "非徒水泉潔，大要麴糵均。", "暄涼體四時，日月周數旬。", "其氣芳以烈，厥味和而辛。", "涓涓滴小槽，清光能照人。", "固可奉宗廟，宜能格天神。", "我姑酌金罍，駐此席上珍。", "况有百花洲，水木長時新。", "煙姿藏碧塢，柳杪見朱闉。", "兩兩鳬鴈侣，依依江海瀕。", "晚光倒晚影，一川無一塵。", "悠悠乘畫舸，坦坦解朝紳。", "綠陰承作蓋，芳草就爲茵。", "引此杯中物，獻酬交錯頻。", "禮俗重三爵，今乃不記巡。", "大言出物表，本性還天真。", "或落孟嘉帽，或抛陶令巾。"]'),
('84c6a867-927c-4613-99b5-7d5e0171ed75','寄題峴山羊公祠堂','范仲淹','宋','宋诗','song-poetry','','[]','休哉羊叔子，輔晉功勳大。',216,'全唐诗/poet.song.8000.json','["休哉羊叔子，輔晉功勳大。", "化行江漢間，恩被疆埸外。", "中國倚而安，治爲天下最。", "開府多英僚，置酒每高會。", "徘徊臨峴首，興言何慷慨。", "此山自古有，游者千萬輩。", "堙滅皆無聞，空悲歲月邁。", "公乎仁澤深，風采獨不昧。", "于今墮淚碑，觀之益欽戴。", "卓有王源叔，文學偉當代。", "借麾來襄陽，高懷極恬退。", "山姿列雲端，江響拂天籟。", "行樂何逍遙，覽古忽感概。", "不見叔子祠，蕪沒民疇內。", "千金贖故基，廟貌重營繪。", "襄人復其祀，水旱有攸賴。", "太守一興善，比戶皆歡快。", "源叔政可歌，又留千載愛。"]'),
('edf266e7-5691-4b4e-a42c-f3af1db9d166','送河東提刑張太博','范仲淹','宋','宋诗','song-poetry','','[]','憶守姑蘇日，見君已驚人。',288,'全唐诗/poet.song.8000.json','["憶守姑蘇日，見君已驚人。", "翩翩幕中畫，落落席上珍。", "强記及敏力，一一精如神。", "洎余領西帥，密與羌夏鄰。", "君來貳邊郡，表裏還相親。", "有如得四支，周旋衞其身。", "予始按萬渠，兵行百物陳。", "而君主其事，進退皆有倫。", "羌酋八九百，醉歌喜齗齗。", "傳告以號令，再拜罔不馴。", "作城大順川，扼胡來路津。", "漢軍始屯集，虜騎俄紛綸。", "諸將稍畏怯，偶語辭艱辛。", "君躍疋馬去，入險將死濱。", "持檛畫禍福，虎校靡不遵。", "呼兵就畚鍤，悦使咸忻忻。", "晝夜戰且役，城成未踰旬。", "虜乃急攻我，萬衆生煙塵。", "蒼惶被矢石，遁走無逡巡。", "君馳奏闕下，感慨動中宸。", "是秋懷敏敗，虜勢侵涇原。", "天地正愁慘，關輔將迸奔。", "腹心苟不守，皮膚安得存。", "予召蕃漢兵，趨邠當北門。"]'),
('00d72f2d-4d11-4423-8c60-ae643e8140a8','依韻和提刑太博嘉雪','范仲淹','宋','宋诗','song-poetry','','[]','南陽風俗常苦耕，太守憂民敢不誠。',320,'全唐诗/poet.song.8000.json','["南陽風俗常苦耕，太守憂民敢不誠。", "今秋與冬數月旱，二麥無望愁編氓。", "龍遁雲藏不肯起，荒祠巫鼓徒轟轟。", "昨宵天意驟回復，繁陰一布飄寒英。", "裁成片片盡六出，化工造物何其精。", "散亂狂飛若倚勢，徘徊緩舞如含情。", "千門競掃明月色，萬木都拆寒梅英。", "天上風流忽爾在，人間險阻無不平。", "因松偶作琴瑟調，過竹徐聞環珮聲。", "江天鳴鴈畏相失，龍庭奔馬豪如驚。", "丞相沙隄初踏練，將軍紫髯渾綴瓔。", "巖前饑殺嘯風虎，海上凍死吞舟鯨。", "我有高樓擘雲上，雙瞳一開千里明。", "羣閻逐去疫癘遠，長逵壓下塵埃清。", "當知有年可坐致，東臯父老休營營。", "因招大使賞天瑞，醉把羲黄向上評。", "窮通得喪了無事，莊老器宇何難并。", "君起作歌我作和，天地和氣須充盈。", "當年此樂不可得，與雪對舞攄平生。", "共君學取雪好處，平施萬物如權衡。"]'),
('dd5ea86a-9b4c-4eb8-9ac6-2d0cdd2b6db3','閲古堂詩','范仲淹','宋','宋诗','song-poetry','','[]','中山天下重，韓公兹鎮臨。',288,'全唐诗/poet.song.8000.json','["中山天下重，韓公兹鎮臨。", "堂上繢昔賢，閲古以儆今。", "牧師六十人，冠劍竦若林。", "既瞻古人像，必求古人心。", "彼或所存遠，我將所得深。", "仁與智可尚，忠與義可欽。", "吾愛古賢守，馨德神祗歆。", "典法曾弗泥，勸沮良自斟。", "躋民在春臺，熙熙樂不淫。", "耕夫與樵子，飽暖相謳吟。", "王道自此始，然後張薫琴。", "吾愛古名將，毅若武庫森。", "其重如山安，其静如淵沉。", "有令凛如霜，有謀密如陰。", "敵城一朝拔，戎首萬里擒。", "虎豹卷韜畧，鯨鯢投釡鬵。", "皇威徹西海，天馬來駸駸。", "留侯武侯者，將相俱能任。", "決勝神所啟，受託天所諶。", "披開日月光，振起雷霆音。", "九關支一柱，萬宇覆重衾。", "前人何赫赫，後人豈愔愔。", "所以作此堂，公意同堅金。", "僕思寶元初，叛羌弄千鐔。"]'),
('92eb804d-0c40-498e-8b49-2a26db252bfa','送謝景初廷評宰餘姚','范仲淹','宋','宋诗','song-poetry','','[]','世德踐甲科，青紫信可拾。',120,'全唐诗/poet.song.8000.json','["世德踐甲科，青紫信可拾。", "故鄉特榮輝，高門復樹立。", "餘姚二山下，東南最名邑。", "煙水萬人家，熙熙自翔集。", "又得賢大夫，坐堂恩信敷。", "春風爲君來，綠波滿平湖。", "乘興訪隱淪，今逢賀老無。", "文藻凌雲處，定喜江山助。", "未能同仙舟，離樽少留駐。", "行行道不孤，明月相隨去。"]'),
('123cb7a4-1a60-4a31-a781-28c901bc3c35','睢陽學舍書懷','范仲淹','宋','宋诗','song-poetry','','[]','白雲無賴帝鄉遙，漢苑誰人奏洞簫。',64,'全唐诗/poet.song.8000.json','["白雲無賴帝鄉遙，漢苑誰人奏洞簫。", "多難未應歌鳯鳥，薄才猶可賦鷦鷯。", "瓢思顔子心還樂，琴遇鍾君恨即銷。", "但使斯文天未喪，澗松何必怨山苗。"]'),
('010b9f9e-3167-4944-a460-e8ba9362398e','詠史五首 陶唐氏','范仲淹','宋','宋诗','song-poetry','','[]','純衣黄冕曆星辰，白馬彤車一百春。',32,'全唐诗/poet.song.8000.json','["純衣黄冕曆星辰，白馬彤車一百春。", "莫道茅茨無復見，古今時有致堯人。"]'),
('edca0f22-26bd-4a38-a3e7-2b727a5f8d64','詠史五首 有虞氏','范仲淹','宋','宋诗','song-poetry','','[]','成都成邑即天開，終踐堯基詠起哉。',32,'全唐诗/poet.song.8000.json','["成都成邑即天開，終踐堯基詠起哉。", "但得四門元凱至，九韶何必鳯皇來。"]'),
('63ade7a6-fc6d-421d-a419-53b618a11c0d','詠史五首 夏后氏','范仲淹','宋','宋诗','song-poetry','','[]','景命還將伯益傳，九川功大若爲遷。',32,'全唐诗/poet.song.8000.json','["景命還將伯益傳，九川功大若爲遷。", "謳歌終在吾君子，豈是當時不讓賢。"]'),
('dfce2261-843f-4c83-8e57-dde01a89959e','詠史五首 商人','范仲淹','宋','宋诗','song-poetry','','[]','履癸昆吾禍莫移，應天重造帝王基。',32,'全唐诗/poet.song.8000.json','["履癸昆吾禍莫移，應天重造帝王基。", "子孫何事爲炮烙，不念嘻吁祝網時。"]'),
('8f9a6d2d-5cc4-4656-8c9e-dee654ff3686','詠史五首 周人','范仲淹','宋','宋诗','song-poetry','','[]','斧鉞爲藩忍內侵，商人塗炭奈何深。',32,'全唐诗/poet.song.8000.json','["斧鉞爲藩忍內侵，商人塗炭奈何深。", "不煩魚火明天意，自有諸侯八百心。"]'),
('fd91c9b4-c167-4add-a6d2-c645f5b882cf','次韻和劉夔判官對雪','范仲淹','宋','宋诗','song-poetry','','[]','蔌蔌樓臺外，新輝溢四遐。',120,'全唐诗/poet.song.8000.json','["蔌蔌樓臺外，新輝溢四遐。", "雲中凋玉葉，星際落榆花。", "嶽色參差露，松聲彷彿加。", "風流裁賦苑，清苦讀書家。", "霜女慚輕格，蟾娥讓素華。", "孤鴻迷鳥道，萬馬憶龍沙。", "浄拂王恭氅，香滋陸羽茶。", "載歌勞郢謝，一奏待鍾牙。", "幾處和梅賞，何人爲鬢嗟。", "含毫看不足，詩社好生涯。"]'),
('05523995-1e2b-4d7c-9dd3-3bbf38d63524','河朔吟','范仲淹','宋','宋诗','song-poetry','','[]','太平燕趙許閑遊，三十從知壯士羞。',64,'全唐诗/poet.song.8000.json','["太平燕趙許閑遊，三十從知壯士羞。", "敢話詩書爲上將，猶憐仁義對諸侯。", "子房帷幄方無事，李牧耕桑合有秋。", "民得袴襦兵得帥，禦戎何必問嚴尤。"]'),
('f4d5c3b8-148f-4f43-813c-c918e0f09e36','和黄惣太博上知郡杜少卿','范仲淹','宋','宋诗','song-poetry','','[]','萬石君賢再出麾，猶龍川上五歌時。',64,'全唐诗/poet.song.8000.json','["萬石君賢再出麾，猶龍川上五歌時。", "九重執憲清規在，十鎮分憂白髪知。", "環禁申威星拱極，鈴齋舒嘯月侵帷。", "金臺下客思何報，願上中和樂職詩。"]'),
('45d8f909-450e-4c55-87cf-1cdf3a5abd50','過太清宫','范仲淹','宋','宋诗','song-poetry','','[]','醜石危松半綠蘿，函關真相玉嵯峨。',64,'全唐诗/poet.song.8000.json','["醜石危松半綠蘿，函關真相玉嵯峨。", "誰言仙道求難至，自愧陰功積未多。", "渺渺雲霞開絳節，雝雝鸞鳯答空歌。", "幾時身退瓊壇畔，榮利匆匆奈老何。"]'),
('e4cd6b85-e42b-4412-98e6-5cf27d813b9c','寄餘杭全安石段少連二從事','范仲淹','宋','宋诗','song-poetry','','[]','分攜俱是佐高牙，兩地光塵自等差。',64,'全唐诗/poet.song.8000.json','["分攜俱是佐高牙，兩地光塵自等差。", "榮事日趨丞相府，道情時過老君家。", "雙鴻得侣知風便，一鶴思鳴對露華。", "早晚相將雲漢外，重爲龍友免天涯。"]'),
('fa68b4a4-1e78-4c83-8ef4-95f31ff9b177','送江南運使張傳度支','范仲淹','宋','宋诗','song-poetry','','[]','刑措東南始詔迴，重分邦計命欽哉。',64,'全唐诗/poet.song.8000.json','["刑措東南始詔迴，重分邦計命欽哉。", "于公已積充閭慶，蕭相還施富國才。", "十郡甘棠歌未歇，一方流馬路初開。", "啓心知有嘉謨在，足亂雲霓憶帝臺。"]'),
('d47fd787-97a7-49f6-84fd-46eb3a8dac0c','堯廟','范仲淹','宋','宋诗','song-poetry','','[]','千古如天日，巍巍與善功。',48,'全唐诗/poet.song.8000.json','["千古如天日，巍巍與善功。", "禹終平洚水，舜亦致薫風。", "江海生靈外，乾坤揖讓中。", "鄉人不知此，簫鼓謝年豐。"]'),
('6cb39cbe-7d92-4656-9d30-047bfdb58831','西溪見牡丹','范仲淹','宋','宋诗','song-poetry','','[]','陽和不擇地，海角亦逢春。',24,'全唐诗/poet.song.8000.json','["陽和不擇地，海角亦逢春。", "憶得上林色，相看如故人。"]'),
('6d5381a1-4eb5-4cad-b7df-6b8ba136b405','寄秦州幕明化基寺丞','范仲淹','宋','宋诗','song-poetry','','[]','同時辟命新，中道改絲綸。',84,'全唐诗/poet.song.8000.json','["同時辟命新，中道改絲綸。", "滄海人歸楚，清風子在秦。", "共居卿月下，獨得將星鄰。", "聳動軍前檄，峥嶸席上珍。", "烽煙邊信息，金鼓武精神。", "獵度天山雪，歌逢隴樹春。", "燕臺無限好，西向自霑巾。"]'),
('a4971a71-1837-4c67-b260-5fcd89425b13','鵰鶚在秋天','范仲淹','宋','宋诗','song-poetry','','[]','秋漢寥寥迥，雄心肯木棲。',72,'全唐诗/poet.song.8000.json','["秋漢寥寥迥，雄心肯木棲。", "人間正揺落，天外絕攀躋。", "月兔精應喪，陽烏影欲齊。", "長河匹練小，太華一拳低。", "下眄羣毛遁，横過百鳥睽。", "乘風俊未巳，空闊玉關西。"]'),
('293a4ee8-1357-4024-abff-11ea26f2e074','觀獵','范仲淹','宋','宋诗','song-poetry','','[]','鷹犬一何驕，霜明遠近郊。',72,'全唐诗/poet.song.8000.json','["鷹犬一何驕，霜明遠近郊。", "鸞皇不觸網，狐兔自充庖。", "熠熠流鳴鏑，紛紛過綠髾。", "雄飛侵漢下，殺氣與雲交。", "翦棘争探穴，摧林競覆巢。", "惟開三面者，盛德播絃匏。"]'),
('a4068d09-43d1-411a-8b76-e50ccb1e75b7','鸚鵡','范仲淹','宋','宋诗','song-poetry','','[]','堂上每云云，金籠久受恩。',48,'全唐诗/poet.song.8000.json','["堂上每云云，金籠久受恩。", "思山誠有意，對主忍無言。", "性比孤鸞潔，聲殊百舌繁。", "雲林如一去，應喜謝朱門。"]'),
('c2f57807-c510-434a-8bfb-46c8c254cb29','歸鴈','范仲淹','宋','宋诗','song-poetry','','[]','稻粱留不得，一一起江天。',72,'全唐诗/poet.song.8000.json','["稻粱留不得，一一起江天。", "带雪南離楚，和春北入燕。", "依依前伴侣，歷歷舊山川。", "木葉程猶遠，梅花信可傳。", "子規啼到曉，鸚鵡鎖經年。", "應羡冥冥者，東風羽翼全。"]'),
('c5769f20-b24b-45f3-9de9-78d72862f0bf','青郊','范仲淹','宋','宋诗','song-poetry','','[]','青郊鳴錦雉，綠水漾金鱗。',24,'全唐诗/poet.song.8000.json','["青郊鳴錦雉，綠水漾金鱗。", "願得郢中客，共歌臺上春。"]'),
('65a2e323-b650-4169-bdd5-562c194d2c90','射陽湖','范仲淹','宋','宋诗','song-poetry','','[]','渺渺指平湖，煙波極望初。',24,'全唐诗/poet.song.8000.json','["渺渺指平湖，煙波極望初。", "縱横皆釣者，何處得嘉魚。"]'),
('3953f4cb-108f-4b1a-8538-95ec0199e57b','舟中','范仲淹','宋','宋诗','song-poetry','','[]','珠彩耀前川，歸來一扣舷。',24,'全唐诗/poet.song.8000.json','["珠彩耀前川，歸來一扣舷。", "微風不起浪，明月自隨船。"]'),
('a3e77cc4-360a-4cf6-8a20-4a0502cd3331','寄歐静秀才','范仲淹','宋','宋诗','song-poetry','','[]','君歸一水遙，魂斷木蘭橈。',24,'全唐诗/poet.song.8000.json','["君歸一水遙，魂斷木蘭橈。", "賴有南軒竹，清風慰寂寥。"]'),
('b5ef8417-b3ef-4661-9b23-eb2a37a0c5d8','和韓布殿丞三首 泛湖中','范仲淹','宋','宋诗','song-poetry','','[]','平湖萬頃碧，謝客一開顔。',24,'全唐诗/poet.song.8000.json','["平湖萬頃碧，謝客一開顔。", "待得臨清夜，徘徊載月還。"]'),
('5293970e-3611-4f5a-bf1f-b6b1b0f2e10a','和韓布殿丞三首 琴酒','范仲淹','宋','宋诗','song-poetry','','[]','絃上萬古意，樽中千日醇。',24,'全唐诗/poet.song.8000.json','["絃上萬古意，樽中千日醇。", "清心向流水，醉貌發陽春。"]'),
('b1d87d58-e5ac-48f8-b136-826ae2dee35c','和韓布殿丞三首 漁父','范仲淹','宋','宋诗','song-poetry','','[]','月色滿滄波，吾生樂事多。',24,'全唐诗/poet.song.8000.json','["月色滿滄波，吾生樂事多。", "何人獨醒者，試聽濯纓歌。"]'),
('56d10c7c-866b-4d04-aee0-d1d166b782a7','送識上人遊金山寺','范仲淹','宋','宋诗','song-poetry','','[]','空半簇樓臺，紅塵安在哉。',48,'全唐诗/poet.song.8000.json','["空半簇樓臺，紅塵安在哉。", "山分江色破，潮带海聲來。", "煙景諸鄰斷，天光四望開。", "疑師得仙去，白日上蓬萊。"]'),
('92fe2dbb-0f77-4e45-a9e3-f06abe0e385f','野色','范仲淹','宋','宋诗','song-poetry','','[]','非煙亦非霧，羃羃映樓臺。',48,'全唐诗/poet.song.8000.json','["非煙亦非霧，羃羃映樓臺。", "白鳥忽點破，夕陽還照開。", "肯隨芳草歇，疑逐遠帆來。", "誰謂山公意，登高醉始迴。"]'),
('c29de2fb-626a-4bc9-8b3f-51f92905edb8','雜詠四首  其一','范仲淹','宋','宋诗','song-poetry','','[]','梓人一笑白雲鄉，杞桂森森遇豫章。',32,'全唐诗/poet.song.8000.json','["梓人一笑白雲鄉，杞桂森森遇豫章。", "聞道周公繩墨在，天庭誰此遇明堂。"]'),
('fc33674a-e9d3-4c2c-80b8-15dc3b222f2d','雜詠四首  其二','范仲淹','宋','宋诗','song-poetry','','[]','有客藍田得意歸，溪光冉冉白虹蜺。',32,'全唐诗/poet.song.8000.json','["有客藍田得意歸，溪光冉冉白虹蜺。", "玉人豈忍言環珮，留取天王尺二圭。"]'),
('87d06058-bede-4962-9b42-cd367443f783','雜詠四首  其三','范仲淹','宋','宋诗','song-poetry','','[]','鏗鏗千古嶧山桐，金石聲來造化中。',32,'全唐诗/poet.song.8000.json','["鏗鏗千古嶧山桐，金石聲來造化中。", "誰道元和無復致，爲君堂上起薫風。"]'),
('329f4b84-c025-4b5f-9eb0-b71f079a888d','雜詠四首  其四','范仲淹','宋','宋诗','song-poetry','','[]','嶺上英英向日開，帝鄉情態自徘徊。',32,'全唐诗/poet.song.8000.json','["嶺上英英向日開，帝鄉情態自徘徊。", "如何一施陽春雨，依舊無心歸去來。"]'),
('1c4f1938-5768-4d85-8973-50824083a357','書事呈韓布殿丞','范仲淹','宋','宋诗','song-poetry','','[]','南宫曾薦牧之文，失足徒勞忽十春。',64,'全唐诗/poet.song.8000.json','["南宫曾薦牧之文，失足徒勞忽十春。", "天上雲龍期際會，山中猿鶴愧因循。", "無功豈不孤黄石，有道何堪憶紫蓴。", "少壯由來須努力，篆銘鐘鼎古何人。"]'),
('b883a929-8a8d-459b-ae66-b9c26b71217a','西溪書事','范仲淹','宋','宋诗','song-poetry','','[]','卑棲曾未託椅梧，敢議雄心萬里途。',64,'全唐诗/poet.song.8000.json','["卑棲曾未託椅梧，敢議雄心萬里途。", "蒙叟自當齊黒白，子牟何必怨江湖。", "秋天響亮頻聞鶴，夜海朣朧每見珠。", "一醉一吟疏嬾甚，溪人能信解嘲無。"]'),
('1f381136-e8b6-4d21-b2f7-4dffb8451985','得李四宗易書','范仲淹','宋','宋诗','song-poetry','','[]','秋風海上憶神交，江外書來慰寂寥。',64,'全唐诗/poet.song.8000.json','["秋風海上憶神交，江外書來慰寂寥。", "松柏舊心當化石，塤篪新韻似聞韶。", "須期管鮑垂千古，不學張陳負一朝。", "三復荆州無限意，王孫芳草路遙遙。"]'),
('6d5bed0d-eb66-4d27-9896-d604c8efb422','歐伯起相訪','范仲淹','宋','宋诗','song-poetry','','[]','海涯牢落若爲懷，惟子相過未忍迴。',64,'全唐诗/poet.song.8000.json','["海涯牢落若爲懷，惟子相過未忍迴。", "勁草不隨風偃去，孤桐何意鳯飛來。", "罇藏金醴遲遲進，匣鎖雲和特特開。", "萬古功名有天命，浩然攜手上春臺。"]'),
('d4d59975-17de-475b-968a-2891ee13bf5d','寄贈林逋處士','范仲淹','宋','宋诗','song-poetry','','[]','唐虞重逸人，束帛降何頻。',168,'全唐诗/poet.song.8000.json','["唐虞重逸人，束帛降何頻。", "風俗因君厚，文章至老淳。", "玉田耕小隱，金闕夢高真。", "罷釣輪生蠧，慵冠鑑積塵。", "餌蓮攀鶴頂，歌雪扣琴身。", "墨妙青囊秘，丹靈綠髪新。", "嶺霞明四望，巖笋入諸鄰。", "幾姓簪裾盛，諸生禮樂循。", "朝廷唯薦鶚，鄉黨不傷麟。", "弔古夫差國，懷賢伍相津。", "劇談來劍俠，騰嘯駭山神。", "有客瞻冥翼，無端預薦紳。", "未能忘帝力，猶待補天均。", "早晚功名外，孤雲可得親。"]'),
('1df49abe-7025-4468-bf23-333474f6ef09','酬滕子京同年','范仲淹','宋','宋诗','song-poetry','','[]','謝家風雅若爲酬，散吏方耽海上游。',64,'全唐诗/poet.song.8000.json','["謝家風雅若爲酬，散吏方耽海上游。", "疏嬾幾忘傳筆夢，寂寥仍有負薪憂。", "欲歌蘭雪歸真隱，敢向簪軒競急流。", "如共茂先瞻氣象，莫言神物在南州。"]'),
('b658aee0-6aba-4b8f-8e32-04c2a7bb8879','贈餘杭唐異處士','范仲淹','宋','宋诗','song-poetry','','[]','名動公卿四十秋，相逢仍作旅人遊。',64,'全唐诗/poet.song.8000.json','["名動公卿四十秋，相逢仍作旅人遊。", "青山欲買難開口，白髪思歸易滿頭。", "厭入市廛如海燕，可堪雲水屬江鷗。", "故鄉知己方都督，千樹春濃種橘休。"]'),
('3263472a-841c-4293-9bc3-6baf8244dae7','和沈書記同訪林處士','范仲淹','宋','宋诗','song-poetry','','[]','山中宰相下巖扃，静接遊人笑傲行。',64,'全唐诗/poet.song.8000.json','["山中宰相下巖扃，静接遊人笑傲行。", "碧嶂淺深驕晚翠，白雲舒卷看春晴。", "煙潭共愛魚方樂，樵爨誰欺鴈不鳴。", "莫道隱君同德少，樽前長揖聖賢清。"]'),
('794a1a95-54d5-42e1-8fff-67a7a3e3149b','諸暨道中作','范仲淹','宋','宋诗','song-poetry','','[]','林下提壺招客醉，溪邊杜宇勸人歸。',32,'全唐诗/poet.song.8000.json','["林下提壺招客醉，溪邊杜宇勸人歸。", "可憐白酒青山在，不醉不歸多少非。"]'),
('8dfdb2d9-7a45-4f1d-bdc3-cf7b8e5216ff','題翠峰院','范仲淹','宋','宋诗','song-poetry','','[]','翠峰高與白雲閑，吾祖曾居水石間。',32,'全唐诗/poet.song.8000.json','["翠峰高與白雲閑，吾祖曾居水石間。", "千載家風應未墜，子孫還解愛青山。"]'),
('ff2c65b9-030e-4f15-a8ad-7e2172f45ec0','與人約訪林處士阻雨因寄','范仲淹','宋','宋诗','song-poetry','','[]','閑約諸公扣隱扃，江天風雨忽飄零。',64,'全唐诗/poet.song.8000.json','["閑約諸公扣隱扃，江天風雨忽飄零。", "方憐春滿王孫草，可忍雲遮處士星。", "蕙帳未容登末席，蘭舟無賴寄前汀。", "湖山早晚逢晴霽，重待尋仙入翠屏。"]'),
('edc8ee74-f9f6-4cc3-8505-a054f1be1418','寄西湖林處士','范仲淹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蕭索遶家雲，清歌獨隱淪。',48,'全唐诗/poet.song.8000.json','["蕭索遶家雲，清歌獨隱淪。", "巢由不願仕，堯舜豈遺人。", "一水無涯静，羣峰滿眼春。", "何當伴閑逸，嘗酒過諸鄰。"]'),
('168864f2-6afc-46a3-8467-226718dbbe34','越上聞子規','范仲淹','宋','宋诗','song-poetry','','[]','夜入翠煙啼，晝尋芳樹飛。',24,'全唐诗/poet.song.8000.json','["夜入翠煙啼，晝尋芳樹飛。", "春山無限好，猶道不如歸。"]'),
('ad4a68c5-d9b0-49b4-8447-655b593debd1','送李紘殿院赴闕  其一','范仲淹','宋','宋诗','song-poetry','','[]','寂寥門巷每相過，親近賢人所得多。',32,'全唐诗/poet.song.8000.json','["寂寥門巷每相過，親近賢人所得多。", "今日九重天上去，濉陽孤客奈愁何。"]'),
('f9239f39-3d96-4e1f-bc3b-88252a9344b1','送李紘殿院赴闕  其二','范仲淹','宋','宋诗','song-poetry','','[]','霜露丘園不忍違，三年月日速如飛。',32,'全唐诗/poet.song.8000.json','["霜露丘園不忍違，三年月日速如飛。", "金門乍入應垂淚，因挂朝衣憶彩衣。"]'),
('76cf666c-a4f0-410e-8309-be673b032b63','送邢昂處士南遊','范仲淹','宋','宋诗','song-poetry','','[]','落落崆峒一大儒，四方心逸憶江湖。',32,'全唐诗/poet.song.8000.json','["落落崆峒一大儒，四方心逸憶江湖。", "東南賴有林君復，萬里清風去不孤。"]'),
('057e3557-ac90-44ee-8896-0e209204795e','送丁司理赴明州','范仲淹','宋','宋诗','song-poetry','','[]','仙家枝葉令威孫，南去司刑庇越民。',32,'全唐诗/poet.song.8000.json','["仙家枝葉令威孫，南去司刑庇越民。", "金闕道書微旨在，獄多陰德是真人。"]'),
('968e0ccb-b41d-4da3-ae22-b021cf8af304','送鄞江竇尉','范仲淹','宋','宋诗','song-poetry','','[]','片帆飛去若輕鴻，一霎春潮過浙東。',32,'全唐诗/poet.song.8000.json','["片帆飛去若輕鴻，一霎春潮過浙東。", "王謝江山久蕭索，子真今爲起清風。"]'),
('dfa0be7d-070f-4210-8f9e-35e4030d73b7','送常熟錢尉','范仲淹','宋','宋诗','song-poetry','','[]','姑蘇臺下水如藍，天賜仙鄉奉旨甘。',32,'全唐诗/poet.song.8000.json','["姑蘇臺下水如藍，天賜仙鄉奉旨甘。", "梅淡柳黄春不淺，王孫歸思滿江南。"]'),
('11a8f869-f1f9-4428-99cc-aca01bbe9410','試筆','范仲淹','宋','宋诗','song-poetry','','[]','偶緣疏拙得天真，豈問前途屈與伸。',64,'全唐诗/poet.song.8000.json','["偶緣疏拙得天真，豈問前途屈與伸。", "車馬縱能欺倦客，江山猶可助騷人。", "懶如叔夜書盈几，狂似淵明酒滿巾。", "况有南窗姬易在，此心那更起纖塵。"]'),
('bf852fff-85af-4e7f-b742-29e4ab47ed2e','送真元二上人歸吳中','范仲淹','宋','宋诗','song-poetry','','[]','歸心不可奪，千里故園春。',48,'全唐诗/poet.song.8000.json','["歸心不可奪，千里故園春。", "及見市朝事，却思江海人。", "煙波方得伴，松月定爲鄰。", "願結虎溪社，休休老此身。"]'),
('d2a3cd8d-e79f-478d-add0-263bce5c4b16','寄題許州錢相公信美亭','范仲淹','宋','宋诗','song-poetry','','[]','華搆高軒敞，名湖一面分。',96,'全唐诗/poet.song.8000.json','["華搆高軒敞，名湖一面分。", "星辰居上相，鼓吹燕中軍。", "山色來嵩室，風光徹汝墳。", "杉篁涵晚翠，蘭茝薦時薫。", "坐嘯頻乘月，歸懷幾望雲。", "迥臨黄霸俗，遠味仲宣文。", "萬户方開國，三階復致君。", "斯亭比棠樹，千載頌清芬。"]'),
('86f64d71-6202-42b7-8a67-c3a02e5fee8c','送何白節推宰晉原二首  其一','范仲淹','宋','宋诗','song-poetry','','[]','盛府兼名邑，榮歸指故林。',48,'全唐诗/poet.song.8000.json','["盛府兼名邑，榮歸指故林。", "多年望鄉淚，萬里倚門心。", "江館春寒薄，山程晚翠深。", "板輿迎侍日，桃李正芳陰。"]'),
('4be9feb5-cb13-4e0b-89c2-35703ccd6e9e','送何白節推宰晉原二首  其二','范仲淹','宋','宋诗','song-poetry','','[]','此行深惜别，所喜是寧親。',48,'全唐诗/poet.song.8000.json','["此行深惜别，所喜是寧親。", "祖帳千門曉，鄉關錦國春。", "鳥歌疑勸酒，山態似迎人。", "我絕南陔望，因兄淚滿巾。"]'),
('57d03f07-b7b4-4acd-8b56-5835fa6594b5','送刁紡户掾太常下第','范仲淹','宋','宋诗','song-poetry','','[]','精鑒本非深，英僚暫此沉。',48,'全唐诗/poet.song.8000.json','["精鑒本非深，英僚暫此沉。", "火炎方試玉，沙密偶遺金。", "豈累青雲器，猶孤白雪音。", "敢希蘇季子，潛有激儀心。"]'),
('b857ebb5-886f-42ac-a2ac-9136040e7cf0','憶杭州西湖','范仲淹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','長憶西湖勝鑑湖，春波千頃綠如鋪。',32,'全唐诗/poet.song.8000.json','["長憶西湖勝鑑湖，春波千頃綠如鋪。", "吾皇不讓明皇美，可賜疏狂賀老無。"]'),
('68dec203-d5a5-4f88-a05c-3d4fc298d3ca','寄林處士','范仲淹','宋','宋诗','song-poetry','','[]','片心高與月徘徊，豈爲千鍾下釣臺。',32,'全唐诗/poet.song.8000.json','["片心高與月徘徊，豈爲千鍾下釣臺。", "猶笑白雲多事在，等閑爲雨出山來。"]'),
('cffa775f-476e-4948-b8ed-82d33e2dbb66','依韻酬毋湜推官','范仲淹','宋','宋诗','song-poetry','','[]','聖門非入室，文陣敢争盟。',192,'全唐诗/poet.song.8000.json','["聖門非入室，文陣敢争盟。", "不意棲雲閣，何才隷月卿。", "珍羣憐未至，霄鶚引脩程。", "直舍有仙味，祕庭無俗聲。", "午陰宫樹綠，宵刻禁鐘清。", "奉制歌三秀，稱觴聽六英。", "恩輝孤易感，交結淡難成。", "新髪鑑中改，舊山天際横。", "纓思漁父濯，春伴隼旟行。", "桃浪觀秦塞，薫風省舜城。", "幾多興廢跡，重疊古今情。", "進退思先覺，蹉跎畏後生。", "見詒如美衮，欲報乏英瓊。", "浄揖澄江練，高窺擢露莖。", "復驚聞正始，終仰輔登閎。", "好勵圖南志，翺翔覽四瀛。"]'),
('08f08ae3-05e3-4804-b88d-0f3aa526e305','送石曼卿','范仲淹','宋','宋诗','song-poetry','','[]','河光嶽色過秦關，英氣飄飄酒滿顔。',64,'全唐诗/poet.song.8000.json','["河光嶽色過秦關，英氣飄飄酒滿顔。", "賈誼書成動西漢，謝安人笑起東山。", "亨途去覺雲天近，舊隱回思水石閑。", "此道聖朝如不墜，疏封宜在立譚間。"]'),
('337d35ed-5166-424d-9603-1218694a85c5','送何涉秀才','范仲淹','宋','宋诗','song-poetry','','[]','蜀道歸來萬里身，上堂嘉慶動諸鄰。',32,'全唐诗/poet.song.8000.json','["蜀道歸來萬里身，上堂嘉慶動諸鄰。", "賢良詔下先生起，休向成都問卜人。"]'),
('dfeeee1d-9e9d-42fb-b909-85a30ff456d9','八月十四夜月','范仲淹','宋','宋诗','song-poetry','','[]','光華豈不盛，賞宴尚遲遲。',48,'全唐诗/poet.song.8000.json','["光華豈不盛，賞宴尚遲遲。", "天意將圓夜，人心待滿時。", "已知千里共，猶訝一分虧。", "來夕如澄霽，清風不負期。"]'),
('0c5641aa-5109-4d31-a819-5144210e176f','送吳安道學士知崇州','范仲淹','宋','宋诗','song-poetry','','[]','一麾輕去奉蘭羞，共惜清賢豈易求。',64,'全唐诗/poet.song.8000.json','["一麾輕去奉蘭羞，共惜清賢豈易求。", "筮易暗驚鳴鶴遠，賦詩深望白駒留。", "古來經緯心皆曉，閑處光陰髪半秋。", "長孺之才同吏隱，相寛頻上海邊樓。"]'),
('cf109579-5128-4f3a-bfd9-226bcfa7528c','謫守睦州作','范仲淹','宋','宋诗','song-poetry','','[]','重父必重母，正邦必正家。',48,'全唐诗/poet.song.8000.json','["重父必重母，正邦必正家。", "一心回主意，十口向天涯。", "銅虎恩猶厚，鱸魚味復佳。", "聖明何以報，沒齒願無邪。"]'),
('972a3a7a-fa48-472e-8e54-d1ba85c359c0','赴桐廬郡淮上遇風三首  其一','范仲淹','宋','宋诗','song-poetry','','[]','聖宋非强楚，清淮異汨羅。',48,'全唐诗/poet.song.8000.json','["聖宋非强楚，清淮異汨羅。", "平生仗忠信，盡室任風波。", "舟楫顛危甚，蛟黿出沒多。", "斜陽幸無事，沽酒聽漁歌。"]'),
('d568c824-6817-4226-a908-d04825551362','赴桐廬郡淮上遇風三首  其二','范仲淹','宋','宋诗','song-poetry','','[]','妻子休相咎，勞生險自多。',24,'全唐诗/poet.song.8000.json','["妻子休相咎，勞生險自多。", "商人豈有罪，同我在風波。"]'),
('cba56818-8294-41ca-9a9f-aee740ea4fdd','赴桐廬郡淮上遇風三首  其三','范仲淹','宋','宋诗','song-poetry','','[]','一棹危於葉，傍觀亦損神。',24,'全唐诗/poet.song.8000.json','["一棹危於葉，傍觀亦損神。", "他時在平地，無忽險中人。"]'),
('5696f3ac-c4c8-4a78-a1e8-7a7d86466eb6','送韓瀆殿院出守岳陽','范仲淹','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','仕宦自飄然，君恩豈欲偏。',48,'全唐诗/poet.song.8000.json','["仕宦自飄然，君恩豈欲偏。", "纔歸劍門道，忽上洞庭船。", "墜絮傷春目，舂濤廢夜眠。", "岳陽樓上月，清賞浩無邊。"]'),
('3699e19f-4bba-4f0f-b264-cea9111551ee','出守桐廬道中十絕  其一','范仲淹','宋','宋诗','song-poetry','','[]','隴上带經人，金門齒諫臣。',24,'全唐诗/poet.song.8000.json','["隴上带經人，金門齒諫臣。", "雷霆日有犯，始可報君親。"]'),
('4dc01459-c220-4286-b487-dbd99dc2138d','出守桐廬道中十絕  其二','范仲淹','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君恩泰山重，爾命鴻毛輕。',24,'全唐诗/poet.song.8000.json','["君恩泰山重，爾命鴻毛輕。", "一意懼千古，敢懷妻子榮。"]'),
('6a7d0a76-4606-4cd2-842c-f4b707d11c39','出守桐廬道中十絕  其三','范仲淹','宋','宋诗','song-poetry','','[]','妻子屢牽衣，出門投禍機。',24,'全唐诗/poet.song.8000.json','["妻子屢牽衣，出門投禍機。", "寧知白日照，猶得虎符歸。"]'),
('46e3672b-3f03-48ae-b644-3fd0b2c9eb78','出守桐廬道中十絕  其四','范仲淹','宋','宋诗','song-poetry','','[]','分符江外去，人笑似騷人。',24,'全唐诗/poet.song.8000.json','["分符江外去，人笑似騷人。", "不道鱸魚美，還堪養病身。"]'),
('8c3adfa7-74e5-4f3d-84e3-d90e2ee2914a','出守桐廬道中十絕  其五','范仲淹','宋','宋诗','song-poetry','','[]','有病甘長廢，無機苦直言。',24,'全唐诗/poet.song.8000.json','["有病甘長廢，無機苦直言。", "江山藏拙好，何敢望天閽。"]'),
('0c52189b-8b0b-455a-888b-a2cd4075361b','出守桐廬道中十絕  其六','范仲淹','宋','宋诗','song-poetry','','[]','天閽變化地，所好必真龍。',24,'全唐诗/poet.song.8000.json','["天閽變化地，所好必真龍。", "軻意正迂闊，悠然輕萬鍾。"]'),
('e0d85d6a-06da-48b6-8f5e-6dc8748da84a','出守桐廬道中十絕  其七','范仲淹','宋','宋诗','song-poetry','','[]','萬鍾誰不慕，意氣滿堂金。',24,'全唐诗/poet.song.8000.json','["萬鍾誰不慕，意氣滿堂金。", "必若枉此道，傷哉非素心。"]'),
('af14a348-ff05-4571-adcb-936fb583c68d','出守桐廬道中十絕  其八','范仲淹','宋','宋诗','song-poetry','','[]','素心愛雲水，此日東南行。',24,'全唐诗/poet.song.8000.json','["素心愛雲水，此日東南行。", "笑解塵纓處，滄浪無限清。"]'),
('ddaa0426-27cb-46f8-87cf-25390fe77a33','出守桐廬道中十絕  其九','范仲淹','宋','宋诗','song-poetry','','[]','滄浪清可愛，白鳥鑑中飛。',24,'全唐诗/poet.song.8000.json','["滄浪清可愛，白鳥鑑中飛。", "不信有京洛，風塵化客衣。"]'),
('0e033fef-45b4-4911-bd4f-6c7601ec251b','出守桐廬道中十絕  其一○','范仲淹','宋','宋诗','song-poetry','','[]','風塵日已遠，郡枕子陵溪。',24,'全唐诗/poet.song.8000.json','["風塵日已遠，郡枕子陵溪。", "始見神龜樂，優優尾在泥。"]'),
('d124172b-66e2-4beb-b4a4-27708957690d','蕭灑桐廬郡十絕  其一','范仲淹','宋','宋诗','song-poetry','','[]','蕭灑桐廬郡，烏龍山靄中。',24,'全唐诗/poet.song.8000.json','["蕭灑桐廬郡，烏龍山靄中。", "使君無一事，心共白雲空。"]'),
('37f12586-16e2-4423-a355-7d7743b39763','蕭灑桐廬郡十絕  其二','范仲淹','宋','宋诗','song-poetry','','[]','蕭灑桐廬郡，開軒即解顔。',24,'全唐诗/poet.song.8000.json','["蕭灑桐廬郡，開軒即解顔。", "勞生一何幸，日日面青山。"]'),
('dca82c7b-9650-47c2-a027-c3041c7094f3','蕭灑桐廬郡十絕  其三','范仲淹','宋','宋诗','song-poetry','','[]','蕭灑桐廬郡，全家長道情。',24,'全唐诗/poet.song.8000.json','["蕭灑桐廬郡，全家長道情。", "不聞歌舞事，遶舍石泉聲。"]'),
('e943a616-eed3-410c-81e3-59ca47005765','蕭灑桐廬郡十絕  其四','范仲淹','宋','宋诗','song-poetry','','[]','蕭灑桐廬郡，公餘午睡濃。',24,'全唐诗/poet.song.8000.json','["蕭灑桐廬郡，公餘午睡濃。", "人生安樂處，誰復問千鍾。"]'),
('2515137d-374a-48cb-b4d0-625524200fb3','蕭灑桐廬郡十絕  其五','范仲淹','宋','宋诗','song-poetry','','[]','蕭灑桐廬郡，家家竹隱泉。',24,'全唐诗/poet.song.8000.json','["蕭灑桐廬郡，家家竹隱泉。", "令人思杜牧，無處不潺湲。"]'),
('f5a7279a-d8a0-442c-a797-441fa93a114b','蕭灑桐廬郡十絕  其六','范仲淹','宋','宋诗','song-poetry','','[]','蕭灑桐廬郡，春山半是茶。',24,'全唐诗/poet.song.8000.json','["蕭灑桐廬郡，春山半是茶。", "新雷還好事，驚起雨前芽。"]'),
('d14c2ee4-ce85-413e-8414-d08c6438fd6f','蕭灑桐廬郡十絕  其七','范仲淹','宋','宋诗','song-poetry','','[]','蕭灑桐廬郡，千家起畫樓。',24,'全唐诗/poet.song.8000.json','["蕭灑桐廬郡，千家起畫樓。", "相呼採蓮去，笑上木蘭舟。"]'),
('e72e2b68-fc4b-4df9-9f9d-b3dd42d6d14c','蕭灑桐廬郡十絕  其八','范仲淹','宋','宋诗','song-poetry','','[]','蕭灑桐廬郡，清潭百丈餘。',24,'全唐诗/poet.song.8000.json','["蕭灑桐廬郡，清潭百丈餘。", "釣翁應有道，所得是嘉魚。"]'),
('e894f30d-cc8f-4b18-989c-761fc5075535','蕭灑桐廬郡十絕  其九','范仲淹','宋','宋诗','song-poetry','','[]','蕭灑桐廬郡，身閑性亦靈。',24,'全唐诗/poet.song.8000.json','["蕭灑桐廬郡，身閑性亦靈。", "降真香一炷，欲老悟黄庭。"]'),
('210aae9b-8d85-4726-a1cf-fd30da6be0b4','蕭灑桐廬郡十絕  其一○','范仲淹','宋','宋诗','song-poetry','','[]','蕭灑桐廬郡，嚴陵舊釣臺。',24,'全唐诗/poet.song.8000.json','["蕭灑桐廬郡，嚴陵舊釣臺。", "江山如不勝，光武肯教來。"]'),
('01d75b79-8f97-47a4-995c-5c1fef9c6c92','新定感興五首  其一','范仲淹','宋','宋诗','song-poetry','','[]','數仞黄堂上，題名僅百賢。',24,'全唐诗/poet.song.8000.json','["數仞黄堂上，題名僅百賢。", "孤高宋開府，千載可拳拳。"]'),
('86b3c26b-cc6e-4d0c-8585-62e9988d6aeb','新定感興五首  其二','范仲淹','宋','宋诗','song-poetry','','[]','山水真名郡，恩多補諫官。',24,'全唐诗/poet.song.8000.json','["山水真名郡，恩多補諫官。", "中間好田錫，風月亦盤桓。"]'),
('270136cf-ef06-4b62-b5d3-d5e42fd9f2c1','新定感興五首  其三','范仲淹','宋','宋诗','song-poetry','','[]','風物皆堪喜，民靈獨可哀。',24,'全唐诗/poet.song.8000.json','["風物皆堪喜，民靈獨可哀。", "稀逢賢太守，多是謫官來。"]'),
('4b02860b-1fc6-4ce7-b8c9-f0d0389f11ec','新定感興五首  其四','范仲淹','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','去國三千里，風波豈不賒。',24,'全唐诗/poet.song.8000.json','["去國三千里，風波豈不賒。", "迴思洞庭險，無限勝長沙。"]'),
('6223eb4a-6085-4233-98ea-111594bf25ff','新定感興五首  其五','范仲淹','宋','宋诗','song-poetry','','[]','江上多嘉客，清歌進白醪。',24,'全唐诗/poet.song.8000.json','["江上多嘉客，清歌進白醪。", "靈均良可笑，終日著離騷。"]'),
('100d30dc-6d66-4322-9939-b30424ecfef1','遊烏龍山寺','范仲淹','宋','宋诗','song-poetry','','[]','高嵐指天近，遠溜出山遲。',48,'全唐诗/poet.song.8000.json','["高嵐指天近，遠溜出山遲。", "萬事不到處，白雲無盡時。", "異花啼鳥樂，靈草隱人知。", "信是棲真地，林僧半雪眉。"]'),
('8cb96cd4-9d2e-4432-b297-dcb360247f85','江干閑望','范仲淹','宋','宋诗','song-poetry','','[]','江干日清曠，寓目一搘笻。',48,'全唐诗/poet.song.8000.json','["江干日清曠，寓目一搘笻。", "落葉信流水，歸雲識舊峰。", "蘭蓀誰共采，鳬鴈自相從。", "莫愛蘋風起，波來千萬重。"]'),
('26d0e45c-cf95-4146-886d-d884c3fb78d9','和章岷推官同登承天寺竹閣','范仲淹','宋','宋诗','song-poetry','','[]','僧閣倚寒竹，幽襟聊一開。',48,'全唐诗/poet.song.8000.json','["僧閣倚寒竹，幽襟聊一開。", "清風曾未足，明月可重來。", "晚意煙垂草，秋姿露滴苔。", "佳賓何以佇，雲瑟與霞杯。"]'),
('b7394d44-09be-4e51-b2fc-6cd0ee3a45c1','齋中偶書','范仲淹','宋','宋诗','song-poetry','','[]','狂愚多苦口，幽遠獨甘心。',48,'全唐诗/poet.song.8000.json','["狂愚多苦口，幽遠獨甘心。", "言路有餘責，權門無去音。", "忘憂曾扣易，思古即援琴。", "此意誰相和，寥寥鶴在陰。"]'),
('da25daaa-eb2b-4706-beb7-5433a8abb3fb','留題江秀才舊居','范仲淹','宋','宋诗','song-poetry','','[]','結舍近滄洲，江山不外求。',24,'全唐诗/poet.song.8000.json','["結舍近滄洲，江山不外求。", "我來明月夜，更得主人留。"]'),
('0b1e9482-9625-452d-bd46-c0956657b15e','依韻酬周騤太博同年','范仲淹','宋','宋诗','song-poetry','','[]','孰敢先懷富貴圖，良時須惜幾嗟吁。',64,'全唐诗/poet.song.8000.json','["孰敢先懷富貴圖，良時須惜幾嗟吁。", "衆心可致巍巍主，上意思平兩兩符。", "不稱內朝裨耳目，多慚外補救皮膚。", "子陵灘畔觀漁釣，無限殘陽媚綠蒲。"]'),
('075a2fb2-78f0-415e-aabc-a8661562fd54','依韻答胡侍郎見寄','范仲淹','宋','宋诗','song-poetry','','[]','千年風采逢明主，一寸襟靈慕昔賢。',32,'全唐诗/poet.song.8000.json','["千年風采逢明主，一寸襟靈慕昔賢。", "待看朝廷興禮讓，天衢何敢鬬先鞭。"]'),
('f63cc2f8-40e3-4ae6-8818-d9afecae7feb','桐廬郡齋書事','范仲淹','宋','宋诗','song-poetry','','[]','千峰秀處白雲驕，吏隱雲邊豈待招。',64,'全唐诗/poet.song.8000.json','["千峰秀處白雲驕，吏隱雲邊豈待招。", "數仞堂高誰富貴，一枝巢隱自逍遙。", "杯中好物閑宜進，林下幽人静可邀。", "莫道官清無歲計，滿山芝朮長靈苖。"]'),
('0ec36167-3bc9-446f-a7a3-dcc68c242001','留題方干處士舊居','范仲淹','宋','宋诗','song-poetry','','[]','風雅先生舊隱存，子陵臺下白雲村。',32,'全唐诗/poet.song.8000.json','["風雅先生舊隱存，子陵臺下白雲村。", "唐朝三百年冠蓋，誰聚詩書到遠孫。"]'),
('c3f0247e-890a-4777-babf-12aa50f5b6cd','依韻酬章推官見贈','范仲淹','宋','宋诗','song-poetry','','[]','姑蘇從古號繁華，却戀巖邊與水涯。',64,'全唐诗/poet.song.8000.json','["姑蘇從古號繁華，却戀巖邊與水涯。", "重入白雲尋釣瀨，更隨明月宿詩家。", "山人驚戴烏紗出，溪女笑偎紅杏遮。", "來蚤又抛泉石去，范茫榮利一吁嗟。"]'),
('c323d46d-5ab3-4b31-a19f-4446472d3eb6','蘇州十詠 泰伯廟','范仲淹','宋','宋诗','song-poetry','','[]','至德本無名，宣尼一此評。',48,'全唐诗/poet.song.8000.json','["至德本無名，宣尼一此評。", "能將天下讓，知有聖人生。", "南國奔方遠，西山道始亨。", "英靈豈不在，千古碧江横。"]'),
('f5107d25-1daf-46bb-96d4-3a00061946fa','蘇州十詠 木蘭堂','范仲淹','宋','宋诗','song-poetry','','[]','堂上列歌鐘，多慚不如古。',24,'全唐诗/poet.song.8000.json','["堂上列歌鐘，多慚不如古。", "却羨木蘭花，曾見霓裳舞。"]'),
('711f38a8-d337-46dc-93ea-8f1b027ebddb','蘇州十詠 洞庭山','范仲淹','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','吳山無此秀，乘暇一遊之。',48,'全唐诗/poet.song.8000.json','["吳山無此秀，乘暇一遊之。", "萬頃湖光裏，千家橘熟時。", "平看月上早，遠覺鳥歸遲。", "近古誰真賞，白雲應得知。"]'),
('0b0380b9-c390-461c-a6a8-5167fd19e0ac','蘇州十詠 虎丘山','范仲淹','宋','宋诗','song-poetry','','[]','昔見虎耽耽，今爲佛子巖。',48,'全唐诗/poet.song.8000.json','["昔見虎耽耽，今爲佛子巖。", "雲寒不出寺，劍静未離潭。", "幽步蘿垂徑，高禪雪閉菴。", "吳都十萬户，煙瓦亘西南。"]'),
('90f5d1b0-ec5b-4092-895b-a7b77d2ba5ad','蘇州十詠 閶門','范仲淹','宋','宋诗','song-poetry','','[]','吳門聳閶闔，迎送毎躋攀。',48,'全唐诗/poet.song.8000.json','["吳門聳閶闔，迎送毎躋攀。", "一水帝鄉路，片雲師子山。", "落鴻漁釣外，斜柳别離間。", "白傅歸休處，盤桓幾厚顔。"]'),
('b5367bea-ac51-474b-8722-216f5c428f51','蘇州十詠 靈巖寺','范仲淹','宋','宋诗','song-poetry','','[]','古來興廢一愁人，白髪僧歸掩寺門。',64,'全唐诗/poet.song.8000.json','["古來興廢一愁人，白髪僧歸掩寺門。", "越相煙波空去鴈，吳王宫闕半啼猿。", "春風似舊花猶笑，往事多遺石不言。", "唯有延陵逃遁去，清名高節滿乾坤。"]'),
('ef977068-564a-4e69-8d5c-1c2e9f9f991a','蘇州十詠 太湖','范仲淹','宋','宋诗','song-poetry','','["\u592a\u6e56"]','有浪即山高，無風還練静。',24,'全唐诗/poet.song.8000.json','["有浪即山高，無風還練静。", "秋宵誰與期，月華三萬頃。"]'),
('0ce3c392-c672-4e83-9095-c385a35b00b3','蘇州十詠 伍相廟','范仲淹','宋','宋诗','song-poetry','','[]','胥也應無憾，至哉忠孝門。',48,'全唐诗/poet.song.8000.json','["胥也應無憾，至哉忠孝門。", "生能酬楚怨，死可報吳恩。", "直氣海濤在，片心江月存。", "悠悠當日者，千載秪慚魂。"]'),
('024ac973-87b1-4158-b3ef-08ec3002df41','蘇州十詠 觀風樓','范仲淹','宋','宋诗','song-poetry','','[]','高壓郡西城，觀風不浪名。',48,'全唐诗/poet.song.8000.json','["高壓郡西城，觀風不浪名。", "山川千里色，語笑萬家聲。", "碧寺煙中静，紅橋柳際明。", "登臨豈劉白，滿目見詩情。"]'),
('e8922bcd-5d8e-4e69-a0b2-83f5cfe6f7bd','蘇州十詠 南園','范仲淹','宋','宋诗','song-poetry','','[]','西施臺下見名園，百草千花特地繁。',32,'全唐诗/poet.song.8000.json','["西施臺下見名園，百草千花特地繁。", "欲問吳王當日事，後來桃李若爲言。"]'),
('33c45a9c-3682-4e30-a827-d7cac9734bdc','依韻奉酬晏尚書見寄','范仲淹','宋','宋诗','song-poetry','','[]','徽音來景亳，盛事聳吳鄉。',144,'全唐诗/poet.song.8000.json','["徽音來景亳，盛事聳吳鄉。", "上象三台照，高文五色章。", "純如登樂府，淵若測天潢。", "寒谷春重煦，幽宫草特芳。", "感知心似血，思報鬢成霜。", "新定慚無惠，姑蘇惜未康。", "堯湯餘水旱，劉白舊風光。", "北闕雲霓遠，南園橘柚荒。", "願聞歌畫一，敢議賦長楊。", "碌碌嘲須解，循循教弗忘。", "跡甘榮路外，情寄聖門傍。", "幾託爲魚夢，江湖尚渺茫。"]'),
('ed96c6cd-0c67-4e8a-9293-27df6058e271','又用前韻謝晏尚書以近著示及','范仲淹','宋','宋诗','song-poetry','','[]','祖述賢人業，何因降玄鄉。',144,'全唐诗/poet.song.8000.json','["祖述賢人業，何因降玄鄉。", "周公舊才美，夫子近文章。", "逸氣彌衝斗，雄源甚決潢。", "月中靈桂老，春外寶芝芳。", "遠似天無翳，清如塞有霜。", "日星圖舜禹，金石頌成康。", "渦曲風騷盛，營丘學校光。", "至精含變化，大手鑿洪荒。", "崧嶽詞欺甫，甘泉價掩揚。", "滿朝當諷誦，終古豈遺忘。", "恍若探龍際，森疑履虎傍。", "半生游此道，觀海特茫茫。"]'),
('92070baf-1cbf-4105-b259-194095ca66eb','陳質殿丞挽歌詞','范仲淹','宋','宋诗','song-poetry','','[]','賢者逝如斯，皇天豈易知。',48,'全唐诗/poet.song.8000.json','["賢者逝如斯，皇天豈易知。", "衆人皆墮淚，君子欲安碑。", "幾世傳清白，滿鄉稱孝慈。", "賢哉生令嗣，遺秀在蘭芝。"]'),
('93761132-bc64-4213-9469-da9437014f93','送僧文光','范仲淹','宋','宋诗','song-poetry','','[]','一品山前識，迢迢三十春。',24,'全唐诗/poet.song.8000.json','["一品山前識，迢迢三十春。", "多慚畫戟裏，重見白雲人。"]'),
('651fbdbc-9a8e-4bfd-a958-b6a2017f2c74','依韻酬府判龐醇之見寄  其一','范仲淹','宋','宋诗','song-poetry','','[]','二十年前已定交，而今鵬鷃各逍遙。',64,'全唐诗/poet.song.8000.json','["二十年前已定交，而今鵬鷃各逍遙。", "但能賈傅親前席，何必蕭生意本朝。", "直節羡君如指佞，孤根憐我異凌霄。", "莫將富貴移平昔，彼此清心髪半凋。"]'),
('e25431fd-7811-4d91-a942-47f1d1be224c','依韻酬府判龐醇之見寄  其二','范仲淹','宋','宋诗','song-poetry','','[]','吳門歉歲減繁華，蕭索專城未足誇。',64,'全唐诗/poet.song.8000.json','["吳門歉歲減繁華，蕭索專城未足誇。", "柳色向秋迎使館，水聲終夜救田車。", "丘山在負思朝寄，毫髪經心愧道家。", "不似桐廬人事少，子陵臺畔樂無涯。"]'),
('404897ba-d771-4939-8315-eb05fcaed28f','依韻酬吳安道學士見寄','范仲淹','宋','宋诗','song-poetry','','[]','聖君賢相正彌綸，諫諍臣微敢徇身。',64,'全唐诗/poet.song.8000.json','["聖君賢相正彌綸，諫諍臣微敢徇身。", "但得葵心長向日，何妨騖足未離塵。", "豈辭雲水三千里，猶濟瘡痍十萬民。", "宴坐黄堂愧無限，隴頭元是带經人。"]'),
('ac245b6c-9c1d-4070-83f5-0890b041a5c5','依韻酬吳春卿二首 鶴','范仲淹','宋','宋诗','song-poetry','','[]','華亭孤立病時身，終日徘徊尚海濱。',64,'全唐诗/poet.song.8000.json','["華亭孤立病時身，終日徘徊尚海濱。", "露掌思高還警夜，芝田音斷欲傷春。", "千年靈氣何求藥，八變奇姿已過人。", "莫厭在陰猶寡和，九臯非晚見精神。"]'),
('5dc843cf-a01a-43be-bb46-39b509d44192','依韻酬吳春卿二首 松','范仲淹','宋','宋诗','song-poetry','','[]','亭亭百尺棟梁身，寂寞雲根與澗濱。',64,'全唐诗/poet.song.8000.json','["亭亭百尺棟梁身，寂寞雲根與澗濱。", "寒冒雪霜寧是病，静期風月不須春。", "蕭蕭遠韻和於樂，密密清陰意在人。", "高節直心時勿伐，千秋爲石迺知神。"]'),
('8fadbe4d-5854-414a-9c63-e252ea53f071','應制賞花釣魚','范仲淹','宋','宋诗','song-poetry','','[]','萬彙嘉亨日，皇心豫宴辰。',48,'全唐诗/poet.song.8000.json','["萬彙嘉亨日，皇心豫宴辰。", "華林新濯雨，靈沼正涵春。", "帝幄紛仙蘤，天鈎擲錦鱗。", "洋洋頒睿唱，賡頌浹簪紳。"]'),
('ef5c606a-9315-473e-a1ef-ab2885d7068a','過餘杭白塔寺','范仲淹','宋','宋诗','song-poetry','','[]','登臨江上寺，遷客特依依。',48,'全唐诗/poet.song.8000.json','["登臨江上寺，遷客特依依。", "遠水欲無際，孤舟曾未歸。", "亂峰藏好處，幽鷺得閑飛。", "多少天真趣，遙心結翠微。"]'),
('b52c804c-8c72-4715-8ccc-9b7cc40ee889','西湖筵上贈胡侍郎','范仲淹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','官秩文昌貴，功名信史褒。',48,'全唐诗/poet.song.8000.json','["官秩文昌貴，功名信史褒。", "朝廷三老重，鄉黨二疏高。", "涯業盡圖籍，子孫皆俊髦。", "西湖天下絕，今日盛遊遨。"]'),
('5c15c9ae-b054-475e-b202-d4aa319f98fe','江城對月','范仲淹','宋','宋诗','song-poetry','','[]','南國風波遠，東門冠蓋回。',24,'全唐诗/poet.song.8000.json','["南國風波遠，東門冠蓋回。", "多情是明月，相逐過江來。"]'),
('6146ff78-bd5b-4924-950a-830de545f307','送向綜國博通判桂州','范仲淹','宋','宋诗','song-poetry','','[]','通籍三公後，監州五嶺深。',48,'全唐诗/poet.song.8000.json','["通籍三公後，監州五嶺深。", "欲知明主意，將慰遠人心。", "歲計多藏藥，舟行不廢琴。", "歸書清白最，寧問槖中金。"]'),
('9d565749-8cbf-415f-8a78-03b5a5306ff0','芝山寺','范仲淹','宋','宋诗','song-poetry','','[]','樓殿觀崔嵬，靈芝安在哉。',48,'全唐诗/poet.song.8000.json','["樓殿觀崔嵬，靈芝安在哉。", "雲飛過江去，花落入城來。", "得食鵶朝聚，聞經虎夜回。", "偶臨西閣望，五老夕陽開。"]'),
('88c98b9e-e052-4f3c-a6e6-451f9e58cb86','昇上人碧雲軒','范仲淹','宋','宋诗','song-poetry','','[]','愛此詩家好，幽軒絕世紛。',48,'全唐诗/poet.song.8000.json','["愛此詩家好，幽軒絕世紛。", "澄宵半牀月，淡曉數峰雲。", "遠意經年就，微吟並舍聞。", "只應虚静處，所得自蘭芬。"]'),
('0cd6224b-3373-450d-92f1-ac89db83a6f0','郡齋即事','范仲淹','宋','宋诗','song-poetry','','[]','三出專城鬢似絲，齋中蕭灑過禪師。',64,'全唐诗/poet.song.8000.json','["三出專城鬢似絲，齋中蕭灑過禪師。", "近疏歌酒緣多病，不負雲山賴有詩。", "半雨黄花秋賞健，一江明月夜歸遲。", "世間榮辱何須道，塞上衰翁也自知。"]'),
('5455297f-7fe4-4775-9816-f1948c682774','同年魏介之會上作','范仲淹','宋','宋诗','song-poetry','','[]','寒苦同登甲乙科，天涯相對合如何。',64,'全唐诗/poet.song.8000.json','["寒苦同登甲乙科，天涯相對合如何。", "心存闕下還憂畏，身在樽前且笑歌。", "閑上碧江游畫鷁，醉留紅袖舞鳴鼉。", "與君今日真良會，自信麤官樂事多。"]'),
('730c4e36-583b-4817-8ebc-119944f22187','依韻酬黄灝秀才','范仲淹','宋','宋诗','song-poetry','','[]','再貶鄱川信不才，子規相愛勸歸來。',64,'全唐诗/poet.song.8000.json','["再貶鄱川信不才，子規相愛勸歸來。", "客心但感江山助，天意難期日月迴。", "白雪孤琴彌冷淡，浮雲雙闕自崔嵬。", "南方歲宴猶能樂，醉盡黄花見早梅。"]'),
('1f41c971-3235-4918-b887-417e38e7d89a','贈鍾道士','范仲淹','宋','宋诗','song-poetry','','[]','人間無復動機心，掛了儒冠歲已深。',32,'全唐诗/poet.song.8000.json','["人間無復動機心，掛了儒冠歲已深。", "惟有詩家風味在，一壇松月伴秋吟。"]'),
('bee57633-16f4-4f58-b19d-b141413bde30','道士程用之爲余傳神因題','范仲淹','宋','宋诗','song-poetry','','[]','貌古神疏畫本難，因師心妙發毫端。',32,'全唐诗/poet.song.8000.json','["貌古神疏畫本難，因師心妙發毫端。", "無功可上凌雲閣，留取雲山静處看。"]'),
('9ac0821b-c727-4b5e-b6c1-ccfe41df1d59','送魏介之江西提點','范仲淹','宋','宋诗','song-poetry','','[]','旌旗如火浪如鷗，一路春城次第遊。',32,'全唐诗/poet.song.8000.json','["旌旗如火浪如鷗，一路春城次第遊。", "江上高樓欲千尺，便從今日望歸舟。"]'),
('44112f6e-dac2-42b4-996e-6b846fd660b0','遊廬山作','范仲淹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五老閑遊倚舳艫，碧梯嵐逕好程途。',64,'全唐诗/poet.song.8000.json','["五老閑遊倚舳艫，碧梯嵐逕好程途。", "雲開瀑影千門掛，雨過松黄十里鋪。", "客愛往來何所得，僧言榮辱此間無。", "從今愈識逍遙旨，一聽升沉造化鑪。"]'),
('4870fea7-f3e8-4aa4-93c3-497b156b8b96','瀑布','范仲淹','宋','宋诗','song-poetry','','[]','迥與衆流異，發源高更孤。',48,'全唐诗/poet.song.8000.json','["迥與衆流異，發源高更孤。", "下山猶直在，到海得清無。", "勢鬭蛟龍惡，聲吹雨雹麤。", "晚來雲一色，詩句自成圖。"]'),
('726854a9-8c8f-485e-b532-db36bff42f1c','贈廣宣大師','范仲淹','宋','宋诗','song-poetry','','[]','憶昔同遊紫閣雲，别來三十二迴春。',32,'全唐诗/poet.song.8000.json','["憶昔同遊紫閣雲，别來三十二迴春。", "白頭相見雙林下，猶是清朝未退人。"]'),
('1ddd6712-f420-4212-8d44-e481a1766feb','移丹陽郡先遊茅山作','范仲淹','宋','宋诗','song-poetry','','[]','丹陽太守意何如，先謁茅卿始下車。',64,'全唐诗/poet.song.8000.json','["丹陽太守意何如，先謁茅卿始下車。", "展節事君三黜後，收心奉道五旬初。", "偶尋靈草逢芝圃，欲扣真關借玉書。", "不更從人問通塞，天教吏隱接山居。"]'),
('b1f7ebb8-1362-4d39-a6ff-e862e1b234fe','贈茅山張道者','范仲淹','宋','宋诗','song-poetry','','[]','有客生平愛白雲，無端年老尚紅塵。',32,'全唐诗/poet.song.8000.json','["有客生平愛白雲，無端年老尚紅塵。", "只應金簡名猶在，得見仙巖種玉人。"]'),
('9804b296-7cda-400e-8bcd-e4c9c133176b','京口即事','范仲淹','宋','宋诗','song-poetry','','[]','突兀立孤城，詩中别有情。',48,'全唐诗/poet.song.8000.json','["突兀立孤城，詩中别有情。", "地深江底過，日大海心生。", "甘露樓臺古，金山氣象清。", "六朝人薄命，不見此昇平。"]'),
('fdfd283d-d47c-4a4f-b76a-8176e32af242','懷慶朔堂','范仲淹','宋','宋诗','song-poetry','','[]','慶朔堂前花自栽，便移官去未曾開。',32,'全唐诗/poet.song.8000.json','["慶朔堂前花自栽，便移官去未曾開。", "年年憶著成離恨，只託清風管勾來。"]'),
('019d6165-65f0-4ce7-ab82-8edd4562eeb8','依韻酬葉道卿中秋對月二首  其一','范仲淹','宋','宋诗','song-poetry','','[]','天遣今宵無寸雲，故開秋碧掛冰輪。',32,'全唐诗/poet.song.8000.json','["天遣今宵無寸雲，故開秋碧掛冰輪。", "詩人不悔衣霑露，爲惜清光豈易親。"]'),
('76de25dc-cbf7-4236-8948-11ec24ac1fc8','依韻酬葉道卿中秋對月二首  其二','范仲淹','宋','宋诗','song-poetry','','[]','孤光千里與君逢，最愛無雲四望通。',32,'全唐诗/poet.song.8000.json','["孤光千里與君逢，最愛無雲四望通。", "處處樓臺競歌宴，的能愛月幾人同。"]'),
('2dcb4334-f746-4714-95bf-f462a03634cb','贈葉少卿','范仲淹','宋','宋诗','song-poetry','','[]','退也天之道，東南事了人。',96,'全唐诗/poet.song.8000.json','["退也天之道，東南事了人。", "風波抛舊路，花月伴閑身。", "湖外扁舟遠，門中駟馬新。", "心從今日泰，家似昔時貧。", "見子登西掖，攜孫過北鄰。", "白雲高閣曙，淥水後池春。", "樽酒呼前輩，鑪香扣上真。", "只應陰德在，八十富精神。"]'),
('69a843de-5e87-4325-a19b-d944c18d5b8e','依韻答梁堅運判見寄','范仲淹','宋','宋诗','song-poetry','','[]','蔽野旌旗色，滿山笳吹聲。',24,'全唐诗/poet.song.8000.json','["蔽野旌旗色，滿山笳吹聲。", "功名早晚就，裴度亦書生。"]'),
('8f50d3f0-e64d-4ff1-a731-67700aa04206','城大順迴道中作','范仲淹','宋','宋诗','song-poetry','','[]','三月二十七，羌山始見花。',24,'全唐诗/poet.song.8000.json','["三月二十七，羌山始見花。", "將軍了邊事，春老未還家。"]'),
('624e7641-5864-4c6d-a8c0-7ca587fa3dc7','依韻和延安龐龍圖柳湖','范仲淹','宋','宋诗','song-poetry','','[]','種柳穿湖後，延安盛可遊。',120,'全唐诗/poet.song.8000.json','["種柳穿湖後，延安盛可遊。", "遠懷忘澤國，真賞即瀛洲。", "江景來秦塞，風情屬庾樓。", "劉琨增坐嘯，王粲乍銷憂。", "秀發千絲墮，光揺匹練柔。", "雙雙翔乳鷰，兩兩睡馴鷗。", "折翠贈歸客，濯清招隱流。", "宴回銀燭夜，吟度玉關秋。", "勝處千場醉，勞生萬事浮。", "王公多雅故，思去共仙舟。"]'),
('856aca7a-3bf2-4cc9-8e1c-28f1452c30ec','和延安龐龍圖寄岳陽滕同年','范仲淹','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','優游滕太守，郡枕洞庭邊。',96,'全唐诗/poet.song.8000.json','["優游滕太守，郡枕洞庭邊。", "幾處雲藏寺，千家月在船。", "疏鴻秋浦外，長笛晚樓前。", "旋撥醅頭酒，新炰縮項鯿。", "宦情須淡薄，詩意定連緜。", "迥是偷安地，仍當飽事年。", "只應天下樂，無出日高眠。", "豈信憂邊處，干戈隔一川。"]'),
('e9c57eab-6aac-4541-8ece-f88c5980e319','與張燾太博行忻代間因話江山作','范仲淹','宋','宋诗','song-poetry','','[]','數年風土塞門行，說著江山意暫清。',32,'全唐诗/poet.song.8000.json','["數年風土塞門行，說著江山意暫清。", "求取罷兵南國去，滿樓蒼翠是平生。"]'),
('5f7fa703-8254-47d5-8d24-f146070f37fb','過長安醉别資政鄭侍郎','范仲淹','宋','宋诗','song-poetry','','[]','鄉關交復親，把酒且逡巡。',48,'全唐诗/poet.song.8000.json','["鄉關交復親，把酒且逡巡。", "共上青雲路，相看白髪人。", "有爲須報國，無事即頥神。", "故素幾云在，風音莫厭頻。"]'),
('d428c4ea-3cbf-46c6-af04-f19fb2169540','依韻酬光化李簡夫屯田','范仲淹','宋','宋诗','song-poetry','','[]','老來難得舊交游，莫歎樽前兩鬢秋。',64,'全唐诗/poet.song.8000.json','["老來難得舊交游，莫歎樽前兩鬢秋。", "少日苦辛名共立，晚年恬退語相投。", "龔黄政事聊牽强，元白鄰封且唱酬。", "附郭田園能置否，與君乘健早歸休。"]'),
('2f8887e4-6222-4384-a6d1-b28c2d258416','依韻酬太傅張相公見贈','范仲淹','宋','宋诗','song-poetry','','[]','出處曾無致主功，南陽爲守地猶雄。',64,'全唐诗/poet.song.8000.json','["出處曾無致主功，南陽爲守地猶雄。", "醉醒往日慚漁父，得失今朝賀塞翁。", "七里河邊歸带月，百花洲上嘯生風。", "卧龍鄉曲多賢達，願預逍遙九老中。"]'),
('5d4f225f-7029-4f29-bc72-c811f6616032','依韻酬益利鈐轄馬端左藏','范仲淹','宋','宋诗','song-poetry','','[]','濫登清顯遇公朝，豈有才謀可致堯。',64,'全唐诗/poet.song.8000.json','["濫登清顯遇公朝，豈有才謀可致堯。", "拙守自慚成木强，宦遊誰歎僅蓬飄。", "醉來多謝提壺勸，歸去寧煩杜宇招。", "好樂當年開口笑，此心無事愧重霄。"]'),
('9a1d255d-b93b-423e-aab8-d0b3facce940','依韻酬邠州通判王稷太博','范仲淹','宋','宋诗','song-poetry','','[]','南豳日日接英標，公外追隨豈待招。',64,'全唐诗/poet.song.8000.json','["南豳日日接英標，公外追隨豈待招。", "惡勸酒時圖共醉，痛贏棋處肯相饒。", "一抛言笑如何遣，頻得音書似不遙。", "獨上西樓爲君久，滿城明月會雲銷。"]'),
('785d879f-6dff-4848-92d3-288c51fd4d73','依韻酬李光化見寄','范仲淹','宋','宋诗','song-poetry','','[]','南陽偃息養衰顔，天暖風和近楚關。',64,'全唐诗/poet.song.8000.json','["南陽偃息養衰顔，天暖風和近楚關。", "欲少禍時當止足，得無權處始安閑。", "心憐好鳥來幽院，目送微雲過别山。", "此景此情聊自慰，是非何極任循環。"]'),
('307d41a7-15d7-4cf1-957f-445e7cde397b','寄安素高處士','范仲淹','宋','宋诗','song-poetry','','[]','吏隱南陽味日新，幕中文雅盡交賓。',32,'全唐诗/poet.song.8000.json','["吏隱南陽味日新，幕中文雅盡交賓。", "滿軒明月清譚夜，共憶詩書萬卷人。"]'),
('b984d91a-5eee-4e49-b38a-9705fc43877c','酬李光化見寄二首  其一','范仲淹','宋','宋诗','song-poetry','','[]','交親莫笑出麾頻，不任纖機只任真。',64,'全唐诗/poet.song.8000.json','["交親莫笑出麾頻，不任纖機只任真。", "遠護玉關猶竭力，入陪金鉉敢周身。", "素心直擬圭無玷，晚節當如竹有筠。", "道本逍遙惟所適，吾生何用蠖求伸。"]'),
('6b5523a0-985e-494e-8fd3-e1299ecc2774','酬李光化見寄二首  其二','范仲淹','宋','宋诗','song-poetry','','[]','萬里承平堯舜風，使君尺素半空空。',64,'全唐诗/poet.song.8000.json','["萬里承平堯舜風，使君尺素半空空。", "庭中無事吏歸早，野外有歌民意豐。", "石鼎鬭茶浮乳白，海螺行酒灎波紅。", "宴堂未盡嘉賓興，移下秋光月色中。"]'),
('85c26d5e-6eaf-4f1e-96eb-851d61db320f','依韻酬李光化敘懷','范仲淹','宋','宋诗','song-poetry','','[]','列宿専城且自娛，清名善最即前途。',64,'全唐诗/poet.song.8000.json','["列宿専城且自娛，清名善最即前途。", "江山樂國誠難會，風月詩家的不辜。", "未必晚成輸早達，好將高笑代長吁。", "公餘更勵經邦業，思爲清朝贊禹謨。"]'),
('427824ce-97fb-4f8e-bc5c-50cb1318e39d','和李光化秋詠四首 曉','范仲淹','宋','宋诗','song-poetry','','[]','牆外轆轤響，樓前江漢欹。',24,'全唐诗/poet.song.8000.json','["牆外轆轤響，樓前江漢欹。", "曙光和月色，猶記早朝時。"]'),
('fe3cb30b-1f4c-42f0-81c9-6fe82fd7b8b3','和李光化秋詠四首 晝','范仲淹','宋','宋诗','song-poetry','','[]','日色清如照，前林葉未零。',24,'全唐诗/poet.song.8000.json','["日色清如照，前林葉未零。", "海東新隼至，一點在青冥。"]'),
('aa656ed6-afe4-459d-804d-9aa97960620a','和李光化秋詠四首 晚','范仲淹','宋','宋诗','song-poetry','','[]','晚色動邊思，去年猶未歸。',24,'全唐诗/poet.song.8000.json','["晚色動邊思，去年猶未歸。", "戍樓人已冷，目斷望征衣。"]'),
('c9c3de84-3e8a-4bd6-85f1-178249daeccc','和李光化秋詠四首 夜','范仲淹','宋','宋诗','song-poetry','','[]','春色人皆醉，秋光獨不眠。',24,'全唐诗/poet.song.8000.json','["春色人皆醉，秋光獨不眠。", "君看明月下，何似落花前。"]'),
('64aa4a0e-30b3-413f-a367-d755a36aa916','送黄灝員外','范仲淹','宋','宋诗','song-poetry','','[]','三十餘年交舊心，相逢那復議升沉。',64,'全唐诗/poet.song.8000.json','["三十餘年交舊心，相逢那復議升沉。", "卑飛塵土味誠薄，達宦風波憂更深。", "自古榮華渾一夢，即時歡笑敵千金。", "追陪未久還離索，早晚軒車重見尋。"]'),
('df5b10ba-4d97-481f-991a-b02181c5ac0e','和并州大資政鄭侍郎秋晚書事','范仲淹','宋','宋诗','song-poetry','','[]','太原兵重壓强胡，莫對秋風憶鱠鱸。',64,'全唐诗/poet.song.8000.json','["太原兵重壓强胡，莫對秋風憶鱠鱸。", "萬里天聲揚紫塞，十年人望在黄樞。", "定應松柏心無改，自信雲龍道不孤。", "應笑病夫何所補，獨能安坐養桑榆。"]'),
('32f64fa9-ce38-4017-a988-829911dd3b09','和提刑趙學士探梅三絕  其一','范仲淹','宋','宋诗','song-poetry','','[]','蕭條臈後復春前，雪壓霜欺未放妍。',32,'全唐诗/poet.song.8000.json','["蕭條臈後復春前，雪壓霜欺未放妍。", "昨日倚欄枝上看，似留芳意入新年。"]'),
('743b2dab-9d8c-437d-b7c0-37dd9c443d30','和提刑趙學士探梅三絕  其二','范仲淹','宋','宋诗','song-poetry','','[]','静映寒林晚未芳，人人欲看壽陽粧。',32,'全唐诗/poet.song.8000.json','["静映寒林晚未芳，人人欲看壽陽粧。", "玉顔須傍韶春笑，莫鬭嚴風與惡霜。"]'),
('7e02285f-fa3e-48b9-870c-9b385a4b0f6e','和提刑趙學士探梅三絕  其三','范仲淹','宋','宋诗','song-poetry','','[]','百花爭早孰過梅，天與芳時豈待催。',32,'全唐诗/poet.song.8000.json','["百花爭早孰過梅，天與芳時豈待催。", "莫惜黄金置清賞，隔年春色爲君開。"]'),
('1328b0fb-6151-40f5-a792-fc78c2821e3e','和太傅鄧公歸遊武當見寄','范仲淹','宋','宋诗','song-poetry','','[]','三提相印代天工，鄧國歸來耀本封。',64,'全唐诗/poet.song.8000.json','["三提相印代天工，鄧國歸來耀本封。", "此日神仙丁令鶴，幾年霖雨武侯龍。", "酬恩定得祠黄石，談道須期會赤松。", "莫慮故鄉陵谷變，武當依舊碧重重。"]'),
('900e8086-b157-454f-ba15-e032677ccb9e','即席呈太傅相公','范仲淹','宋','宋诗','song-poetry','','[]','鳯池三入冠台躔，致了昇平一品閑。',64,'全唐诗/poet.song.8000.json','["鳯池三入冠台躔，致了昇平一品閑。", "白傅歌詩傳海外，晉公桃李滿人間。", "上都雲遠經時别，故國春濃幾度還。", "太史占天應有奏，壽星光彩近南山。"]'),
('fd7ac7a9-3cf9-434b-99a1-82d099a5b10d','紀送太傅相公歸闕','范仲淹','宋','宋诗','song-poetry','','[]','搢紳誰敢望差肩，獨向昌期協半千。',128,'全唐诗/poet.song.8000.json','["搢紳誰敢望差肩，獨向昌期協半千。", "首會雲龍游少海，親扶日月上中天。", "碧油兩就元戎鎮，黄閣三提冢宰權。", "坐致唐虞成大化，退居師傅養高年。", "閑披丹訣開鑪竈，醉度清歌被管絃。", "同牓幾人登將相，滿朝今日羡神仙。", "松楸薙草思純孝，里巷揮金過昔賢。", "歸赴誕辰知兑說，輕安拜舞壽觴前。"]'),
('937ed755-1b9e-452d-a223-bca0f96ccfc6','謝佛鑑大師寄韞玉鑪','李彭','宋','宋诗','song-poetry','','[]','道人力參具正眼，古廟香爐心已灰。',112,'全唐诗/poet.song.80000.json','["道人力參具正眼，古廟香爐心已灰。", "平生厚我習氣在，索書常逐征鴻來。", "深藏山谷實高蹈，下視萬象遺塵埃。", "遣奴餉我此長物，不比珍簟餘嫌猜。", "摩娑温潤侔玉德，荆山抱璞真良材。", "妙香起處侑茶鼎，媒孽萬壑生風雷。", "忽言與君隔千里，對此了了聞談諧。"]'),
('c5506a8c-6771-4097-a1ed-5de5c3124b18','謝王成可惠鼎爐','李彭','宋','宋诗','song-poetry','','[]','王郎筆若追風驃，歷塊過都愈奇峭。',160,'全唐诗/poet.song.80000.json','["王郎筆若追風驃，歷塊過都愈奇峭。", "胸中好古類古人，鑄鼎爲鑪亦臻妙。", "禹金九牧知神姦，周定郟鄏垂不刊。", "據耳向來爲上客，折足遙憐空汗顔。", "顔率遊談聊貰患，納郜臧孫貽直諫。", "淪亡泗水蓋厚誣，得自汾陰亂真贋。", "孰如此鼎形瓌奇，皤腹雲雷差次之。", "上有蒼虬肉倔強，隱映么麽微螽斯。", "明窗净几香氤氳，藹如黄雲覆晏温。", "拜嘉詎意獲此寶，子孫父已傳仍昆。"]'),
('49ff38d0-6fa9-4d33-aa2b-ae1ea82c7aca','次九弟中秋韻','李彭','宋','宋诗','song-poetry','','[]','楚江微波鳴盎酒，脱葉蕭然坐來久。',128,'全唐诗/poet.song.80000.json','["楚江微波鳴盎酒，脱葉蕭然坐來久。", "仰頭看月落烏紗，無復纖雲漢津口。", "顧兔之靈態度深，搗藥長生傳至今。", "風前急管聞三弄，泓下蒼龍時一吟。", "逸興俄生縹粉壺，攜幼近局無勞呼。", "坐中白髪飲輙醉，鼻雷發聲聊據梧。", "異舍羣雞皆誤唱，舍下鳴蛩亦清壯。", "低昂北斗掛柴扉，不眠尚倚過眉杖。"]'),
('b49fb8a1-ef0c-482a-9b7d-f6d098332d45','歸舟','李彭','宋','宋诗','song-poetry','','[]','旌陽峰頭千仞石，溪光卻照楚天碧。',96,'全唐诗/poet.song.80000.json','["旌陽峰頭千仞石，溪光卻照楚天碧。", "歸客操舟暝色時，怒雷濺雪多灘磧。", "夜榜時驚烏鵲喧，星光破碎月映門。", "訪戴人歸剡谿曲，問津客出桃花村。", "香醪獨酌吾静寄，萬事不理端復細。", "俗交從來薄於紙，小黠大癡聊一戲。"]'),
('740cfe2c-29f0-4c15-8ed7-41c1e8d57716','正月二十六日寇順之飲僕以醽渌酒徑醉聞横笛音李仲先順之有蒼頭能作龍吟三弄偶不果戲成此詩','李彭','宋','宋诗','song-poetry','','[]','髯奴不及緣坡竹，柱車守閭各有局。',128,'全唐诗/poet.song.80000.json','["髯奴不及緣坡竹，柱車守閭各有局。", "苟不上券吾不欲，僮約卒音幾慟哭。", "劣於郄公常奴爾，性不茹葷少陵喜。", "吐茵西曹第忍之，封侯骨相多小史。", "蒼頭乃復在琳房，柯亭横吹節飽霜。", "炊飯作糜緣底事，心寫泉聲風韻長。", "寇謙酌我次翁狂，如魚聽曲首低昂。", "恨不臨風作三弄，不减當時桓野王。"]'),
('74923d78-abf0-4688-aca2-b182bdf34eb4','舟中戲作雜言','李彭','宋','宋诗','song-poetry','','[]','昨日觀畫筴，李成山水真難忘。',126,'全唐诗/poet.song.80000.json','["昨日觀畫筴，李成山水真難忘。", "寒林遠近烟暗澹，絕壑稠疊雲微茫。", "忽看清溪下野艇，驚殘鷗鳥不成行。", "我嘗指此語座客，安得仙骨來中央。", "此事數日爾，忽落圖上鳴漁榔。", "山重水複灘瀨急，雅飛不過吳天長。", "嗟予老矣兩鬢蒼，放浪自得宜深藏。", "煩於畫筴試檢校，恐我割取附益歐峰旁。"]'),
('bfd2cf66-aea2-4f4c-8347-ad8a2fc07304','次暉書記韻','李彭','宋','宋诗','song-poetry','','[]','平生邁往回萬牛，晚著壞衲乘虚舟。',64,'全唐诗/poet.song.80000.json','["平生邁往回萬牛，晚著壞衲乘虚舟。", "僧中那得賈長頭，對語亹亹連不休。", "作夏深藏白蓮裏，心如此花映秋水。", "夢隨歸雲欲訪之，鄰垣華鯨喧枕底。"]'),
('aa58bfd4-2f4f-414e-913a-5c5a941b24dc','次韻陳無己擬古','李彭','宋','宋诗','song-poetry','','[]','說桓佐宣項垂癭，鋭頭將軍風骨緊。',64,'全唐诗/poet.song.80000.json','["說桓佐宣項垂癭，鋭頭將軍風骨緊。", "病夫面带丘壑姿，白薤綠葵窮可忍。", "忠風輝映義骨香，苦事何須味方永。", "夜歌商頌出金石，猿歗寒柯掛參井。"]'),
('68e4c99a-0039-4225-b1ff-45385769e195','病目宴坐','李彭','宋','宋诗','song-poetry','','[]','腦脂遮目乏風味，宴坐禪床真得計。',64,'全唐诗/poet.song.80000.json','["腦脂遮目乏風味，宴坐禪床真得計。", "赤眼歸宗近似之，面壁少林聊復爾。", "東坡妙語久猶新，治目常存如治民。", "但學曹參相齊法，清夷王度不無人。"]'),
('8c3e944e-0ad2-433c-82e7-3c799ce07add','連日大雪','李彭','宋','宋诗','song-poetry','','[]','春風吹雪塞寒門，饑烏暮啼寒雀喧。',96,'全唐诗/poet.song.80000.json','["春風吹雪塞寒門，饑烏暮啼寒雀喧。", "此中要是難測地，材堪令僕無複褌。", "引帆上檣中繫軛，燒車與船復延客。", "平生四十二年非，頓悟前塵頭半白。", "願隨谿支水雲鄉，簑衣負雪時鳴榔。", "不知許事付歡伯，醉著寒灘清夢長。"]'),
('e2b91940-00c9-4d9d-9de6-e20f670df648','喜得師質消息','李彭','宋','宋诗','song-poetry','','[]','南國柳花合，淮壖麥秀初。',48,'全唐诗/poet.song.80000.json','["南國柳花合，淮壖麥秀初。", "數聲傳喜鵲，一紙故人書。", "君出理煙艇，儂還荷雨鋤。", "天高風浪惡，歸興不應疏。"]'),
('1600506b-5ea9-45d7-9f0d-0f3d02ab49d1','漫興','李彭','宋','宋诗','song-poetry','','[]','鴈带秋聲滿，鷗将暝色歸。',48,'全唐诗/poet.song.80000.json','["鴈带秋聲滿，鷗将暝色歸。", "打窗紅葉亂，裁句碧雲飛。", "好飲酒儲盡，少眠茶夢稀。", "眷言方外侣，時送北山薇。"]'),
('14f7b6fc-438d-40f2-8beb-6ad22ea39152','宿同安寺','李彭','宋','宋诗','song-poetry','','[]','山暝客初到，雨餘雲尚屯。',48,'全唐诗/poet.song.80000.json','["山暝客初到，雨餘雲尚屯。", "長廊響僧唄，凉月耿松門。", "踐境知心遠，背塵惟佛尊。", "道人暗不語，真覺我言煩。"]'),
('3a8890ea-6211-4f13-90ba-c12eb72551a0','遊藏山寺','李彭','宋','宋诗','song-poetry','','[]','招提雖負郭，菌閣暗藏幽。',48,'全唐诗/poet.song.80000.json','["招提雖負郭，菌閣暗藏幽。", "春漲桃花水，風回沙際鷗。", "含煙朝日麗，擇路晚雲愁。", "淡墨呻吟內，非萱可療憂。"]'),
('e546c62d-db0c-4110-8183-a2bc99c69f81','久不得潘髯書','李彭','宋','宋诗','song-poetry','','[]','八字山頭鴈，武昌江上魚。',48,'全唐诗/poet.song.80000.json','["八字山頭鴈，武昌江上魚。", "略無千里遠，不寄一行書。", "度鳥愈清曠，晴雲時卷舒。", "河陽應好在，有底苦相疏。"]'),
('57fa4362-dc55-4a25-8c23-381eee3d78e3','書龍壽寺煮泉亭壁  其一','李彭','宋','宋诗','song-poetry','','[]','病馬繫喬木，攜笻到上方。',48,'全唐诗/poet.song.80000.json','["病馬繫喬木，攜笻到上方。", "江花迷枉渚，野竹亂鳴榔。", "石竈懷桑苧，漥尊憶漫郎。", "吾生真寄傲，佛地欲深藏。"]'),
('350efff4-14ed-4a6b-b222-631b629e61bc','書龍壽寺煮泉亭壁  其二','李彭','宋','宋诗','song-poetry','','[]','客裏多岑寂，尋春興獨賖。',48,'全唐诗/poet.song.80000.json','["客裏多岑寂，尋春興獨賖。", "擎来妙喜葉，盡屬法王家。", "不見青鞋士，来煎黑面茶。", "幽懷在天末，落日更鳴鴉。"]'),
('f7f6b737-7b3c-4a9e-9740-cb2237e86b17','曇珠曇規二禪者歸湖外乞詩二首  其一','李彭','宋','宋诗','song-poetry','','[]','淑氣紛花藥，喧風樂鳥烏。',48,'全唐诗/poet.song.80000.json','["淑氣紛花藥，喧風樂鳥烏。", "山僧来訪別，稚子竟傳呼。", "噴玉渥洼種，行沙滄海珠。", "湘天多過雁，能寄尺書無。"]'),
('7fecb8a0-5417-471e-9160-b7ec6e721408','曇珠曇規二禪者歸湖外乞詩二首  其二','李彭','宋','宋诗','song-poetry','','[]','獨秀峰前見，林間憶語離。',48,'全唐诗/poet.song.80000.json','["獨秀峰前見，林間憶語離。", "游觀如昨夢，換謝若晨炊。", "柳絮飛千尺，殘陽隱半規。", "打包湖外去，探道就鉗搥。"]'),
('0c5b7bd6-ceca-4f82-ab48-dc9cf2884005','西塔','李彭','宋','宋诗','song-poetry','','[]','秋山何秀整，風磴頗崢嶸。',48,'全唐诗/poet.song.80000.json','["秋山何秀整，風磴頗崢嶸。", "寺古殘僧病，門深舊犬迎。", "崖蜂将割蜜，澗鳥自呼名。", "毳衲典刑在，蕭然物外情。"]'),
('e771c609-9cd3-499a-9139-f3d77d139b55','病起過鄰寺','李彭','宋','宋诗','song-poetry','','[]','慣作招提客，應非拖玉身。',48,'全唐诗/poet.song.80000.json','["慣作招提客，應非拖玉身。", "一年强半病，十畞未全貧。", "孝秀鄉閭盛，朝頒符瑞頻。", "不妨幽仄裏，高卧姓龐人。"]'),
('6965b249-ac96-4ff7-ab20-18f89c0aa378','封氏野老留飲看白兔是晚微雪','李彭','宋','宋诗','song-poetry','','[]','封老朱顔在，髯髯已白鬚。',48,'全唐诗/poet.song.80000.json','["封老朱顔在，髯髯已白鬚。", "酌醪招倦客，唤婦煮肥鱸。", "玉兔君家有，銀甖客舍無。", "醉餘看舞雪，未覺客情孤。"]'),
('c0bfc0f9-5c18-4f00-85c1-aa387ac6aff3','登無相絕頂舊有東坡題字今不復見','李彭','宋','宋诗','song-poetry','','[]','深雲蒙無相，斜日照崔嵬。',48,'全唐诗/poet.song.80000.json','["深雲蒙無相，斜日照崔嵬。", "慘澹天梯往，蒼茫地勢開。", "巾裾拂河漢，談話雜風雷。", "惆悵銀鈎處，歸来首重回。"]'),
('03c26a46-1cc3-498c-be04-eab03e05df1e','次九弟韻兼懷師川二首  其一','李彭','宋','宋诗','song-poetry','','[]','抱瘵便秋晚，加餐喜歲豐。',48,'全唐诗/poet.song.80000.json','["抱瘵便秋晚，加餐喜歲豐。", "幽懷烏鳥樂，世故馬牛風。", "坯戶寒蟲急，安巢野老同。", "年来百念冷，頓悟衆緣空。"]'),
('76f8f1ea-e39d-4362-b035-1e92d69c4700','次九弟韻兼懷師川二首  其二','李彭','宋','宋诗','song-poetry','','[]','雞回落雁渚，菊带傲霜華。',48,'全唐诗/poet.song.80000.json','["雞回落雁渚，菊带傲霜華。", "稍過郊墟雨，猶鳴官地蛙。", "層空聽隼擊，俯杖看蜂衙。", "妙趣誰能解，懷人天一涯。"]'),
('9543950b-b84e-4ca6-a538-8160ac959816','次文虎韻戲暉書記','李彭','宋','宋诗','song-poetry','','[]','孤舟泛湛水，心法已圜融。',48,'全唐诗/poet.song.80000.json','["孤舟泛湛水，心法已圜融。", "詩律期三昩，庵居役二空。", "住山須拙斧，閲世任寒蓬。", "慢着尋幽履，雪泥殊未通。"]'),
('a69627a5-1fd2-447e-8c36-f71e604f84c0','次九弟韻後篇戲奉世十一弟二首  其一','李彭','宋','宋诗','song-poetry','','[]','少成憐季子，拔俗似安豐。',48,'全唐诗/poet.song.80000.json','["少成憐季子，拔俗似安豐。", "逸氣期公幹，鈎深似國風。", "未須輕小伎，著意要參同。", "聊語詩家病，塵窗研滴空。"]'),
('e3008771-0d83-40a7-b46d-06e43c12d9c9','次九弟韻後篇戲奉世十一弟二首  其二','李彭','宋','宋诗','song-poetry','','[]','莫學中郎将，休懷陰麗華。',48,'全唐诗/poet.song.80000.json','["莫學中郎将，休懷陰麗華。", "三餘遊竹素，兩部有鳴蛙。", "乃肻親龐老，多情過押衙。", "吾衰那復此，羡爾樂無涯。"]'),
('91f41563-0049-4e56-8e66-2311b7da1284','戲贈','李彭','宋','宋诗','song-poetry','','[]','王謝風流在，星星映角巾。',48,'全唐诗/poet.song.80000.json','["王謝風流在，星星映角巾。", "屬文無少盡，結社有迂輪。", "頗作餐霞侣，願充觀國賓。", "徑須呼伯雅，且入醉鄉春。"]'),
('7752e720-8597-4f6b-845c-15025f7b5b29','贈鄒中美','李彭','宋','宋诗','song-poetry','','[]','盛漢數鄒陽，雲孫復擅場。',48,'全唐诗/poet.song.80000.json','["盛漢數鄒陽，雲孫復擅場。", "筍輿逢鹿苑，蠟屐繞羊膓。", "囊有壺公藥，爐多荀令香。", "麻姑在鄉國，期子共徜佯。"]'),
('f60e4d47-5bdd-49c0-959f-9f79c689bc32','贈暉書記暉有伯時所畫馬甚奇','李彭','宋','宋诗','song-poetry','','[]','脱盡膏粱氣，秖餘雲壑姿。',48,'全唐诗/poet.song.80000.json','["脱盡膏粱氣，秖餘雲壑姿。", "囊中支遁馬，筆下惠休詩。", "木末鳥還語，花邊蝶浪窺。", "平章賴公等，吾病不能奇。"]'),
('b4a8eac6-cd1e-416c-98c1-284a381909e2','聞官軍已臨賊境','李彭','宋','宋诗','song-poetry','','[]','聞道官軍至，戈鋋壓賊壕。',48,'全唐诗/poet.song.80000.json','["聞道官軍至，戈鋋壓賊壕。", "鼎魚猶未腐，穴兔竟何逃。", "鋭氣連全楚，皇恩貸爾曹。", "洗兵無復用，歡喜薦春醪。"]'),
('375079e4-208b-44e8-8e95-3baeb26b0d6a','次韻九弟遊雲居','李彭','宋','宋诗','song-poetry','','[]','禁足同僧夏，秋風倚杖前。',48,'全唐诗/poet.song.80000.json','["禁足同僧夏，秋風倚杖前。", "捫蘿懷鳥道，著屐到壺天。", "霜月懸崖腹，參旗落枕邊。", "營詩嗟錦盡，老語不須傳。"]'),
('bd00bc92-0c98-4912-9a1c-a3af92cd2fb6','夜坐聞櫓','李彭','宋','宋诗','song-poetry','','[]','日斜喧急雨，雨夜候蟲秋。',48,'全唐诗/poet.song.80000.json','["日斜喧急雨，雨夜候蟲秋。", "宴坐遊三昩，因人吟四愁。", "疏林月色好，別渚櫓聲幽。", "卻憶秦淮上，寒更渡小舟。"]'),
('020a5767-0609-4767-8601-f35ba74aaa6d','自雲居歸欲到瑶田作','李彭','宋','宋诗','song-poetry','','[]','稍上參雲漢，中藏祗樹園。',48,'全唐诗/poet.song.80000.json','["稍上參雲漢，中藏祗樹園。", "煙横迷遠嶼，鳥度失孤村。", "一嶺分晴雨，半山纔晏温。", "回頭聽梵唄，真是欲忘言。"]'),
('6e76d7f6-8ce0-4006-b528-c2950e2318c1','絕章水','李彭','宋','宋诗','song-poetry','','[]','春水静遊浪，晚吹怒生濤。',48,'全唐诗/poet.song.80000.json','["春水静遊浪，晚吹怒生濤。", "歸興催舟楫，驚魂寄桔橰。", "留髠忽忘故，訪戴敢辭勞。", "推挽柁師力，令人愧爾曹。"]'),
('eed658f3-a9bb-481b-8990-67b593960c78','哭李少微三首  其一','李彭','宋','宋诗','song-poetry','','[]','應劉玉山隕，之子尚璵璠。',48,'全唐诗/poet.song.80000.json','["應劉玉山隕，之子尚璵璠。", "未握論交臂，俄招去幹魂。", "茂陵有遺藁，健婦解持門。", "何日生芻奠，人琴恐或存。"]'),
('ce44d373-4a90-4d93-90fe-a17769a63861','哭李少微三首  其二','李彭','宋','宋诗','song-poetry','','[]','評闕汝南旦，窮嗟校尉途。',48,'全唐诗/poet.song.80000.json','["評闕汝南旦，窮嗟校尉途。", "故交非浪哭，吾道恐成孤。", "往在談文處，還能步屧無。", "秋風聊倚杖，草樹日疏蕪。"]'),
('ca7165d2-c348-4208-9045-22e4e251657c','哭李少微三首  其三','李彭','宋','宋诗','song-poetry','','[]','我客齊安歲，君官汾上春。',48,'全唐诗/poet.song.80000.json','["我客齊安歲，君官汾上春。", "安知瀕鬼錄，不作定交人。", "煬竈中郎滿，鬬雞開府頻。", "如何令王濟，清血染衣巾。"]'),
('866481e8-a321-4b67-9cd5-a233d677bd1e','次韻東坡五更山吐月  其一','李彭','宋','宋诗','song-poetry','','[]','一更山吐月，修木瑩澄瀾。',48,'全唐诗/poet.song.80000.json','["一更山吐月，修木瑩澄瀾。", "全勝西園夜，金覊带笑看。", "團欒照坐好，倚徙冰人寒。", "縹瓷傾竹葉，何必辦狼殘。"]'),
('d24884ed-0af5-4f93-8478-cb1172c86a09','次韻東坡五更山吐月  其二','李彭','宋','宋诗','song-poetry','','[]','二更山吐月，寂寂山家夜。',48,'全唐诗/poet.song.80000.json','["二更山吐月，寂寂山家夜。", "衰翁葆鬢濕，衡移復露下。", "泠泠泉可潄，冉冉雲可藉。", "相携塵外人，共說無生話。"]'),
('2bd51195-09d5-4020-92bc-9debddbd5795','次韻東坡五更山吐月  其三','李彭','宋','宋诗','song-poetry','','[]','三更山吐月，無睡客還起。',48,'全唐诗/poet.song.80000.json','["三更山吐月，無睡客還起。", "風微一鐸鳴，歷歷正談此。", "此身如傳舍，幽懷湛秋水。", "兹遊共昔遊，定非聊爾爾。"]'),
('85ca79c9-be4f-4581-9869-c9a43b8fb8c7','次韻東坡五更山吐月  其四','李彭','宋','宋诗','song-poetry','','[]','四更山吐月，月是故園明。',48,'全唐诗/poet.song.80000.json','["四更山吐月，月是故園明。", "三峡笙簧起，紫霄星斗横。", "林猿霜後嘯，山鬼夜深行。", "託宿耆闍寺，真遊王舍城。"]'),
('ec6eb62c-6642-4335-a39c-95ae1f94268f','次韻東坡五更山吐月  其五','李彭','宋','宋诗','song-poetry','','[]','五更山吐月，夢回人更幽。',48,'全唐诗/poet.song.80000.json','["五更山吐月，夢回人更幽。", "風来虎溪寺，江動庾公樓。", "雞唤楚江曙，河殘淮上秋。", "倚梧成短句，僅欲不勝謳。"]'),
('cae31d67-d68f-4187-947d-96a1636fdf06','不宿開先道中口占','李彭','宋','宋诗','song-poetry','','[]','穉菊含佳色，苔痕上老笻。',48,'全唐诗/poet.song.80000.json','["穉菊含佳色，苔痕上老笻。", "了山已埋玉，盧老自鳴鐘。", "但飲東溪水，休看雙劍峰。", "斜陽空翠合，猶聽隔溪舂。"]'),
('5c47baf5-f645-4588-9010-085d5134e376','雪','李彭','宋','宋诗','song-poetry','','[]','瑞木辭天漢，因風響觸楹。',48,'全唐诗/poet.song.80000.json','["瑞木辭天漢，因風響觸楹。", "光催曉雞誤，素失白鷴驚。", "冰柱隨門見，瑶林逐徑成。", "南州多癘鬼，藉汝勝鏖兵。"]'),
('19e6113b-eb05-467a-b235-ece954ffff66','王子張數以詩見過','李彭','宋','宋诗','song-poetry','','[]','午夢蠻花濕，晚凉衣带秋。',48,'全唐诗/poet.song.80000.json','["午夢蠻花濕，晚凉衣带秋。", "愁来倚柱嘯，詩到擊盤謳。", "律熟無誰敵，詞慳不擬酬。", "蘇州語猶在，五字爲君休。"]'),
('fc664707-89da-49a0-ad25-d417a4e59eaa','同雲叟遊歐峰','李彭','宋','宋诗','song-poetry','','[]','遠墅春辭木，空山晚著花。',48,'全唐诗/poet.song.80000.json','["遠墅春辭木，空山晚著花。", "幽懷生蠟屐，稍上問星槎。", "屢共普熏飯，仍烹圓夢茶。", "期君未衰白，爛漫飽煙霞。"]'),
('8269da0f-3975-4822-af1a-959c397bb428','書懷','李彭','宋','宋诗','song-poetry','','[]','未作終焉計，懷哉興不疏。',48,'全唐诗/poet.song.80000.json','["未作終焉計，懷哉興不疏。", "逢人問息耗，閲歲歎乘除。", "老境来顔面，歸家識此渠。", "攀緣俱斷絕，何暇羡嚴徐。"]'),
('ff0bc89f-f28a-49e1-b3c1-c2038effd48b','遊石鏡溪','李彭','宋','宋诗','song-poetry','','[]','石鏡溪邊樹，金輪峰上雲。',48,'全唐诗/poet.song.80000.json','["石鏡溪邊樹，金輪峰上雲。", "貪看魚弄影，不覺鳥迷曛。", "山態迤迤好，泉聲細細分。", "銀鈎懷柱史，誰復振斯文。"]'),
('f29b17ed-78f8-4d4c-b01f-fb01a0b29f75','懷秦處度','李彭','宋','宋诗','song-poetry','','[]','淮海紫髯叟，長吟獨倚風。',48,'全唐诗/poet.song.80000.json','["淮海紫髯叟，長吟獨倚風。", "稍将芸辟蠹，應罷手書空。", "拄策舊寒澗，含毫餘老松。", "觀雲毎悵望，苦念小安豐。"]'),
('6c62597a-5253-42ca-b696-f7826266355a','留題壁間','李彭','宋','宋诗','song-poetry','','[]','遠意在丘壑，籃輿同此尋。',48,'全唐诗/poet.song.80000.json','["遠意在丘壑，籃輿同此尋。", "干雲絕壁秀，落澗幽泉音。", "卷祴盡開士，聽法多珍禽。", "煙横半峰暝，信是忘歸心。"]'),
('b84e69df-3362-4b03-9566-88f00969f379','過蘄州故居','李彭','宋','宋诗','song-poetry','','[]','繫馬金沙樹，衡茅儼暝途。',48,'全唐诗/poet.song.80000.json','["繫馬金沙樹，衡茅儼暝途。", "沾襟問鄰老，携手憶於菟。", "意逐前雲遠，情隨歸路迂。", "霜風吹曉角，夢聽小單于。"]'),
('c92d6ca2-52c2-4f26-9050-0c323a968063','寄文若','李彭','宋','宋诗','song-poetry','','[]','仲氏客淮上，蓬窗憶聚星。',48,'全唐诗/poet.song.80000.json','["仲氏客淮上，蓬窗憶聚星。", "雲從望中密，雨逐去邊零。", "赤壁念存沒，怡亭幾醉醒。", "歸歟勤著腳，莫負讀書螢。"]'),
('56c39751-988e-44cc-b0a3-a9ec81500618','用韋蘇州神静師院韻寄微公','李彭','宋','宋诗','song-poetry','','[]','雲卧衣裳冷，巖幽鐘磬微。',48,'全唐诗/poet.song.80000.json','["雲卧衣裳冷，巖幽鐘磬微。", "秋蟲留霧牖，夕鳥下煙扉。", "無人瀹茗椀，坐我語斜暉。", "分携復經歲，長嗟志願違。"]'),
('a0f67a85-9745-4915-b7fc-f16a39030851','将到九江先寄王環中','李彭','宋','宋诗','song-poetry','','[]','鹿門真大隱，不減遠人村。',48,'全唐诗/poet.song.80000.json','["鹿門真大隱，不減遠人村。", "淨供維摩室，鄰居祗樹園。", "秦淮揮別淚，楚岸倒芳樽。", "牢落還相見，定能顔色温。"]'),
('b72716be-a613-4e2a-915a-243348741f87','新篘濁醪味嚴勁飲數盞大醉醉中作此詩','李彭','宋','宋诗','song-poetry','','[]','我生憐麴蘖，剛置自中年。',48,'全唐诗/poet.song.80000.json','["我生憐麴蘖，剛置自中年。", "破屋鳴春溜，陰崖響夜泉。", "興来猶味著，飲罷剩狂顛。", "但病無風韻，聊堪栩栩眠。"]'),
('fa524dd3-0476-4e4a-bee2-4f3e7d5ab173','佚老堂爲柳仲輝題','李彭','宋','宋诗','song-poetry','','[]','小隱寄巖谷，堂成笑傲中。',48,'全唐诗/poet.song.80000.json','["小隱寄巖谷，堂成笑傲中。", "雖無黄閣相，不羡黑頭翁。", "倚杖鷗邊雨，營詩鴈背風。", "好閑多病處，清興略相同。"]'),
('57abc9a1-b0e8-4948-854f-7f220b816874','自寶峰還過長坑澗谷勝絕處','李彭','宋','宋诗','song-poetry','','[]','㶁㶁水循澗，悠悠山放雲。',48,'全唐诗/poet.song.80000.json','["㶁㶁水循澗，悠悠山放雲。", "關河元未遠，境界有誰分。", "幽樹花無賴，輕鷗聲念羣。", "箇中須著句，傳與世間聞。"]'),
('b82207eb-e0c0-47e5-90b7-57bbe2831f3e','蓺玉軒','李彭','宋','宋诗','song-poetry','','[]','短李江南秀，虬鬚讓帝孫。',48,'全唐诗/poet.song.80000.json','["短李江南秀，虬鬚讓帝孫。", "開懷仍好客，愛畫復堪論。", "蓺玉風煙外，藍溪氣象存。", "他年多結綠，會看有乘軒。"]'),
('69408a08-c335-470d-a6a8-00f991cb2b1a','豫章董瞿老求詩','李彭','宋','宋诗','song-poetry','','[]','珍重膠西相，風流後葉孫。',48,'全唐诗/poet.song.80000.json','["珍重膠西相，風流後葉孫。", "退藏羞射策，曠遠頗窺園。", "韻絕五峰秀，句奇三峡喧。", "羌山多勝踐，周禮魯俱存。"]'),
('76047340-c857-4248-81bf-24dd0a9a090b','漫書','李彭','宋','宋诗','song-poetry','','[]','歐峰秋色外，一上一回高。',48,'全唐诗/poet.song.80000.json','["歐峰秋色外，一上一回高。", "踐華誰云險，捫參未覺勞。", "雲扉留野客，霧牖卧方袍。", "拄頬非吾事，何須似馬曹。"]'),
('3f03af14-32b8-4307-a8e2-02dc54c136fd','錢盱眙赴上因乞詩','李彭','宋','宋诗','song-poetry','','[]','君自金張侣，從予嵇阮遊。',48,'全唐诗/poet.song.80000.json','["君自金張侣，從予嵇阮遊。", "祗園分客袂，星渚繫歸舟。", "楚國煙霞晚，隋河榆柳秋。", "中州多汲引，行矣亦封侯。"]'),
('e241766a-73e4-44d0-b163-4db75428de1b','次瑛上人韻','李彭','宋','宋诗','song-poetry','','[]','鼻祖真消息，風流出當家。',48,'全唐诗/poet.song.80000.json','["鼻祖真消息，風流出當家。", "觀門親杜順，蹙指悟玄沙。", "顧我晚聞道，參同今未涯。", "懸知飲光笑，初不爲拈花。"]'),
('bd3b2400-f1e1-4591-a97d-4b83adbc19ce','題吴少馮聽雨堂','李彭','宋','宋诗','song-poetry','','[]','碧澗寒侵屋，幽雲夜度墻。',48,'全唐诗/poet.song.80000.json','["碧澗寒侵屋，幽雲夜度墻。", "貪看山入坐，慣聽雨鳴廊。", "苦乏陰鏗句，聊登孺子床。", "君非無汲引，寄傲學潛郎。"]'),
('5028f33f-0efa-4ca3-a851-c5e5598b2fdb','喜得京師書信','李彭','宋','宋诗','song-poetry','','[]','簷間噪烏鵲，窗下集邕渠。',48,'全唐诗/poet.song.80000.json','["簷間噪烏鵲，窗下集邕渠。", "喜有大梁使，能携小陸書。", "南烹飽薇蕨，北饌到庭除。", "得雋傳消息，更看雙鯉魚。"]'),
('e54d8999-7490-4897-a45c-8081626fc7fe','追凉對酒','李彭','宋','宋诗','song-poetry','','[]','袢暑晚来歇，追凉聊解顔。',48,'全唐诗/poet.song.80000.json','["袢暑晚来歇，追凉聊解顔。", "星移團扇底，月動縹瓷間。", "蟬噪斷仍續，鳥喧棲復還。", "幽人嗜清曠，只合卧湖山。"]'),
('a9d7f1fa-099e-466b-9e4f-1be4a7f8e651','上黄太史魯直詩','李彭','宋','宋诗','song-poetry','','[]','扈聖當元祐，雄名獨擅長。',288,'全唐诗/poet.song.80000.json','["扈聖當元祐，雄名獨擅長。", "羣公調玉燭，延閣近扶桑。", "揮灑驚雷雨，觀瞻列堵墻。", "密雲来北苑，珍菓出明光。", "柱下惟青史，銀臺無露章。", "胡爲隨逐客，不作瑞齋房。", "岑寂金華省，蕭條玉筍行。", "長庚萬里去，大雅百夫望。", "老覺丹心壯，閑知清畫長。", "珍蔬時入饌，荔子喜傳芳。", "世故跏趺遠，生涯嘯傲傍。", "甘爲劍外客，誰念太官羊。", "宣室二天詔，遺弓萬國傷。", "老臣還召畢，陛下過成康。", "澤笏皆忠讜，彈冠多俊良。", "力辭佳吏部，直作老潛郎。", "憶在金華日，寧扶八座床。", "未能窺絳帳，頗識戲羅囊。", "候雁隨陽去，奔駒度隙忙。", "千秋銅狄泣，萬古玉人藏。", "諸阮釁猶在，蘄春痛未央。", "羣雛極鵝雁，衆口歎蛩螀。", "恨乏一廛地，歸来屢擇鄉。", "親交標鬼錄，卜築近僧坊。"]'),
('81e41027-4ecc-4640-98e4-b673dadbc467','觀畫山水','李彭','宋','宋诗','song-poetry','','[]','不愛邊鸞愛李成，胸中成畫自峥嶸。',64,'全唐诗/poet.song.80000.json','["不愛邊鸞愛李成，胸中成畫自峥嶸。", "數行島嶼隨人去，一段風煙向腕生。", "猨啼巫峡殷勤嘯，雁到衡陽嘹唳鳴。", "我與羣山成保社，直疑俱是舊經行。"]'),
('b38dedbf-213b-405f-aaae-e50b7ede145a','遠明閣飲','李彭','宋','宋诗','song-poetry','','[]','百尺遊絲入座来，浮嵐空翠入樽罍。',64,'全唐诗/poet.song.80000.json','["百尺遊絲入座来，浮嵐空翠入樽罍。", "談諧自得江山助，觴詠不勞絲管催。", "滕閣風流今未遠，南樓氣味唤仍回。", "城鴉欲曙衆客醉，木末闌干懸斗魁。"]'),
('fabd2794-afc2-472a-ada0-1727caa91c07','城上','李彭','宋','宋诗','song-poetry','','[]','城上棲烏尾畢逋，寒塘烏影過相呼。',64,'全唐诗/poet.song.80000.json','["城上棲烏尾畢逋，寒塘烏影過相呼。", "一天欲放山陰雪，六幅如觀栗里圖。", "問老自應師粲忍，扶衰初喜得封胡。", "香醪已熟糟床注，唤客無勞滿眼酤。"]'),
('6fd89181-81b3-4b0e-967a-67a9185739c8','宿萬松兼示慶首座','李彭','宋','宋诗','song-poetry','','[]','步屧欣逢釋梵宫，餘霞尚带日歸紅。',64,'全唐诗/poet.song.80000.json','["步屧欣逢釋梵宫，餘霞尚带日歸紅。", "峰前晚靄晚来積，岫外秋天秋滿空。", "獨鳥深藏欹牖樹，幽花香逐下山風。", "青燈耿耿照無睡，賴有能詩老贊公。"]'),
('0ba29b94-bd94-4b09-bf49-84143259d6f6','鄒天錫見過','李彭','宋','宋诗','song-poetry','','[]','議郎梁獄坐口語，置散投閒今放回。',64,'全唐诗/poet.song.80000.json','["議郎梁獄坐口語，置散投閒今放回。", "令節由来迫吹帽，幽園尋勝獨登臺。", "共歌昭代得銀甕，何暇著書名玉杯。", "此口惟堪飲醇酎，人間萬事要寒灰。"]'),
('9de13e03-8c3f-451e-8fc1-b759e89aefa4','次駒父遊孺子亭韻','李彭','宋','宋诗','song-poetry','','[]','平居懶與慢相親，寄傲行歌似隱淪。',64,'全唐诗/poet.song.80000.json','["平居懶與慢相親，寄傲行歌似隱淪。", "水退荷花饑殘暑，秋来山色挽幽人。", "從雌鸂鶒窺黄帽，旁母鳬雛映白蘋。", "興罷歸来去高卧，詩成聊復寄雷陳。"]'),
('4b0465ff-f64c-4e16-b065-4ae937a10583','余久不飲酒偶飲殊適因和九弟韻','李彭','宋','宋诗','song-poetry','','[]','年侵畏病酒尊空，矧復聽歌盛小叢。',64,'全唐诗/poet.song.80000.json','["年侵畏病酒尊空，矧復聽歌盛小叢。", "煙際鳥呼雲際雨，花邊蝶舞柳邊風。", "向来懷抱愁眉外，今日懽娱醉眼中。", "何用花奴鳴羯鼓，新詩解穢思無窮。"]'),
('023ae75e-8190-4a77-801a-bb0d77753acc','遊雲居三首  其一','李彭','宋','宋诗','song-poetry','','[]','山林投老更疏慵，尚有躋攀興不窮。',64,'全唐诗/poet.song.80000.json','["山林投老更疏慵，尚有躋攀興不窮。", "絕壑久忘蛇起陸，寒窗聊食雁来紅。", "人方嵇阮似無愧，詩比陰何或未工。", "永夜不眠茶作祟，一燈明暗鳥呼風。"]'),
('43660110-287e-4fb6-8a4a-c165f6d616a3','遊雲居三首  其二','李彭','宋','宋诗','song-poetry','','[]','故歲新芽約略黄，重来敗葉带飛霜。',64,'全唐诗/poet.song.80000.json','["故歲新芽約略黄，重来敗葉带飛霜。", "尋幽少脱塵勞夢，訪舊頗熏知見香。", "深谷鳴鐘雲暗淡，半峰斜照樹微茫。", "去天尺五今應是，璧月珠星掛上方。"]'),
('46faf24f-63ff-4b7d-a023-53b36f1ee54b','遊雲居三首  其三','李彭','宋','宋诗','song-poetry','','[]','羣峰羅立紫崔嵬，無復市聲蚊聚雷。',64,'全唐诗/poet.song.80000.json','["羣峰羅立紫崔嵬，無復市聲蚊聚雷。", "遠嶠雲屯飛鳥沒，寒江煙斂健帆開。", "暖眠犢子陽關草，香逐蜂鬚陰谷梅。", "散策捫蘿覓歸路，摩挲蒼石更裵回。"]'),
('c6b56136-621f-409d-a372-bb7ab30cd548','次韻答董彦速','李彭','宋','宋诗','song-poetry','','[]','疏山翠氣連眉嫵，雲外飛鴻點點愁。',64,'全唐诗/poet.song.80000.json','["疏山翠氣連眉嫵，雲外飛鴻點點愁。", "只在吴頭并楚尾，非關張掖至幽州。", "著書繁露想成癖，待詔公車安足求。", "何日芒鞵尋舊約，蘭旌蓀楫共優遊。"]'),
('e848c94b-dd49-4725-a02a-28cc439ecd7b','過鵝湖懷師川','李彭','宋','宋诗','song-poetry','','[]','寶峰嶔﨑青未了，枕下灘聲走白沙。',64,'全唐诗/poet.song.80000.json','["寶峰嶔﨑青未了，枕下灘聲走白沙。", "谷口不應無小隱，桃源真恐有人家。", "寒猨飲水避帆影，槁葉隨波上槳牙。", "苦憶南州徐孺子，歸舟天際暮雲遮。"]'),
('8c765080-00d4-4e42-8acf-a73279bce5d0','春夜奉懷蘇仲豫次陳無己韻贈仲豫','李彭','宋','宋诗','song-poetry','','[]','雲外頭陀是去年，已看汀草漲晴川。',64,'全唐诗/poet.song.80000.json','["雲外頭陀是去年，已看汀草漲晴川。", "夢中未覺關河遠，枕底忽聞鐘鼓傳。", "但可馬曹聊拄頬，看渠鳯閣競加鞭。", "蓬窗想得司春甕，一夜糟床酒注泉。"]'),
('082b82d9-cfb9-4e5a-bff4-616c89267dad','春日懷秦髯','李彭','宋','宋诗','song-poetry','','[]','山雨蕭蕭作快晴，郊園物物近清明。',64,'全唐诗/poet.song.80000.json','["山雨蕭蕭作快晴，郊園物物近清明。", "花如解語迎人笑，草不知名隨意生。", "晚節漸於春事懶，病軀却怕酒壺傾。", "睡餘若憶舊交友，應在日邊聽曉鶯。"]'),
('6e050488-f793-434f-a547-d68690a9d95b','季敵檢校南村田','李彭','宋','宋诗','song-poetry','','[]','風吹䆉稏半傳黄，凖擬中厨雲子香。',64,'全唐诗/poet.song.80000.json','["風吹䆉稏半傳黄，凖擬中厨雲子香。", "潮水忽生添野水，山光便可接湖光。", "難求塵外餐霞侣，未試囊中辟穀方。", "徑遣阿連聊檢校，饑雷已復殷枯膓。"]'),
('ee368cf8-7559-448d-8b09-eb378a16428a','自豫章歸書齋題壁','李彭','宋','宋诗','song-poetry','','[]','鳥烏聲樂客還家，僮僕懽迎日未斜。',64,'全唐诗/poet.song.80000.json','["鳥烏聲樂客還家，僮僕懽迎日未斜。", "小徑潛筠新長筍，幽齋茂樹晚多花。", "深慚麯蘖留春住，尚覺年顔老去賖。", "出處由来非細事，弄泉莫忘飽煙霞。"]'),
('b94c2064-e384-47ee-9db8-ec395b259ee7','泮宫曝書恭覽御書故事行鄉飲酒禮諸老率諸生皆在楊先生病足獨不至賦詩見寄次韻答之','李彭','宋','宋诗','song-poetry','','[]','雲漢昭回泮水邊，諸生拜舞鱣堂前。',64,'全唐诗/poet.song.80000.json','["雲漢昭回泮水邊，諸生拜舞鱣堂前。", "老翁七十荷衣綠，弟子三千桂魄圓。", "樂正足傷何必慮，伏生口授尚能傳。", "墨池載酒容他日，門外侯芭也可憐。"]'),
('0616666a-4914-4620-bb65-a995c50c2a39','寒食日','李彭','宋','宋诗','song-poetry','','[]','幽人衣带病餘寬，終日蕭然懶正冠。',64,'全唐诗/poet.song.80000.json','["幽人衣带病餘寬，終日蕭然懶正冠。", "柳絮野鶯春向晚，榆羮杏粥食猶寒。", "倦於杯杓生新興，頻有鄰儀救老殘。", "試把一尊招近友，放歌聊復罄交懽。"]'),
('3ed74533-8ba7-4a03-85f3-4510111a5f08','李成德求迺翁挽詩','李彭','宋','宋诗','song-poetry','','[]','養疴丘壑玩寒藤，領略雞園最上乘。',64,'全唐诗/poet.song.80000.json','["養疴丘壑玩寒藤，領略雞園最上乘。", "射虎已驚生李廣，登龍行復見元膺。", "九原煙雨悲埋玉，一代功名定伐冰。", "安得董狐南史筆，發揚潛德到雲仍。"]'),
('57024242-d0df-47c4-9829-f54422b833bd','戲次居仁見寄韻','李彭','宋','宋诗','song-poetry','','[]','長蘆老人半聖號，眉毛不惜爲談空。',64,'全唐诗/poet.song.80000.json','["長蘆老人半聖號，眉毛不惜爲談空。", "靜委耽禪如縛律，懸知選佛勝封公。", "影沉寒水雁無意，春入幽園花自紅。", "欲向池陽參百問，却慚勾賊亂家風。"]'),
('d8e658b6-182d-4736-b4d6-4ab50d93dfb8','寄如壁上人','李彭','宋','宋诗','song-poetry','','[]','平生剛直隱長虹，收卷波瀾說苦空。',64,'全唐诗/poet.song.80000.json','["平生剛直隱長虹，收卷波瀾說苦空。", "翰墨場中無李廣，苾蒭園裏有支公。", "未應雪浪侵頭白，想見丹砂入頬紅。", "驄馬他年焚諫草，看君妙手試宗風。"]'),
('bcd50a3e-9faf-4f8e-b211-c8422346627b','次韻寄居仁二弟','李彭','宋','宋诗','song-poetry','','[]','老覺餘生如過鳥，何寧留迹寄長空。',64,'全唐诗/poet.song.80000.json','["老覺餘生如過鳥，何寧留迹寄長空。", "一丘一壑應還我，三沐三薰盡付公。", "病懶自知玄尚白，醉餘貪看碧成紅。", "荀家兄弟俱奇絕，時聽淮南好國風。"]'),
('a7804fea-6fea-4d3c-a28a-fbfb455f32d1','次韻寄山伯蕭老二弟','李彭','宋','宋诗','song-poetry','','[]','平原翁仲草蒙茸，種竹當年語竟空。',64,'全唐诗/poet.song.80000.json','["平原翁仲草蒙茸，種竹當年語竟空。", "羣從嗟予真漫叟，象賢期女繼汧公。", "別来江草唤愁碧，書到山陰稱意紅。", "瘞鶴銀鈎光照坐，行書正欲乞楊風。"]'),
('29ebef04-6398-419d-8569-38eb2887fee8','卜居','李彭','宋','宋诗','song-poetry','','[]','有宅一區聊解嘲，清風歷歷自鳴瓢。',64,'全唐诗/poet.song.80000.json','["有宅一區聊解嘲，清風歷歷自鳴瓢。", "買山作隱吾無取，爲黍殺雞何用招。", "魚托么荷障斜日，籜隨新竹上層霄。", "箇中已了一生事，倒屣安能求度遼。"]'),
('a820014e-b472-48e3-a612-b5db39f8b77b','寄劉壯輿将赴唐州儀曹','李彭','宋','宋诗','song-poetry','','[]','五柳先生同舊科，壺觴終日盼庭柯。',64,'全唐诗/poet.song.80000.json','["五柳先生同舊科，壺觴終日盼庭柯。", "一行作吏事皆廢，三徑就荒君若何。", "問字有誰堪載酒，談經許我或操戈。", "平生獨自賞音者，聽此殷勤勞者歌。"]'),
('07e12f54-c54b-4423-b324-a7045ae876a2','奉贈瑛明發','李彭','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','上人霜鶻氣横秋，法界重重幻筆頭。',64,'全唐诗/poet.song.80000.json','["上人霜鶻氣横秋，法界重重幻筆頭。", "已泛毗盧真覺海，戲裁佳句比湯休。", "雲開鶴嶺露蘭若，波起洞庭霜橘洲。", "華髪蕭騷瀕老境，多情猿鳥替人愁。"]'),
('05c452bd-9a2f-4e8e-99dd-8805869b766c','駒父次予舊韻見貽復次韻','李彭','宋','宋诗','song-poetry','','[]','玉人皮裏有陽秋，句入丹青顧虎頭。',64,'全唐诗/poet.song.80000.json','["玉人皮裏有陽秋，句入丹青顧虎頭。", "壓倒何勞譏陸陸，老衰得懶欲休休。", "支牀夢破嚴城角，决眥風回落雁洲。", "遣興竟須桑落酒，談間莫著畔牢愁。"]'),
('9b1f1231-9cf0-4eae-aa30-786ad14276fb','用韻戲呈仲誠','李彭','宋','宋诗','song-poetry','','[]','蒲萄政復得凉州，底事微官章水頭。',64,'全唐诗/poet.song.80000.json','["蒲萄政復得凉州，底事微官章水頭。", "早歲已能交北海，高懷乃肯顧韓休。", "手妙他時掃銀夏，胸蟠佳處協滄州。", "誰言京兆畫眉嫵，後院懸知多莫愁。"]'),
('b0110ece-d2d8-4b4a-9889-9c434b610277','寄何斯舉','李彭','宋','宋诗','song-poetry','','[]','傳詩句句爛生光，妙手殷紅入象床。',64,'全唐诗/poet.song.80000.json','["傳詩句句爛生光，妙手殷紅入象床。", "本自奉常參定脉，定從儋耳悟神方。", "玉花自合歸天廐，黄鵠應須下建章。", "見說年来真欲隱，轉身一路直須强。"]'),
('21d9a3e5-f5d4-4928-bfa2-df13fb7319d0','寄張聖源','李彭','宋','宋诗','song-poetry','','[]','豪氣向来回萬牛，筆端衮衮楚江流。',64,'全唐诗/poet.song.80000.json','["豪氣向来回萬牛，筆端衮衮楚江流。", "拾遺已見傳三賦，平子不應吟四愁。", "柱後許時淹闊步，石渠看即副旁求。", "老夫病著蒼崖底，細和堯民擊壤謳。"]'),
('f633fea4-3615-445b-a7ea-86d7c60e781e','還家寄吴世長兼簡潘子真','李彭','宋','宋诗','song-poetry','','[]','江頭楊柳麴塵姿，弄日晴空百尺絲。',64,'全唐诗/poet.song.80000.json','["江頭楊柳麴塵姿，弄日晴空百尺絲。", "騎省風流還有賦，吴筠英妙更能詩。", "殺雞爲黍相期處，問雁呼卿政此時。", "下榻深慚徐孺子，非關勞者作歌辭。"]'),
('56803fe7-46f1-4604-ac98-45c73624eaf7','贈九峰長老','李彭','宋','宋诗','song-poetry','','[]','已透韶陽向上關，蔬盂茗椀毎開顔。',64,'全唐诗/poet.song.80000.json','["已透韶陽向上關，蔬盂茗椀毎開顔。", "頭顱無意掃殘雪，毳衲徒来着壞山。", "瘦節直疑青嶂立，道心常與白鷗閑。", "歸来天末一回首，應在孤峰煙靄間。"]'),
('5a7e5990-f0e2-4e31-91d8-9d17d61d12aa','次韻答寶峰仁書記','李彭','宋','宋诗','song-poetry','','[]','袖手脱鞋悲太白，搴旗縛敵笑光顔。',64,'全唐诗/poet.song.80000.json','["袖手脱鞋悲太白，搴旗縛敵笑光顔。", "自知日面與月面，莫問南山與北山。", "獨秀峰前雲不隔，蓮花洲下水長閒。", "還鄉一曲真奇絕，與子終朝談笑間。"]'),
('3394653d-0a9c-487c-8203-13b16ceafd7b','寄撫州謝幼槃','李彭','宋','宋诗','song-poetry','','[]','別去鷓鴣思日寒，書来鵯鵊語林端。',64,'全唐诗/poet.song.80000.json','["別去鷓鴣思日寒，書来鵯鵊語林端。", "我懷求仲徑方掃，君向山陰興已闌。", "細讀清詩如艶雪，何時痛飲劇奔湍。", "懸知作草非賣菜，要自心期禮數寬。"]'),
('0f1cd95f-9cac-4fab-9e10-5ed7fd7c0f8e','賦高明大使神功妙濟真君祠','李彭','宋','宋诗','song-poetry','','[]','楊柳江頭星宿疏，呼船梢子散林烏。',64,'全唐诗/poet.song.80000.json','["楊柳江頭星宿疏，呼船梢子散林烏。", "煙横雲捲樹出沒，天澹波平山有無。", "稚子摠參三洞籙，病軀長佩五靈符。", "步虚聲裏瞻風馬，頗覺神清到蘂珠。"]'),
('09e9f000-f5c0-480a-a439-d3c9c67dd54c','代虚中作','李彭','宋','宋诗','song-poetry','','[]','曉悟無生貝葉經，起宗真喜得人英。',64,'全唐诗/poet.song.80000.json','["曉悟無生貝葉經，起宗真喜得人英。", "風流定自壓全楚，文物由来繼兩京。", "謝傳平生處華屋，滕公俄忽掩佳城。", "哀榮贈典他年在，翁仲何知淚滿纓。"]'),
('c878c5e0-8edf-493d-8625-8dd120495f6a','聽王散人琴','李彭','宋','宋诗','song-poetry','','[]','花邊猶舞舊時蝶，屋角還鳴他日禽。',64,'全唐诗/poet.song.80000.json','["花邊猶舞舊時蝶，屋角還鳴他日禽。", "但訝鏡中顔色改，詎知門外歲華侵。", "一杯相屬步兵酒，三疊共聽中散琴。", "有慨余懷聊復寫，雨餘汀草自青深。"]'),
('aa17ef24-82f6-4244-bdd1-db801c424e8c','南至','李彭','宋','宋诗','song-poetry','','[]','鄰雞戒曉暮鐘催，老境俱從裏許来。',64,'全唐诗/poet.song.80000.json','["鄰雞戒曉暮鐘催，老境俱從裏許来。", "但喜書雲占嗣歲，詎知緹室暗飛灰。", "和風欲上千門柳，協氣先傳五嶺梅。", "弟勸兄酬真樂事，燈前細酌莫停杯。"]'),
('8dbdbc24-b188-4231-a398-3d56932794b7','葺茅屋戲成','李彭','宋','宋诗','song-poetry','','[]','朔風卷我屋間茅，烏鵲含将去作巢。',64,'全唐诗/poet.song.80000.json','["朔風卷我屋間茅，烏鵲含将去作巢。", "執扑鳩工課奴客，巡簷長嘯望江郊。", "謝公五畞似能保，揚子一區聊解嘲。", "欲學參謀懷廣厦，苦無鳯觜續弦膠。"]'),
('8ca0c208-5f38-4cf2-a4f1-e7ea6089a2c3','鷄冠','李彭','宋','宋诗','song-poetry','','[]','景純機上爲裁剪，淺碧深藏稱意紅。',64,'全唐诗/poet.song.80000.json','["景純機上爲裁剪，淺碧深藏稱意紅。", "要與飛鴻同保社，肻隨凡鳥在樊籠。", "鳴堦鼓翼何勞爾，介羽登場略未工。", "赤幘漫多安足數，尸鄉反笑祝雞翁。"]'),
('b1600b63-16cb-4cf2-9acc-333ec39f4263','七夕用東坡韻','李彭','宋','宋诗','song-poetry','','[]','老火微微迹已陳，稚金稍稍欲親人。',64,'全唐诗/poet.song.80000.json','["老火微微迹已陳，稚金稍稍欲親人。", "蛛絲曲綴當時態，舊葉頻澆見在身。", "女隸不堪嚴侍立，天孫誰識靚粧新。", "柳州太巧何須乞，憐汝題詩正角巾。"]'),
('a0c88dca-868e-4ed9-8220-5ee1f2df3e25','早發開先入城至中道親舊約予復還薄晚復自歸宗入郡中','李彭','宋','宋诗','song-poetry','','[]','細聽㶁㶁水流澗，静看悠悠山放雲。',64,'全唐诗/poet.song.80000.json','["細聽㶁㶁水流澗，静看悠悠山放雲。", "澗底遊魚隨葉下，巖間獨樹藉雲分。", "殘星已發招隱寺，落日願仾耶舍墳。", "却背孤村入城市，沙邊深愧白鷗羣。"]'),
('f7e7cf85-df4b-42aa-bfaf-e4c0bdfa46a2','過廣濟','李彭','宋','宋诗','song-poetry','','[]','不到梅川已十年，市橋官柳尚依然。',64,'全唐诗/poet.song.80000.json','["不到梅川已十年，市橋官柳尚依然。", "追尋耆舊知誰在，觸撥清愁不欲眠。", "蘭若霜鐘猶唤睡，平陽宰木上參天。", "倦遊客子心無際，眼盡崗原起暮煙。"]'),
('62c235b4-ecb4-4558-8987-30b577aa7224','種仙茅','李彭','宋','宋诗','song-poetry','','[]','聞說仙茅勝鍾乳，移根遠自西山阿。',64,'全唐诗/poet.song.80000.json','["聞說仙茅勝鍾乳，移根遠自西山阿。", "豈獨客来塵意少，更覺夜眠幽氣多。", "避謗何須求薏苡，去家不減食藦蘿。", "候門稚子成羣後，矍鑠仍看馬伏波。"]'),
('962bb244-2b91-40b9-b63e-9b5f5defd988','王子張以詩見報次其韻','李彭','宋','宋诗','song-poetry','','[]','卧看雲生舍北籬，起来臨鏡慰衰遲。',64,'全唐诗/poet.song.80000.json','["卧看雲生舍北籬，起来臨鏡慰衰遲。", "欲投未落鶴盤嶼，将去還留鵲遶枝。", "天上漢庭勞夢寐，嶠南殷鑒恐覊縻。", "藍田丘壑仍孫在，勝日勤来賦好詩。"]'),
('56a17614-be13-43fc-9181-93d3a7214a97','七夕懷徐十用去年所賦東坡清凉韻','李彭','宋','宋诗','song-poetry','','[]','幽人喜雨静無塵，雨罷幽蟲料理人。',64,'全唐诗/poet.song.80000.json','["幽人喜雨静無塵，雨罷幽蟲料理人。", "顧我維摩方卧病，憶君徐稚是前身。", "鐘鳴祗樹年華隔，潮上吳江月色新。", "共看牽牛渡河漢，月殘露脚濕綸巾。"]'),
('6f911e96-79da-4747-8d4e-8a9afee348c5','戲次人韻','李彭','宋','宋诗','song-poetry','','[]','人言鼓吹来詩思，鳴鶴遂聞長阜音。',64,'全唐诗/poet.song.80000.json','["人言鼓吹来詩思，鳴鶴遂聞長阜音。", "細讀一犁新句好，始知三語用功深。", "自甘散木傲霜節，懶作幽雲出岫心。", "茗盌爐芬清晝永，流鶯捎蝶過墻陰。"]'),
('40b6e92b-e6f0-4e61-8fc0-49bcf9daf267','送果上人坐兜率夏','李彭','宋','宋诗','song-poetry','','[]','落絮霏霏攪客心，鳴鳩歷歷唤春陰。',64,'全唐诗/poet.song.80000.json','["落絮霏霏攪客心，鳴鳩歷歷唤春陰。", "未於蓮社添宗炳，已向蘭亭減道林。", "遠嶠煙横鐘磬晚，禪天目斷薜蘿深。", "詩緣酒廢苦無思，爲子送将聊一吟。"]'),
('3c4220de-161a-47aa-87dc-48808fbd4447','舟中次珍書記韻','李彭','宋','宋诗','song-poetry','','[]','沙頭作別數峰暝，意逐屯雲愁晏陰。',64,'全唐诗/poet.song.80000.json','["沙頭作別數峰暝，意逐屯雲愁晏陰。", "雨打船篷藏枉渚，鐘殘客夢憶禪林。", "山重水複歸棹遠，魚躍鷺飛寒葦深。", "何日支郎訪玄度，倚松停策伴微吟。"]'),
('5a6921b7-69de-4a22-a802-1660a3992e68','用師川題駒甫詩卷後韻','李彭','宋','宋诗','song-poetry','','[]','夢中逐客幻中歸，荆楚甌閩好賦詩。',64,'全唐诗/poet.song.80000.json','["夢中逐客幻中歸，荆楚甌閩好賦詩。", "誰謂涪翁呼不起，細看宅相力能追。", "太冲文價輕皇甫，籍也辭源怯退之。", "丘壑同盟從已定，莫令鬼祟作愁眉。"]'),
('3304d69a-7f29-4c85-b644-044f9b9bf489','即事','李彭','宋','宋诗','song-poetry','','[]','槐火煎茶氣味新，東園肯讓兔園春。',64,'全唐诗/poet.song.80000.json','["槐火煎茶氣味新，東園肯讓兔園春。", "鳥摧穠李霑衣袂，蝶遶夭桃傍鬢唇。", "迴策如縈峻儀範，好詩轉彈絕風塵。", "頗勝袁粲飲無偶，步屧白楊要惡賓。"]'),
('9b2ec745-dc2b-4219-a27c-e6be909dcde9','貽王充道隱士','李彭','宋','宋诗','song-poetry','','["\u897f\u6e56"]','憶昨涪翁虎溪別，雁来一字不寧收。',64,'全唐诗/poet.song.80000.json','["憶昨涪翁虎溪別，雁来一字不寧收。", "勞君爲傳三月信，遣我少寬千斛愁。", "煙艇方遊建業水，玉人猶在仲宣樓。", "何時掛席西湖去，藜杖青鞋鸚鵡洲。"]'),
('9519ca07-0dbe-45ee-8045-86c92cdc3ffd','潮州木龜有堂舊在天慶觀北極殿之左近爲道流竊取而去今莫知所在矣','李彭','宋','宋诗','song-poetry','','[]','長生要自食山蘚，妙語寧聞葛稚川。',64,'全唐诗/poet.song.80000.json','["長生要自食山蘚，妙語寧聞葛稚川。", "忽見靈龜藏六用，定巢蓮葉閲千年。", "刳膓已笑清江使，曵尾聊同修水邊。", "懸想偷兒難卜夜，守閭黄耳得安眠。"]'),
('c81a5de9-0c7a-45ab-b7b3-3f9bd157c54b','宿侍其雲叟書齋','李彭','宋','宋诗','song-poetry','','[]','高齋解榻留我宿，破夢驚濤翻疾雷。',64,'全唐诗/poet.song.80000.json','["高齋解榻留我宿，破夢驚濤翻疾雷。", "水鳥時呼山鳥語，朝帆纔去暮帆来。", "百年榮落真墮甑，一世稱譏同死灰。", "珍重秦淮隱君子，只今風月且銜杯。"]'),
('8f6eb278-28e5-48f4-80be-f60e79ddf5f7','竹枕','李彭','宋','宋诗','song-poetry','','[]','湘江翠竹斬雲根，偃月初無刻削痕。',64,'全唐诗/poet.song.80000.json','["湘江翠竹斬雲根，偃月初無刻削痕。", "尚想繁柯俱笨尊，寧經綵鳯屢飛翻。", "佳眠時有池塘夢，避暑不勞河朔樽。", "殷殷晴雷喧白晝，兒童走報雨翻盆。"]'),
('98e7f37e-da8a-4a9b-b998-c74a9c397711','過林子幽居','李彭','宋','宋诗','song-poetry','','[]','卧聽山城罷擊柝，策蹇過君霜滿鬚。',64,'全唐诗/poet.song.80000.json','["卧聽山城罷擊柝，策蹇過君霜滿鬚。", "窗間山好天欲曙，庭下菜肥人愈臞。", "我非當世可領袖，君合於今稱楷模。", "謝公小草恐未免，懷寶要令真不沽。"]'),
('ba4f5048-4e06-4b8f-bfa3-47e5ff625615','同安即事','李彭','宋','宋诗','song-poetry','','[]','摇落霜林秋興新，捨舟尋壑自冥塵。',64,'全唐诗/poet.song.80000.json','["摇落霜林秋興新，捨舟尋壑自冥塵。", "雲光山色解迎客，松氣竹氛俱着人。", "漢上營詩多累句，孟生題壁欲傷神。", "頻伽依舊丁寧語，應笑華顛映角巾。"]'),
('33841248-324a-4ed5-93e8-7f8aecab181f','怡顔堂','李彭','宋','宋诗','song-poetry','','[]','心遠由来地自偏，有琴何必問無弦。',64,'全唐诗/poet.song.80000.json','["心遠由来地自偏，有琴何必問無弦。", "新醪清濁動秋興，老樹扶疏可晝眠。", "失學已從兒輩懶，哦詩常苦後生傳。", "此腰倔强應難折，尚愧顔公二萬錢。"]'),
('93fb6ff0-bd57-4def-a623-8d0c1fbe39d8','周明府國鎮寄詩有招隱之意次韻以報之','李彭','宋','宋诗','song-poetry','','[]','絕壑平生深遯逃，相期推轂敵英豪。',64,'全唐诗/poet.song.80000.json','["絕壑平生深遯逃，相期推轂敵英豪。", "綠葵白薤堪扶老，黄帽青鞋非養高。", "薰浴懸知慚管葛，經綸何敢望崔毛。", "新詩如對故人面，清夜不眠雞屢號。"]'),
('8f932779-d940-42ca-9849-3174c8118e85','予以王褒僮約授嗣行叟叟有書抵予并求跛奚移文且云要與僮約作伉儷以此詩戲之','李彭','宋','宋诗','song-poetry','','[]','髯奴上劵歸公許，跛奚移文猶見催。',64,'全唐诗/poet.song.80000.json','["髯奴上劵歸公許，跛奚移文猶見催。", "臧獲要令成伉儷，文章相與挟風雷。", "目成眉語似真爾，足躡心邀安在哉。", "大士好奇聊一戲，不應禪寂便寒灰。"]'),
('9e398d18-f168-41c8-9627-fadc6d1deaba','戲何人表','李彭','宋','宋诗','song-poetry','','[]','示疾維摩難共語，誰堪問疾坐繩床。',64,'全唐诗/poet.song.80000.json','["示疾維摩難共語，誰堪問疾坐繩床。", "也知世乏長桑手，盡用枕中鴻寶方。", "馬價不須勞廣漢，牛衣何用泣王章。", "清凉心地俱安穩，特訪名園顧辟疆。"]'),
('35ad82a7-90bc-4252-bd8a-0eefd4e2a8cf','仲豫買侍兒作小詩戲之','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','霜鶚横空河漢秋，聊隨雞鶩稻梁謀。',64,'全唐诗/poet.song.80000.json','["霜鶚横空河漢秋，聊隨雞鶩稻梁謀。", "却將屬國舊長劍，換得石城新莫愁。", "要遣短轅無復馭，定看遥集解忘憂。", "匡山醉客時相訪，莫下疏簾作障羞。"]'),
('fe0015d6-a02b-489e-b100-674fb41c7660','溪上','李彭','宋','宋诗','song-poetry','','[]','門前渾是浣花溪，坊裏深疑號碧雞。',64,'全唐诗/poet.song.80000.json','["門前渾是浣花溪，坊裏深疑號碧雞。", "短艇波横隨暮靄，遥岑雨歇看朝隮。", "髯奴便了能沽酒，稚子添丁解灌畦。", "欲賦郊居追沈約，只愁誤讀作雌霓。"]'),
('b850b7b9-9a28-46b5-967a-2ae043d917b5','扇上畫雪景戲書','李彭','宋','宋诗','song-poetry','','[]','醉餘澹墨寫生綃，咫尺真成萬里遥。',64,'全唐诗/poet.song.80000.json','["醉餘澹墨寫生綃，咫尺真成萬里遥。", "短棹船歸剡溪曲，披蓑人渡浣花橋。", "暑中松雪俄輝映，月裏山河俱動摇。", "凛凛寒生立毛髪，從今褦襶不須嘲。"]'),
('604f5995-8b03-4e9e-8d23-8155fb33bbd3','二月二日大雪','李彭','宋','宋诗','song-poetry','','[]','天公長作狡獪戲，舍北舍南無限春。',64,'全唐诗/poet.song.80000.json','["天公長作狡獪戲，舍北舍南無限春。", "密密疏疏桃著糝，娉娉裊裊柳含塵。", "老人已老難復少，故衣雖故昔經新。", "岸薺未花湯餅滑，何勞象白間猩唇。"]'),
('3ad8f5e3-e0e2-4d8f-8c74-4d9f5ff15d25','得了翁書','李彭','宋','宋诗','song-poetry','','[]','都司寧拂御爐香，嚴譴歸来鬢未霜。',64,'全唐诗/poet.song.80000.json','["都司寧拂御爐香，嚴譴歸来鬢未霜。", "麟閣他年看赫弈，獸樽今日久凄涼。", "楚氛聞說行將弭，漢道真成喜再昌。", "莫作湘纍吟澤畔，鋒車促召據南床。"]'),
('bae30d8e-7f2b-4e27-9444-1d4efc0e8108','廬山道中見梅花','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江頭細草已摇春，幽谷疏梅尚著人。',64,'全唐诗/poet.song.80000.json','["江頭細草已摇春，幽谷疏梅尚著人。", "未許揚州動詩興，却嫌戚里妬粧新。", "范郎鄙棗不同傳，漢省含香可買鄰。", "蝶翅蜂鬚莫浪喜，元無一物涴香塵。"]'),
('be1ac090-6333-462a-8ae4-f3dfe71f4079','苦雨','李彭','宋','宋诗','song-poetry','','[]','陵陂麥熟晚雲黄，婦姑當穫相扶将。',64,'全唐诗/poet.song.80000.json','["陵陂麥熟晚雲黄，婦姑當穫相扶将。", "谿山作雨水漂屨，芝菌對床蝸篆梁。", "宴坐翻疑谷簾下，夢回恐在漏天旁。", "何時晴嵐来入戶，撩我浩歌傾一觴。"]'),
('738d6072-6cf3-4192-8289-a85fa7857583','江梅','李彭','宋','宋诗','song-poetry','','[]','江梅疏雨弄晴曛，割取江東一信春。',64,'全唐诗/poet.song.80000.json','["江梅疏雨弄晴曛，割取江東一信春。", "剩得耐寒驚蛱蝶，竟来占醉倒綸巾。", "未容作賦重招屈，豈敢含毫論過秦。", "何日大梅梅子熟，從渠高浪白如銀。"]'),
('e7ff429b-abb8-40d5-ad49-e1ecb64ab485','睡起','李彭','宋','宋诗','song-poetry','','[]','鳥鳥聲樂報新晴，睡罷南窗午醉醒。',64,'全唐诗/poet.song.80000.json','["鳥鳥聲樂報新晴，睡罷南窗午醉醒。", "惡客從譏玄尚白，斯人相向眼終青。", "渚蒲汀草垂垂發，幕燕林鶯續續聽。", "日糴太倉真細事，安尋佳句遣沉冥。"]'),
('29bcb4e4-5076-4ea5-bc0c-88632b14b472','次妙明觀韵','李彭','宋','宋诗','song-poetry','','[]','春岸波平汀草深，野航蕩槳恣幽尋。',64,'全唐诗/poet.song.80000.json','["春岸波平汀草深，野航蕩槳恣幽尋。", "星壇香轉来真侣，菌閣鐘鳴生道心。", "憶昨霓旌歸紫府，尚餘鴻寶作黄金。", "肩吾戲吐煙霞語，縹緲欲仙難陸沈。"]'),
('fda66c7c-974e-4540-bb23-a18d291018bc','次韵答仲兄元亮','李彭','宋','宋诗','song-poetry','','[]','楊柳江頭人迹稀，心隨鐘度遠山遲。',64,'全唐诗/poet.song.80000.json','["楊柳江頭人迹稀，心隨鐘度遠山遲。", "忽傳憶弟看雲句，想見流觴曲水時。", "人比封胡終有恨，韻低徐庾敢言詩。", "青春欲謝子規呌，莫惜歸帆赴後期。"]'),
('93a553ae-bae6-491b-9936-4510fb85f9c4','用元亮韵寄駒甫','李彭','宋','宋诗','song-poetry','','[]','才名綠髪斗牛垂，天祿讐書何太遲。',64,'全唐诗/poet.song.80000.json','["才名綠髪斗牛垂，天祿讐書何太遲。", "却掃未嘗嗟半菽，養疴不是傲當時。", "鋪張大對明光手，收卷裁成鄴下詩。", "見底冰壺最清澈，何時照眼會心期。"]'),
('b640b332-b9db-4df4-bda5-875bb9250cb0','用元亮韵答師川篇末見寄','李彭','宋','宋诗','song-poetry','','[]','蚤歲聞君萬人敵，定交已悔十年遲。',64,'全唐诗/poet.song.80000.json','["蚤歲聞君萬人敵，定交已悔十年遲。", "中間會面無虚日，底事分携用此時。", "不隔南雲無過雁，猶因北阮著新詩。", "征車欲作日邊去，儻赴幽園茗菓期。"]'),
('fb9dca1e-9f08-41e7-a045-73d60385bcc0','復用遲字韻呈元亮','李彭','宋','宋诗','song-poetry','','[]','去日關河雪打圍，縫裳密密恐歸遲。',64,'全唐诗/poet.song.80000.json','["去日關河雪打圍，縫裳密密恐歸遲。", "忽看高筍成筠處，始見殘樽下馬時。", "暮雨蕭蕭聊洗恨，東園物物總宜詩。", "莫言心賞隨年薄，勤赴幽人林下期。"]'),
('b643e156-e789-45b3-ba8b-b6be18a3b184','東臺','李彭','宋','宋诗','song-poetry','','[]','門巷依依稱意苔，杖藜野色逐人開。',64,'全唐诗/poet.song.80000.json','["門巷依依稱意苔，杖藜野色逐人開。", "馬駒卓錫今應在，康樂翻經那復来。", "雲物蒼茫山遠近，波聲宛轉水縈廻。", "風流賴有潘懷縣，一洗從前猿鶴哀。"]'),
('39f7ea6d-9b82-4407-a6fb-e135f68109a2','次韻徐師川喜洪駒父歸自臨汀之作','李彭','宋','宋诗','song-poetry','','[]','赤壁煙波翻渺溟，長沙卑濕重行行。',64,'全唐诗/poet.song.80000.json','["赤壁煙波翻渺溟，長沙卑濕重行行。", "一觴一詠勞清夢，三沐三薰慰別情。", "不作畔牢愁執戟，共吟哀郢哭初平。", "生来競病幾牢落，漫興安能學背城。"]'),
('55debbee-4489-4049-84e4-18d62c06ec2a','度章水道中戲用城字韻呈駒甫師川','李彭','宋','宋诗','song-poetry','','[]','楚波不動晚山青，顧兔西来照我行。',64,'全唐诗/poet.song.80000.json','["楚波不動晚山青，顧兔西来照我行。", "野鳥鈎輈如有意，漁歌欸乃亦多情。", "湖邊倒載思山簡，機上廻紋念始平。", "欲覓澄江如練句，乞靈須向謝宣城。"]'),
('43e6d480-1e63-4314-b3a6-64b79da85a78','次韻答季智伯弟','李彭','宋','宋诗','song-poetry','','[]','廢詩不復匠蘇州，蠹簡於人風馬牛。',64,'全唐诗/poet.song.80000.json','["廢詩不復匠蘇州，蠹簡於人風馬牛。", "喜有丘明能撰次，極知水部愈風流。", "句分競病應難敵，家有封胡可解憂。", "共歎宣城遊岱早，剩招去幹不能收。"]'),
('1b1d7986-3669-43f7-baca-e61d3ac3a9cc','贈蘇仲豫','李彭','宋','宋诗','song-poetry','','[]','平生照眼玉壺冰，解向朝陽續鳯鳴。',64,'全唐诗/poet.song.80000.json','["平生照眼玉壺冰，解向朝陽續鳯鳴。", "黄鵠樓前重會面，白蓮社裏定交情。", "疏才我亦憐文舉，大雅君應笑正平。", "貰酒臨卭聊復爾，莫令狗監汙高明。"]'),
('8f45c190-b2f7-4fe7-a800-d605a1a9581c','贈王環中','李彭','宋','宋诗','song-poetry','','[]','拄策前年訪草堂，掛帆煙際在西江。',64,'全唐诗/poet.song.80000.json','["拄策前年訪草堂，掛帆煙際在西江。", "詩隨鴻雁来春渚，夢逐蟾蜍入夜窗。", "辭聘知君追孺子，屢空嗟我似窮龐。", "菟裘欲買爲鄰竝，歲晚相期倒百缸。"]'),
('4c35a955-164b-46d8-ae61-9a4a072daa28','贈張仲義','李彭','宋','宋诗','song-poetry','','[]','春衫試吏楚江濆，真以文昌思不羣。',64,'全唐诗/poet.song.80000.json','["春衫試吏楚江濆，真以文昌思不羣。", "未暇等陶辭小秩，何妨慕謝始精文。", "壁間妙句流黄素，松下英姿大壑雲。", "但恐承明賴公等，不容蠻府作參軍。"]'),
('c486fd72-40af-48aa-a1d8-f8e3d57c738e','奉贈介然','李彭','宋','宋诗','song-poetry','','[]','彈壓諸方化城老，聊同懶瓚恣佳眠。',64,'全唐诗/poet.song.80000.json','["彈壓諸方化城老，聊同懶瓚恣佳眠。", "雲隨雷下雨歸壑，竹引窗間風動煙。", "晝靜冥捜徒覓句，道安高論愧彌天。", "叢林良藥今無有，絕影須公爲著鞭。"]'),
('f990244e-76f7-4723-82a7-989f0afed6cd','宿同安用舊韻呈雲叟','李彭','宋','宋诗','song-poetry','','[]','蒲柳望秋今復衰，遥岑雨罷抹修眉。',64,'全唐诗/poet.song.80000.json','["蒲柳望秋今復衰，遥岑雨罷抹修眉。", "寒林要使入方尺，妙筆懸知愧畫師。", "不見揚雄草玄手，細看束晳補亡詩。", "何時共飲建業水，更把北山煙雨犂。"]'),
('4085fea8-bec6-4206-b865-d55912bb3023','遊同安寺','李彭','宋','宋诗','song-poetry','','[]','郭內那知草色新，道人庭宇別藏春。',64,'全唐诗/poet.song.80000.json','["郭內那知草色新，道人庭宇別藏春。", "高榆風度青含荚，艶杏雨餘紅退唇。", "茗盌薰爐清有致，禪天金地夐無塵。", "裁詩得句如拱璧，不費咸陽設九賓。"]'),
('51d96d83-881d-4a16-a717-c0361299ea1b','遊昭德觀','李彭','宋','宋诗','song-poetry','','[]','曉隨歸雁影聯翩，来訪仇池小有天。',64,'全唐诗/poet.song.80000.json','["曉隨歸雁影聯翩，来訪仇池小有天。", "萬籟虚徐雜鐘磬，一源淳樸異山川。", "雲霾大壑真遊遠，風掃石楠佳句傳。", "司命峰前徐孺子，幾時風雪對床眠。"]'),
('d6de442d-290d-4510-9458-7dfc98ad7b93','夏牛卿用韻見貽次韻答之夏先君子與先平陽厚善','李彭','宋','宋诗','song-poetry','','[]','君合雍容供奉班，彤墀紫仗近天顔。',64,'全唐诗/poet.song.80000.json','["君合雍容供奉班，彤墀紫仗近天顔。", "悮隨手板落趨走，却望家山思燕閒。", "使君銅狄悲遊岱，令尹玉棺今賜環。", "樽前回首二十載，更話幽禪未易攀。"]'),
('1db60a2f-26a2-404a-865f-8f3dc8f0f2e5','客有和予顔字韻詩者答之','李彭','宋','宋诗','song-poetry','','[]','蠻花初捲簟文斑，苦被秋風吹老顔。',64,'全唐诗/poet.song.80000.json','["蠻花初捲簟文斑，苦被秋風吹老顔。", "慰眼既親還有舊，起予多病復思閒。", "暮年倚仗心三徑，看子著鞭腰九環。", "小屈尉曹吴會去，莫因横槊廢躋攀。"]'),
('85e2dabb-6a1a-4794-99e6-d419f17bb078','送規老住虔之慈雲','李彭','宋','宋诗','song-poetry','','[]','禪翁竟補棲禪處，兔角龜毛杖佛僧。',64,'全唐诗/poet.song.80000.json','["禪翁竟補棲禪處，兔角龜毛杖佛僧。", "久厭宗雷同保社，却凴章貢濁埃塵。", "定携天上蒼鷹爪，去接西江白業賓。", "大庾嶺頭梅正好，同風千里一枝春。"]'),
('746307f0-5a7a-4336-a81f-25d37eeddcb3','郊外書事','李彭','宋','宋诗','song-poetry','','[]','郊原野老带經鋤，童稚何知競挽鬚。',64,'全唐诗/poet.song.80000.json','["郊原野老带經鋤，童稚何知競挽鬚。", "我亦彌年躬井臼，兒能終日課樵蘇。", "頗思鷗閣仍虬戶，那似松醪伴酪奴。", "志大才疏苦多累，真須鹿鹿效周謨。"]'),
('9ed7d815-ed52-4d70-a031-21f1ac90e4b6','和何思舉韻寄元亮兼簡性之','李彭','宋','宋诗','song-poetry','','[]','避冷幽窗歌扊扅，鴉啼疏柳把南枝。',64,'全唐诗/poet.song.80000.json','["避冷幽窗歌扊扅，鴉啼疏柳把南枝。", "長鬚勿送平安報，滿眼仍看競病詩。", "稚子毎嗟簷隙短，波臣常梗客行遲。", "應貪左轄藍田會，落雪官梅動興時。"]'),
('5d34e64a-b591-48b1-adf1-b5b9dc4c6345','和許秀才見贈許病目良苦','李彭','宋','宋诗','song-poetry','','[]','木末鴉啼負郭村，無人白晝掩柴門。',64,'全唐诗/poet.song.80000.json','["木末鴉啼負郭村，無人白晝掩柴門。", "詩来或作破客夢，語妙直堪排帝閽。", "抱瘵端如叔夜懶，幽懷思對阮生論。", "何時還子讀書眼，解脱無根須返元。"]'),
('766d24d5-641c-4e69-8155-4353c1cfb643','和馮仲宣韻','李彭','宋','宋诗','song-poetry','','[]','秋風寂寞仲宣樓，金狄傷嗟卧一丘。',64,'全唐诗/poet.song.80000.json','["秋風寂寞仲宣樓，金狄傷嗟卧一丘。", "喜有斯人出淮海，追還舊觀極風流。", "莫将起草明光手，去伴諸郎肉食謀。", "我欲清江理煙艇，尋君楚尾及吳頭。"]'),
('51b5c6b8-de00-4c2b-9e30-d8eae82013df','奉酬謝幼槃','李彭','宋','宋诗','song-poetry','','[]','窗間遠岫謝玄暉，人物煌煌三秀芝。',64,'全唐诗/poet.song.80000.json','["窗間遠岫謝玄暉，人物煌煌三秀芝。", "黄耳来時得佳句，碧雲合處起幽思。", "深閨復見解圍手，勝日應多贈婦辭。", "念我龐婆最癡絕，只能舉案解支頤。"]'),
('4e90993b-35d4-4ece-847d-c01278cffb2e','次韻奉酬幼槃','李彭','宋','宋诗','song-poetry','','[]','結廬不入遺民社，好客初無仲蔚蒿。',64,'全唐诗/poet.song.80000.json','["結廬不入遺民社，好客初無仲蔚蒿。", "度鳥冥冥與心遠，孤峰峭峭伴名高。", "樽前著我醉千日，鏡裏緣君減二毛。", "安得買鄰揮百萬，拍浮左手更持螯。"]'),
('f7b04817-9aa5-43ad-ae72-2c07241f0ca6','再次韻呈之忱彦先彦達兼呈幼槃','李彭','宋','宋诗','song-poetry','','[]','割據溪山天下豪，長松獨許倚青蒿。',64,'全唐诗/poet.song.80000.json','["割據溪山天下豪，長松獨許倚青蒿。", "小巫政自雄河朔，淺器從来鄙奉高。", "爛醉何勞憤田竇，淳風相與繼崔毛。", "不知底事真奇語，且向窗前嚼二螯。"]'),
('36fa753a-0e82-42dc-97de-4a5a4c8b5338','次駒甫涵虚閣韻','李彭','宋','宋诗','song-poetry','','[]','夢中占夢偶相逢，山上有山隨轉篷。',64,'全唐诗/poet.song.80000.json','["夢中占夢偶相逢，山上有山隨轉篷。", "我自持觴酹玄酒，君應臨水洗蠻風。", "行參鵷鷺峨冠客，豈是江湖把釣翁。", "暇日頻来裁錦句，要看玉手亂殷紅。"]'),
('7c6fbe4d-9ea6-487a-8a9b-1434a944ba16','紫霄道中','李彭','宋','宋诗','song-poetry','','[]','山行積石路逶迤，村徑成門逐處移。',128,'全唐诗/poet.song.80000.json','["山行積石路逶迤，村徑成門逐處移。", "一點炊煙生虎穴，四来暝色到牛衣。", "畏人沙鳥飛南隴，傍母山猿戀北枝。", "鴈塔崔嵬臨畫嶠，墨雲霮䨴起方池。", "髯秦昔別留奇畫，病可雖亡餘好詩。", "羊祜不如銅雀妓，蔡邕尚有虎賁兒。", "開顔欲效東籬醉，真隱慚無谷口姿。", "安得膏腴盈二頃，雍雍喚取共扶犂。"]'),
('54a9cafd-ba0d-48f8-b9f3-7b2a35711fcb','喚渡亭','李彭','宋','宋诗','song-poetry','','[]','草風兼沙雨，依約渭河邊。',24,'全唐诗/poet.song.80000.json','["草風兼沙雨，依約渭河邊。", "昔人寧喚渡，絕唱頗清緜。"]'),
('bb368e8a-c334-46b3-a6cb-8ba5cb775ddc','戲書山水枕屏四段  其一','李彭','宋','宋诗','song-poetry','','[]','遥岑天南端，野彴垂楊下。',24,'全唐诗/poet.song.80000.json','["遥岑天南端，野彴垂楊下。", "蕭散策寒藤，綠雲復觀化。"]'),
('f988f12f-d2da-4863-870a-ddf6309292ca','戲書山水枕屏四段  其二','李彭','宋','宋诗','song-poetry','','[]','澄江真皎鏡，短艇戲鳴榔。',24,'全唐诗/poet.song.80000.json','["澄江真皎鏡，短艇戲鳴榔。", "無復機心動，不驚鷗鳥行。"]'),
('cc4cfe52-0565-468b-a893-3da265940d0f','戲書山水枕屏四段  其三','李彭','宋','宋诗','song-poetry','','[]','孤峰上排霄，羣木盡生意。',24,'全唐诗/poet.song.80000.json','["孤峰上排霄，羣木盡生意。", "持竿坐石磯，高懷在雲際。"]'),
('5435162a-d93e-4e10-8f9c-2005f0f27cec','戲書山水枕屏四段  其四','李彭','宋','宋诗','song-poetry','','[]','複閣耿蒼烟，斜暉掛木末。',24,'全唐诗/poet.song.80000.json','["複閣耿蒼烟，斜暉掛木末。", "卷帆何處船，危檣待明發。"]'),
('82098a4e-cd36-41cd-8a2c-c76bf12e9043','大雪投宿圜通以野雪蓋精廬爲韻賦五詩并書塗中所見  其一','李彭','宋','宋诗','song-poetry','','[]','寒雪盡垂空，玉色粲萬瓦。',24,'全唐诗/poet.song.80000.json','["寒雪盡垂空，玉色粲萬瓦。", "默默行五牙，鬱靄望黄野。"]'),
('7074c6a0-ea6e-467a-95db-85369a46db15','大雪投宿圜通以野雪蓋精廬爲韻賦五詩并書塗中所見  其二','李彭','宋','宋诗','song-poetry','','[]','昔我遊山陰，雜花紛似雪。',24,'全唐诗/poet.song.80000.json','["昔我遊山陰，雜花紛似雪。", "重来雪作團，遠樹皓已結。"]'),
('94adad9d-8d91-4980-be0d-950838b8f175','大雪投宿圜通以野雪蓋精廬爲韻賦五詩并書塗中所見  其三','李彭','宋','宋诗','song-poetry','','[]','山翁雪垂素，相逢乃傾蓋。',24,'全唐诗/poet.song.80000.json','["山翁雪垂素，相逢乃傾蓋。", "同看艷雪舞，盡此威遲態。"]'),
('0e7cfa3e-acc3-42c9-a91e-f04c173aa060','大雪投宿圜通以野雪蓋精廬爲韻賦五詩并書塗中所見  其四','李彭','宋','宋诗','song-poetry','','[]','借問佩蒼玉，何如煮黄精。',24,'全唐诗/poet.song.80000.json','["借問佩蒼玉，何如煮黄精。", "古来澗谷槃，價自重連城。"]'),
('549b190d-823e-4189-8d2a-3136ebace48a','大雪投宿圜通以野雪蓋精廬爲韻賦五詩并書塗中所見  其五','李彭','宋','宋诗','song-poetry','','[]','馬疲如客饑，稅鞅文公廬。',24,'全唐诗/poet.song.80000.json','["馬疲如客饑，稅鞅文公廬。", "人好雪亦好，何啻射洪烏。"]'),
('34086426-1ce1-4265-b9fb-e883530d5098','迎陽閣','李彭','宋','宋诗','song-poetry','','[]','扶桑有玉書，鬱儀善相保。',24,'全唐诗/poet.song.80000.json','["扶桑有玉書，鬱儀善相保。", "朝暾到頹簷，危坐填血腦。"]'),
('9467fdea-2baf-42ba-bac7-9a5923f1abdb','予夏中卧病起已見落葉因取淵明詩門庭多落葉慨然知已秋賦十章遣興  其一','李彭','宋','宋诗','song-poetry','','[]','西嶺障斜日，澄江來遶門。',24,'全唐诗/poet.song.80000.json','["西嶺障斜日，澄江來遶門。", "歸鴉千萬點，暝色入遠村。"]'),
('27fb7c55-381f-4bd0-9669-8170112e4e26','予夏中卧病起已見落葉因取淵明詩門庭多落葉慨然知已秋賦十章遣興  其二','李彭','宋','宋诗','song-poetry','','[]','燕坐修白業，焚香觀黄庭。',24,'全唐诗/poet.song.80000.json','["燕坐修白業，焚香觀黄庭。", "清霄降真侣，弭節或見聆。"]'),
('c112e849-7d7d-41fa-967a-3c18cd1c0c7a','予夏中卧病起已見落葉因取淵明詩門庭多落葉慨然知已秋賦十章遣興  其三','李彭','宋','宋诗','song-poetry','','[]','境静輪鞅寡，堦空絡緯多。',24,'全唐诗/poet.song.80000.json','["境静輪鞅寡，堦空絡緯多。", "蕭然正遐矚，脱葉下庭柯。"]'),
('052f7f0b-d8d8-4c7d-a759-9e55d77cb807','予夏中卧病起已見落葉因取淵明詩門庭多落葉慨然知已秋賦十章遣興  其四','李彭','宋','宋诗','song-poetry','','[]','我初卧病時，桑麻翳負郭。',24,'全唐诗/poet.song.80000.json','["我初卧病時，桑麻翳負郭。", "扶杖延秋風，山川俱黄落。"]'),
('f0852429-c480-4fe3-8ec1-11890ad9bb98','予夏中卧病起已見落葉因取淵明詩門庭多落葉慨然知已秋賦十章遣興  其五','李彭','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','寒温機中素，榮歇洞庭葉。',24,'全唐诗/poet.song.80000.json','["寒温機中素，榮歇洞庭葉。", "發興鷗鳥行，風烟理舟楫。"]'),
('f45f4389-ecd5-45fd-b24f-1fe51b1e327d','予夏中卧病起已見落葉因取淵明詩門庭多落葉慨然知已秋賦十章遣興  其六','李彭','宋','宋诗','song-poetry','','[]','平生老驥心，伏櫪端有在。',24,'全唐诗/poet.song.80000.json','["平生老驥心，伏櫪端有在。", "華月生夜涼，南窗歌慷慨。"]'),
('dffd4704-efff-4a52-83b4-101e0113e74d','予夏中卧病起已見落葉因取淵明詩門庭多落葉慨然知已秋賦十章遣興  其七','李彭','宋','宋诗','song-poetry','','[]','園中有奇貨，雨滿瓜芋田。',24,'全唐诗/poet.song.80000.json','["園中有奇貨，雨滿瓜芋田。", "一飽吾已足，望山思悠然。"]'),
('6d17d6a7-6bf0-486d-b5aa-6830c5628300','予夏中卧病起已見落葉因取淵明詩門庭多落葉慨然知已秋賦十章遣興  其八','李彭','宋','宋诗','song-poetry','','[]','結交何用早，士貴心相知。',24,'全唐诗/poet.song.80000.json','["結交何用早，士貴心相知。", "苟合殊真味，咄咄成乖離。"]'),
('31e63986-360f-4338-be8b-0dc9952b7117','予夏中卧病起已見落葉因取淵明詩門庭多落葉慨然知已秋賦十章遣興  其九','李彭','宋','宋诗','song-poetry','','[]','林廬亦云樂，欲語輙復已。',24,'全唐诗/poet.song.80000.json','["林廬亦云樂，欲語輙復已。", "取琴撫徽絃，妙不在宫徵。"]'),
('bfa62b7f-510a-4154-8f0b-834934eee137','予夏中卧病起已見落葉因取淵明詩門庭多落葉慨然知已秋賦十章遣興  其一○','李彭','宋','宋诗','song-poetry','','[]','沅湘歌九辯，梁父吟四愁。',24,'全唐诗/poet.song.80000.json','["沅湘歌九辯，梁父吟四愁。", "虚齋無一事，坐對楚江秋。"]'),
('bd87a2a3-27b6-4fc1-8f70-4ec57b1f660f','太平小寺','李彭','宋','宋诗','song-poetry','','[]','行盡斜峰急澗，忽看化寺神居。',28,'全唐诗/poet.song.80000.json','["行盡斜峰急澗，忽看化寺神居。", "雲瑣沉沉複閣，旁看貝葉遺書。"]'),
('0df4601d-8e8b-450f-9023-0e623c043cd3','昌書記畫梅','李彭','宋','宋诗','song-poetry','','[]','花柳春風紛衍，禪窗晚放横枝。',28,'全唐诗/poet.song.80000.json','["花柳春風紛衍，禪窗晚放横枝。", "虢國生憎粉黛，晚粧淡掃蛾眉。"]'),
('65035fbf-b329-4bf4-8158-0c81c7159ce1','夜坐兼戲環上人  其一','李彭','宋','宋诗','song-poetry','','[]','蠹簡聊寬岑寂，榴花頗慰榛蕪。',28,'全唐诗/poet.song.80000.json','["蠹簡聊寬岑寂，榴花頗慰榛蕪。", "莫問草玄上白，須令看碧成朱。"]'),
('3f2dc382-a543-4242-8ecf-a2ea03f54a19','夜坐兼戲環上人  其二','李彭','宋','宋诗','song-poetry','','[]','毛髪早驚蒲柳，衣裾又變風烟。',28,'全唐诗/poet.song.80000.json','["毛髪早驚蒲柳，衣裾又變風烟。", "我是一丘一壑，君應三要三玄。"]'),
('f675cb7d-a542-45b7-9d4e-02fe677dc6ce','夜坐兼戲環上人  其三','李彭','宋','宋诗','song-poetry','','[]','落木霜猿到耳，風高候雁横空。',28,'全唐诗/poet.song.80000.json','["落木霜猿到耳，風高候雁横空。", "覓句深憑料理，解圍俄聽晨鐘。"]'),
('ee9b3ad8-d387-4347-93ec-60595d6b4e81','昌書記畫馴猿','李彭','宋','宋诗','song-poetry','','[]','巫峽猿啼向曙，云何却在樊籠。',28,'全唐诗/poet.song.80000.json','["巫峽猿啼向曙，云何却在樊籠。", "想見珍羞豢養，翻思槲葉微風。"]'),
('ba8cf56f-134e-4b54-a0b6-5cd59028b4d4','庭梅','李彭','宋','宋诗','song-poetry','','[]','春風日日下丘園，綠到萱芽蕨破拳。',32,'全唐诗/poet.song.80000.json','["春風日日下丘園，綠到萱芽蕨破拳。", "莫怪庭梅晚来好，尚堪桃李與争妍。"]'),
('516ca60d-74c8-4dad-a7be-52b9f030332d','寄贈擇言兩絕句  其一','李彭','宋','宋诗','song-poetry','','[]','憶昨同傾三昧酒，論文時掇百家衣。',32,'全唐诗/poet.song.80000.json','["憶昨同傾三昧酒，論文時掇百家衣。", "他年準擬蘭亭會，好畫高人支遁師。"]'),
('31c01552-4235-4d37-84a2-4facbe545c07','寄贈擇言兩絕句  其二','李彭','宋','宋诗','song-poetry','','[]','逍遥儒墨兩専場，萬遍蓮花嫁馬郎。',32,'全唐诗/poet.song.80000.json','["逍遥儒墨兩専場，萬遍蓮花嫁馬郎。", "心若死灰詩欲盡，乞儂西國更生香。"]'),
('a6489591-5961-45c7-bae2-2377be32e74d','舍弟彤檢校南庄刈稻中秋日作三絕句見寄醉後偶次其韻答之  其一','李彭','宋','宋诗','song-poetry','','[]','天南雲破玉繩横，上有蟾蜍雲外明。',32,'全唐诗/poet.song.80000.json','["天南雲破玉繩横，上有蟾蜍雲外明。", "共把一杯懷少雁，新詩深悉未歸情。"]'),
('3ef938e8-7801-4288-89d4-7f8e49d8b144','舍弟彤檢校南庄刈稻中秋日作三絕句見寄醉後偶次其韻答之  其二','李彭','宋','宋诗','song-poetry','','[]','呼鄰貰酒酒如冰，以酒攻愁愁有城。',32,'全唐诗/poet.song.80000.json','["呼鄰貰酒酒如冰，以酒攻愁愁有城。", "醉舞不須看短舞，神清便覺映膚清。"]'),
('d84166b1-0c0b-41c2-8b24-6a594efc40d4','舍弟彤檢校南庄刈稻中秋日作三絕句見寄醉後偶次其韻答之  其三','李彭','宋','宋诗','song-poetry','','[]','珍重江南庾子山，詩名晚歲滿江關。',32,'全唐诗/poet.song.80000.json','["珍重江南庾子山，詩名晚歲滿江關。", "應須剩讀書千卷，始在班揚伯仲間。"]'),
('8cc5d38f-74bf-48c7-a011-5c976b1b8db5','答徐十贈詩三絕句  其一','李彭','宋','宋诗','song-poetry','','[]','東湖高士有雲孫，句夢池塘論過秦。',32,'全唐诗/poet.song.80000.json','["東湖高士有雲孫，句夢池塘論過秦。", "海內故人流落盡，病夫杯渡不嫌頻。"]'),
('73ce6230-aef1-4f9b-82d0-212d94c2e602','答徐十贈詩三絕句  其二','李彭','宋','宋诗','song-poetry','','[]','窗中山色撲衣襟，户外江聲醒客心。',32,'全唐诗/poet.song.80000.json','["窗中山色撲衣襟，户外江聲醒客心。", "我在山陰君在剡，思君行坐短長吟。"]'),
('bcbf71cc-e65f-47e1-96c8-93ec87df7b04','答徐十贈詩三絕句  其三','李彭','宋','宋诗','song-poetry','','[]','爐薰細細繞禪房，竹日暉暉映短牆。',32,'全唐诗/poet.song.80000.json','["爐薰細細繞禪房，竹日暉暉映短牆。", "安得買鄰同歲晚，鉢盂分飯共繩床。"]'),
('02e09a5f-2701-4a82-b256-3129dd52beb0','答謝邁秀才三絕句  其一','李彭','宋','宋诗','song-poetry','','[]','飽聞玉樹堦庭長，今見憑虚意欲仙。',32,'全唐诗/poet.song.80000.json','["飽聞玉樹堦庭長，今見憑虚意欲仙。", "遣我池塘夢春草，阿連風味劇堪憐。"]'),
('f538993b-b148-4572-a897-9583970b90e6','答謝邁秀才三絕句  其二','李彭','宋','宋诗','song-poetry','','[]','短李門前無寧馨，書淫詩癡類天成。',32,'全唐诗/poet.song.80000.json','["短李門前無寧馨，書淫詩癡類天成。", "多情喜有謝康樂，步屧同尋鷗鳥盟。"]'),
